{
  "name": "Nexus Video Studio Pro",
  "description": "A professional-grade, AI-powered video editing suite featuring multi-layer timelines, real-time effects, and advanced generative video capabilities using Gemini Veo.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export enum MediaType {
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO',
  IMAGE = 'IMAGE',
  TEXT = 'TEXT'
}

export interface Asset {
  id: string;
  name: string;
  type: MediaType;
  url: string;
  duration: number; // in seconds
  thumbnail?: string;
}

export interface Clip {
  id: string;
  assetId: string;
  startTime: number; // position on timeline in seconds
  offset: number; // start point within the asset in seconds
  duration: number; // length of the clip on timeline
  layer: number;
  effects: Effect[];
}

export interface Effect {
  id: string;
  type: 'filter' | 'transition' | 'adjustment';
  name: string;
  params: Record<string, any>;
}

export interface Project {
  id: string;
  name: string;
  resolution: { width: number; height: number };
  fps: number;
  tracks: Track[];
}

export interface Track {
  id: string;
  name: string;
  type: 'video' | 'audio';
  clips: Clip[];
}

export interface ProjectState {
  currentProject: Project;
  assets: Asset[];
  selectedClipId: string | null;
  currentTime: number;
  isPlaying: boolean;
  zoom: number;
}

import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  /**
   * Generates a video using Veo 3.1
   */
  async generateVideo(prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: aspectRatio
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  }

  /**
   * Uses Gemini 3 Pro to generate a script or analyze video content
   */
  async analyzeContent(prompt: string) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2000 }
      }
    });
    return response.text;
  }
}

import { useState, useCallback, useMemo } from 'react';
import { Project, Asset, Clip, MediaType, Track } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [] },
    { id: 'track-v2', name: 'Video 2', type: 'video', clips: [] },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [] }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10); // pixels per second factor

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    const newClip: Clip = {
      id: `clip-${Math.random().toString(36).substr(2, 9)}`,
      assetId: asset.id,
      startTime: startTime,
      offset: 0,
      duration: asset.duration,
      layer: 0,
      effects: []
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => 
        t.id === trackId ? { ...t, clips: [...t.clips, newClip] } : t
      )
    }));
  }, []);

  const updateClip = useCallback((clipId: string, updates: Partial<Clip>) => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => ({
        ...t,
        clips: t.clips.map(c => c.id === clipId ? { ...c, ...updates } : c)
      }))
    }));
  }, []);

  const moveClip = useCallback((clipId: string, trackId: string, newStartTime: number) => {
    setProject(prev => {
      let targetClip: Clip | null = null;
      // Remove clip from current track
      const newTracks = prev.tracks.map(t => {
        const found = t.clips.find(c => c.id === clipId);
        if (found) targetClip = found;
        return {
          ...t,
          clips: t.clips.filter(c => c.id !== clipId)
        };
      });

      if (!targetClip) return prev;

      // Add clip to new track
      return {
        ...prev,
        tracks: newTracks.map(t => 
          t.id === trackId 
            ? { ...t, clips: [...t.clips, { ...targetClip!, startTime: newStartTime }] } 
            : t
        )
      };
    });
  }, []);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    addAsset,
    addClip,
    updateClip,
    moveClip,
    setProject
  };
};

import React, { useRef, useEffect } from 'react';
import { Project, Track, Asset, Clip } from '../../types';

interface TimelineProps {
  project: Project;
  currentTime: number;
  zoom: number;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ 
  project, 
  currentTime, 
  zoom, 
  onTimeChange,
  onClipMove,
  selectedClipId,
  onSelectClip
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const pixelsPerSecond = zoom * 10;

  const handleTimelineClick = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const scrollLeft = containerRef.current.scrollLeft;
    const x = e.clientX - rect.left + scrollLeft - 150; // 150 is track header width
    if (x >= 0) {
      onTimeChange(x / pixelsPerSecond);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    const frames = Math.floor((seconds % 1) * 30);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}:${frames.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex-1 bg-[#121212] flex flex-col overflow-hidden border-t border-[#333]">
      {/* Ruler */}
      <div className="h-8 bg-[#1a1a1a] flex border-b border-[#333] relative">
        <div className="w-[150px] flex-shrink-0 border-r border-[#333] flex items-center px-4 text-xs font-mono text-gray-500">
          {formatTime(currentTime)}
        </div>
        <div 
          ref={containerRef}
          className="flex-1 overflow-x-auto relative timeline-grid scrollbar-hide"
          onClick={handleTimelineClick}
        >
          {Array.from({ length: 20 }).map((_, i) => (
            <div 
              key={i} 
              className="absolute top-0 text-[10px] text-gray-600 font-mono border-l border-gray-700 h-full pl-1"
              style={{ left: i * 10 * pixelsPerSecond }}
            >
              {i * 10}s
            </div>
          ))}
          {/* Playhead */}
          <div 
            className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none"
            style={{ left: currentTime * pixelsPerSecond }}
          >
            <div className="absolute -top-1 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>

      {/* Tracks Container */}
      <div className="flex-1 overflow-y-auto overflow-x-hidden">
        {project.tracks.map((track) => (
          <div key={track.id} className="flex border-b border-[#222] min-h-[64px]">
            <div className="w-[150px] flex-shrink-0 bg-[#1a1a1a] border-r border-[#333] p-2 flex flex-col justify-center">
              <span className="text-xs font-medium text-gray-400 truncate">{track.name}</span>
              <div className="flex gap-2 mt-1">
                <button className="w-4 h-4 rounded-full bg-gray-700 hover:bg-gray-600 flex items-center justify-center text-[10px]">M</button>
                <button className="w-4 h-4 rounded-full bg-gray-700 hover:bg-gray-600 flex items-center justify-center text-[10px]">S</button>
              </div>
            </div>
            <div className="flex-1 relative bg-[#0f0f0f] timeline-grid min-w-[2000px]">
              {track.clips.map((clip) => (
                <div
                  key={clip.id}
                  onClick={(e) => {
                    e.stopPropagation();
                    onSelectClip(clip.id);
                  }}
                  className={`absolute top-1 bottom-1 rounded-sm border cursor-pointer transition-colors flex items-center px-2 overflow-hidden ${
                    selectedClipId === clip.id 
                      ? 'bg-blue-600/40 border-blue-400 z-10' 
                      : 'bg-zinc-800 border-zinc-700 hover:bg-zinc-700'
                  }`}
                  style={{
                    left: clip.startTime * pixelsPerSecond,
                    width: clip.duration * pixelsPerSecond
                  }}
                >
                  <span className="text-[10px] font-medium text-white truncate pointer-events-none">
                    {clip.id}
                  </span>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

