import React, { useState, useEffect, useCallback } from 'react';
import { Library } from './components/AssetLibrary/Library';
import { Timeline } from './components/Timeline/Timeline';
import { PreviewPlayer } from './components/Preview/PreviewPlayer';
import { useProjectStore } from './store/useProjectStore';
import { GeminiService } from './services/geminiService';
import { Settings, Download, Layers, Palette, Wand2, Type as TypeIcon, HelpCircle } from 'lucide-react';

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);
  const [activeTab, setActiveTab] = useState<'edit' | 'ai' | 'export'>('edit');

  // Playback timer effect
  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    const prompt = prompt("Describe the video you want to generate:");
    if (!prompt) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(prompt);
      const newAsset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${prompt.substring(0, 15)}...`,
        type: 'VIDEO' as any,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip(store.project.tracks[0].id, newAsset, store.currentTime);
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("Failed to generate AI video. Check console for details.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-[#0a0a0a]">
