              <button key={item} className="px-2.5 py-1 text-[11px] text-zinc-400 hover:text-white hover:bg-white/5 rounded transition-all">{item}</button>
            ))}
          </nav>
        </div>

        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 text-[11px] font-semibold px-4 py-1.5 rounded border border-zinc-700 transition-all">
