          </div>

          {/* Bottom Half: Timeline */}
          <Timeline 
            project={store.project}
            currentTime={store.currentTime}
            zoom={store.zoom}
            onTimeChange={store.setCurrentTime}
            onClipMove={store.moveClip}
            selectedClipId={store.selectedClipId}
            onSelectClip={store.setSelectedClipId}
          />
        </div>
      </main>

      {/* Loading Overlay for AI */}
      {isGenerating && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex flex-col items-center justify-center">
          <div className="w-64 h-2 bg-zinc-900 rounded-full overflow-hidden mb-6">
            <div className="h-full bg-blue-500 animate-[loading_2s_infinite_linear]" style={{ width: '40%' }}></div>
          </div>
          <p className="text-blue-400 font-medium animate-pulse">Consulting Veo Engine...</p>
          <p className="text-zinc-500 text-xs mt-2 italic">Generating your cinematic masterpiece</p>
        </div>
      )}

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(250%); }
        }
      `}</style>
    </div>
  );
};

export default App;

