    // API Key Selection: Veo models require user-selected paid API keys.
    // Check if an API key has been selected; if not, open the selection dialog.
    if (typeof window.aistudio !== 'undefined') {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          // Trigger the selection dialog and proceed to avoid race condition delays.
          window.aistudio.openSelectKey();
        }
      } catch (err) {
        console.warn("Failed to check API key selection", err);
      }
    }

    // Fix for Line 27: Use a different name for the variable to avoid shadowing the global prompt function.
    const userInput = window.prompt("Describe the video you want to generate:");
