import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  /**
   * Generates a video using Veo 3.1.
   * Note: Veo models require a user-selected paid API key from a billing-enabled project.
   */
  async generateVideo(prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') {
    // Create a new GoogleGenAI instance right before the call to ensure the latest selected API key is used.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: aspectRatio
      }
    });

    while (!operation.done) {
      // Poll every 5 seconds as video generation is a long-running process.
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation completed but no video URI was found.");
    }

    // The download link requires an API key to fetch the MP4 bytes.
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!response.ok) {
      throw new Error(`Failed to fetch generated video: ${response.statusText}`);
    }
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  }

  /**
   * Uses Gemini 3 Pro to generate a script or analyze video content with reasoning capabilities.
   */
  async analyzeContent(prompt: string) {
    // Create a new instance right before making an API call for up-to-date configuration.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        // High-quality reasoning for complex creative tasks.
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    // Use the .text property directly to extract output.
    return response.text || '';
  }
}

import { Asset, MediaType } from '../types';

export class AssetService {
  static async processFile(file: File): Promise<Asset> {
    const url = URL.createObjectURL(file);
    const type = file.type.startsWith('video/') ? MediaType.VIDEO : 
                 file.type.startsWith('audio/') ? MediaType.AUDIO : 
                 MediaType.IMAGE;

    let duration = 0;
    let thumbnail = '';

    if (type === MediaType.VIDEO || type === MediaType.AUDIO) {
      duration = await this.getMediaDuration(url);
      if (type === MediaType.VIDEO) {
        thumbnail = await this.generateThumbnail(url);
      }
    }

    return {
      id: `asset-${Math.random().toString(36).substr(2, 9)}`,
      name: file.name,
      type,
      url,
      duration,
      thumbnail
    };
  }

  private static getMediaDuration(url: string): Promise<number> {
    return new Promise((resolve) => {
      const media = document.createElement('video');
      media.src = url;
      media.onloadedmetadata = () => resolve(media.duration);
      media.onerror = () => resolve(0);
    });
  }

  private static generateThumbnail(url: string): Promise<string> {
    return new Promise((resolve) => {
      const video = document.createElement('video');
      video.src = url;
      video.currentTime = 1; // Seek to 1s for thumbnail
      video.onseeked = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 160;
        canvas.height = 90;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg'));
      };
      video.onerror = () => resolve('');
    });
  }
}

import { useState, useCallback } from 'react';
import { Project, Asset, Clip, Track } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [] },
    { id: 'track-v2', name: 'Video 2', type: 'video', clips: [] },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [] }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    const newClip: Clip = {
      id: `clip-${Math.random().toString(36).substr(2, 9)}`,
      assetId: asset.id,
      startTime: startTime,
      offset: 0,
      duration: asset.duration || 5, // Default 5s for images if duration is 0
      layer: 0,
      effects: []
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => 
        t.id === trackId ? { ...t, clips: [...t.clips, newClip] } : t
      )
    }));
  }, []);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => ({
        ...t,
        clips: t.clips.filter(c => c.id !== clipId)
      }))
    }));
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string, time: number) => {
    setProject(prev => {
      const newTracks = prev.tracks.map(track => {
        const clipIdx = track.clips.findIndex(c => c.id === clipId);
        if (clipIdx === -1) return track;

        const clip = track.clips[clipIdx];
        const relativeSplitPoint = time - clip.startTime;

        if (relativeSplitPoint <= 0 || relativeSplitPoint >= clip.duration) return track;

        const leftClip: Clip = { ...clip, duration: relativeSplitPoint };
        const rightClip: Clip = {
          ...clip,
          id: `clip-${Math.random().toString(36).substr(2, 9)}`,
          startTime: time,
          offset: clip.offset + relativeSplitPoint,
          duration: clip.duration - relativeSplitPoint
        };

        const filteredClips = track.clips.filter(c => c.id !== clipId);
        return { ...track, clips: [...filteredClips, leftClip, rightClip] };
      });

      return { ...prev, tracks: newTracks };
    });
  }, []);

  const moveClip = useCallback((clipId: string, trackId: string, newStartTime: number) => {
    setProject(prev => {
      let targetClip: Clip | null = null;
      const filteredTracks = prev.tracks.map(t => {
        const found = t.clips.find(c => c.id === clipId);
        if (found) targetClip = found;
        return { ...t, clips: t.clips.filter(c => c.id !== clipId) };
      });

      if (!targetClip) return prev;

      return {
        ...prev,
        tracks: filteredTracks.map(t => 
          t.id === trackId 
            ? { ...t, clips: [...t.clips, { ...targetClip!, startTime: Math.max(0, newStartTime) }] } 
            : t
        )
      };
    });
  }, []);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    addAsset,
    addClip,
    deleteClip,
    splitClip,
    moveClip,
    setProject
  };
};

import React, { useRef, useState, useEffect } from 'react';
import { Project, Clip } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut } from 'lucide-react';

interface TimelineProps {
  project: Project;
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ 
  project, 
  currentTime, 
  zoom, 
  setZoom,
  onTimeChange,
  onClipMove,
  onClipSplit,
  onClipDelete,
  selectedClipId,
  onSelectClip
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [draggingClip, setDraggingClip] = useState<{ id: string, startX: number, originalStartTime: number } | null>(null);

  const pixelsPerSecond = zoom * 10;

  const handleMouseDownPlayhead = (e: React.MouseEvent) => {
    setIsDraggingPlayhead(true);
    updateTimeFromEvent(e);
  };

  const updateTimeFromEvent = (e: React.MouseEvent | MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const scrollLeft = containerRef.current.scrollLeft;
    const x = e.clientX - rect.left + scrollLeft - 150;
    onTimeChange(Math.max(0, x / pixelsPerSecond));
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDraggingPlayhead) {
        updateTimeFromEvent(e);
      }
      if (draggingClip && containerRef.current) {
        const deltaX = e.clientX - draggingClip.startX;
        const deltaSeconds = deltaX / pixelsPerSecond;
        const newTime = draggingClip.originalStartTime + deltaSeconds;
        // In a real app, we would find the track ID under the cursor. 
        // For now, we'll keep it on the same track.
        const currentTrackId = project.tracks.find(t => t.clips.some(c => c.id === draggingClip.id))?.id;
        if (currentTrackId) {
          onClipMove(draggingClip.id, currentTrackId, newTime);
        }
      }
    };

    const handleMouseUp = () => {
      setIsDraggingPlayhead(false);
      setDraggingClip(null);
    };

    if (isDraggingPlayhead || draggingClip) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDraggingPlayhead, draggingClip, pixelsPerSecond]);

  const handleClipMouseDown = (e: React.MouseEvent, clip: Clip) => {
    e.stopPropagation();
    onSelectClip(clip.id);
    setDraggingClip({
      id: clip.id,
      startX: e.clientX,
      originalStartTime: clip.startTime
    });
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    const ms = Math.floor((seconds % 1) * 100);
    return `${mins}:${secs.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex-1 bg-[#121212] flex flex-col overflow-hidden border-t border-[#333]">
      {/* Toolbar */}
      <div className="h-10 bg-[#1a1a1a] border-b border-[#333] flex items-center px-4 justify-between">
        <div className="flex items-center gap-2">
          <button 
            disabled={!selectedClipId}
            onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)}
            className="p-1.5 hover:bg-zinc-800 rounded disabled:opacity-30 text-zinc-400 hover:text-white transition-colors"
            title="Split Clip (S)"
          >
            <Scissors size={16} />
          </button>
          <button 
            disabled={!selectedClipId}
            onClick={() => selectedClipId && onClipDelete(selectedClipId)}
            className="p-1.5 hover:bg-zinc-800 rounded disabled:opacity-30 text-red-400 transition-colors"
            title="Delete Clip"
          >
            <Trash2 size={16} />
          </button>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-[#111] px-2 py-1 rounded border border-zinc-800">
            <button onClick={() => setZoom(Math.max(1, zoom - 2))} className="text-zinc-500 hover:text-white"><ZoomOut size={14}/></button>
            <div className="w-16 h-1 bg-zinc-800 rounded-full overflow-hidden">
                <div className="h-full bg-blue-500" style={{ width: `${(zoom/50)*100}%` }} />
            </div>
            <button onClick={() => setZoom(Math.min(50, zoom + 2))} className="text-zinc-500 hover:text-white"><ZoomIn size={14}/></button>
          </div>
          <span className="text-[10px] font-mono text-zinc-500 uppercase tracking-tighter">
            Zoom: {zoom}x
          </span>
        </div>
      </div>

      {/* Ruler */}
      <div className="h-8 bg-[#1a1a1a] flex border-b border-[#333] relative select-none">
        <div className="w-[150px] flex-shrink-0 border-r border-[#333] flex items-center px-4 text-[10px] font-mono text-blue-400 font-bold">
          {formatTime(currentTime)}
        </div>
        <div 
          ref={containerRef}
          className="flex-1 overflow-x-auto relative timeline-grid scrollbar-hide"
          onMouseDown={handleMouseDownPlayhead}
        >
          {Array.from({ length: 100 }).map((_, i) => (
            <div 
              key={i} 
              className="absolute top-0 text-[9px] text-zinc-600 font-mono border-l border-zinc-800 h-full pl-1 pt-1"
              style={{ left: i * pixelsPerSecond }}
            >
              {i}s
            </div>
          ))}
          {/* Playhead */}
          <div 
            className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none"
            style={{ left: currentTime * pixelsPerSecond }}
          >
            <div className="absolute -top-1 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45 shadow-[0_0_10px_rgba(239,68,68,0.5)]" />
          </div>
        </div>
      </div>

      {/* Tracks */}
      <div className="flex-1 overflow-y-auto overflow-x-hidden" onClick={() => onSelectClip(null)}>
        {project.tracks.map((track) => (
          <div key={track.id} className="flex border-b border-[#222] min-h-[80px]">
            <div className="w-[150px] flex-shrink-0 bg-[#161616] border-r border-[#333] p-3 flex flex-col justify-center">
              <span className="text-[11px] font-semibold text-zinc-400 uppercase tracking-tight truncate">{track.name}</span>
              <div className="flex gap-2 mt-2">
                <button className="w-5 h-5 rounded bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-[10px] text-zinc-500">M</button>
                <button className="w-5 h-5 rounded bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-[10px] text-zinc-500">S</button>
              </div>
            </div>
            <div className="flex-1 relative bg-[#0d0d0d] timeline-grid min-w-[5000px]">
              {track.clips.map((clip) => (
                <div
                  key={clip.id}
                  onMouseDown={(e) => handleClipMouseDown(e, clip)}
                  className={`absolute top-2 bottom-2 rounded-md border-2 cursor-grab active:cursor-grabbing transition-shadow overflow-hidden group ${
                    selectedClipId === clip.id 
                      ? 'bg-blue-600/30 border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.2)] z-10' 
                      : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500'
                  }`}
                  style={{
                    left: clip.startTime * pixelsPerSecond,
                    width: clip.duration * pixelsPerSecond
                  }}
                >
                   <div className="absolute inset-0 opacity-20 pointer-events-none bg-gradient-to-r from-transparent via-white/5 to-transparent" />
                   <div className="h-full flex flex-col justify-center px-3 relative z-0">
                      <span className="text-[10px] font-bold text-white truncate pointer-events-none drop-shadow-md">
                        {clip.id.split('-')[1]}
                      </span>
                      <span className="text-[8px] text-zinc-400 font-mono pointer-events-none">
                        {clip.duration.toFixed(2)}s
                      </span>
                   </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

