import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize, Volume2 } from 'lucide-react';
import { Project, Asset } from '../../types';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  // Simple rendering logic: find the highest video clip at current time
  const activeClip = project.tracks
    .filter(t => t.type === 'video')
    .flatMap(t => t.clips)
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeAsset = activeClip ? assets.find(a => a.id === activeClip.assetId) : null;

  useEffect(() => {
    if (videoRef.current && activeAsset && activeClip) {
      const localTime = (currentTime - activeClip.startTime) + activeClip.offset;
      videoRef.current.currentTime = localTime;

      if (isPlaying) {
        videoRef.current.play().catch(() => {});
      } else {
        videoRef.current.pause();
      }
    }
  }, [currentTime, activeAsset?.id, isPlaying]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden">
      {/* Monitor Area */}
      <div className="flex-1 flex items-center justify-center p-8 bg-[#080808]">
        <div 
          className="aspect-video bg-[#000] shadow-[0_0_50px_rgba(0,0,0,0.5)] rounded-lg border border-white/5 flex items-center justify-center overflow-hidden relative"
          style={{ maxHeight: '100%', maxWidth: '100%' }}
        >
          {activeAsset && activeAsset.url ? (
            <video 
              ref={videoRef}
              src={activeAsset.url}
              className="w-full h-full object-contain"
              muted
              playsInline
            />
          ) : (
            <div className="text-center">
              <div className="w-16 h-16 rounded-3xl bg-zinc-900 border border-zinc-800 flex items-center justify-center mx-auto mb-4 opacity-50">
                <Play className="w-6 h-6 text-zinc-600" />
              </div>
              <p className="text-[10px] text-zinc-600 font-mono tracking-widest uppercase">No Active Media</p>
            </div>
          )}

          {/* Overlay info */}
          <div className="absolute top-4 left-4 flex gap-2">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono text-white border border-white/10 uppercase">
              Preview
            </div>
            {activeAsset && (
              <div className="px-2 py-1 bg-blue-600/40 backdrop-blur rounded text-[9px] font-mono text-white border border-blue-400/20 uppercase">
                {activeAsset.name}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Playback Controls */}
      <div className="h-14 bg-[#141414] border-t border-[#333] flex items-center justify-between px-6 z-10">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-10 h-10 rounded-full bg-white flex items-center justify-center hover:scale-110 transition-all shadow-[0_0_20px_rgba(255,255,255,0.2)] active:scale-95"
            >
              {isPlaying ? (
                <Pause className="text-black fill-black" size={18} />
              ) : (
                <Play className="text-black fill-black translate-x-0.5" size={18} />
              )}
            </button>
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipForward size={16} /></button>
          </div>
          <div className="px-3 py-1 bg-black rounded font-mono text-[13px] text-indigo-400 border border-zinc-800 tabular-nums">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">.{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 group">
            <Volume2 size={16} className="text-zinc-500 group-hover:text-zinc-300 transition-colors" />
            <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden relative">
              <div className="absolute inset-0 bg-indigo-600 w-3/4" />
            </div>
          </div>
          <button className="text-zinc-500 hover:text-white transition-colors">
            <Maximize size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
