declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    if (typeof window.aistudio !== 'undefined') {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          window.aistudio.openSelectKey();
        }
      } catch (err) {
        console.warn("Failed to check API key selection", err);
      }
    }

    const userInput = window.prompt("Describe the video you want to generate:");
    if (!userInput) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${userInput.substring(0, 15)}...`,
        type: MediaType.VIDEO,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip(store.project.tracks[0].id, newAsset, store.currentTime);
    } catch (error: any) {
      console.error("AI Generation failed:", error);
      if (error?.message?.includes("Requested entity was not found.") && typeof window.aistudio !== 'undefined') {
        alert("API Key error. Please ensure you have selected a valid paid API key.");
        await window.aistudio.openSelectKey();
      } else {
        alert("Failed to generate AI video.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    // Automatically add to first track at current playhead
    const targetTrackId = asset.type === MediaType.AUDIO ? 'track-a1' : 'track-v1';
    store.addClip(targetTrackId, asset, store.currentTime);
  };

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200">
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
