          <div className="flex items-center gap-2.5">
            <div className="w-7 h-7 bg-gradient-to-tr from-indigo-600 to-violet-500 rounded-lg flex items-center justify-center text-[11px] font-black shadow-lg shadow-indigo-600/30">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4">
            {['File', 'Edit', 'Sequence', 'View'].map(item => (
              <button key={item} className="px-3 py-1 text-[11px] font-semibold text-zinc-500 hover:text-white transition-colors">{item}</button>
            ))}
          </nav>
        </div>

        <div className="flex items-center gap-4">
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[10px] text-zinc-600 hover:text-zinc-400 transition-colors">Billing Documentation</a>
          <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-bold px-5 py-1.5 rounded-full transition-all shadow-lg shadow-indigo-600/20 active:scale-95">
            <Download size={14} /> Render
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10"><Layers size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Palette size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><TypeIcon size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Wand2 size={22} /></button>
          <div className="mt-auto mb-2 flex flex-col gap-6">
            <button className="text-zinc-600 hover:text-zinc-400"><Settings size={22} /></button>
            <button className="text-zinc-600 hover:text-zinc-400"><HelpCircle size={22} /></button>
          </div>
        </aside>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library 
              assets={store.assets} 
              onAddAsset={store.addAsset} 
              onGenerateAI={handleAICompose}
              onDragAssetToTimeline={handleAssetToTimeline}
            />
            <PreviewPlayer 
              project={store.project}
              assets={store.assets}
