      // Space for play/pause
      if (e.code === 'Space' && e.target === document.body) {
        e.preventDefault();
        store.setIsPlaying(!store.isPlaying);
      }
      // S or B for Split (B is a common standard in many editors for 'Blade')
      if ((e.code === 'KeyS' || e.code === 'KeyB') && store.selectedClipId) {
        store.splitClip(store.selectedClipId, store.currentTime);
      }
      // Delete for Delete
      if (e.code === 'Delete' && store.selectedClipId) {
        store.deleteClip(store.selectedClipId);
