interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  // Video logic: find the highest video clip at current time
  const activeVideoClip = project.tracks
    .filter(t => t.type === 'video')
    .flatMap(t => t.clips)
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;

  // Audio logic: find the first audio clip at current time (simplified for now)
  const activeAudioClip = project.tracks
    .filter(t => t.type === 'audio')
    .flatMap(t => t.clips)
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeAudioAsset = activeAudioClip ? assets.find(a => a.id === activeAudioClip.assetId) : null;

  useEffect(() => {
    // Handle Video sync
    if (videoRef.current && activeVideoAsset && activeVideoClip) {
      const localTime = (currentTime - activeVideoClip.startTime) + activeVideoClip.offset;
      // Precision check to avoid constant re-seeking if drift is minimal
      if (Math.abs(videoRef.current.currentTime - localTime) > 0.1) {
        videoRef.current.currentTime = localTime;
      }

      if (isPlaying) {
        videoRef.current.play().catch(() => {});
      } else {
        videoRef.current.pause();
      }
    } else if (videoRef.current) {
        videoRef.current.pause();
    }

    // Handle Audio sync
    if (audioRef.current && activeAudioAsset && activeAudioClip) {
      const localAudioTime = (currentTime - activeAudioClip.startTime) + activeAudioClip.offset;
      if (Math.abs(audioRef.current.currentTime - localAudioTime) > 0.1) {
        audioRef.current.currentTime = localAudioTime;
      }
      if (isPlaying) {
        audioRef.current.play().catch(() => {});
      } else {
        audioRef.current.pause();
      }
    } else if (audioRef.current) {
        audioRef.current.pause();
    }
  }, [currentTime, activeVideoAsset?.id, activeAudioAsset?.id, isPlaying]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden">
      {/* Monitor Area */}
      <div className="flex-1 flex items-center justify-center p-8 bg-[#080808]">
        <div 
          className="aspect-video bg-[#000] shadow-[0_0_50px_rgba(0,0,0,0.5)] rounded-lg border border-white/5 flex items-center justify-center overflow-hidden relative"
          style={{ maxHeight: '100%', maxWidth: '100%' }}
        >
          {activeVideoAsset && activeVideoAsset.url ? (
            <video 
              ref={videoRef}
              src={activeVideoAsset.url}
              className="w-full h-full object-contain"
              playsInline
            />
          ) : activeAudioAsset && activeAudioAsset.url ? (
             <div className="text-center">
              <div className="w-16 h-16 rounded-full bg-indigo-900/30 border border-indigo-500/30 flex items-center justify-center mx-auto mb-4 animate-pulse">
                <Volume2 className="w-6 h-6 text-indigo-400" />
              </div>
              <p className="text-[10px] text-indigo-400 font-mono tracking-widest uppercase">Playing Audio...</p>
            </div>
          ) : (
            <div className="text-center">
              <div className="w-16 h-16 rounded-3xl bg-zinc-900 border border-zinc-800 flex items-center justify-center mx-auto mb-4 opacity-50">
                <Play className="w-6 h-6 text-zinc-600" />
              </div>
              <p className="text-[10px] text-zinc-600 font-mono tracking-widest uppercase">No Active Media</p>
            </div>
          )}

          {/* Hidden audio element for audio tracks */}
          <audio ref={audioRef} src={activeAudioAsset?.url} />

          {/* Overlay info */}
          <div className="absolute top-4 left-4 flex gap-2">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono text-white border border-white/10 uppercase">
              Preview
            </div>
            {activeVideoAsset && (
              <div className="px-2 py-1 bg-blue-600/40 backdrop-blur rounded text-[9px] font-mono text-white border border-blue-400/20 uppercase">
                {activeVideoAsset.name}
              </div>
            )}
             {activeAudioAsset && !activeVideoAsset && (
              <div className="px-2 py-1 bg-indigo-600/40 backdrop-blur rounded text-[9px] font-mono text-white border border-indigo-400/20 uppercase">
                {activeAudioAsset.name}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Playback Controls */}
      <div className="h-14 bg-[#141414] border-t border-[#333] flex items-center justify-between px-6 z-10">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-10 h-10 rounded-full bg-white flex items-center justify-center hover:scale-110 transition-all shadow-[0_0_20px_rgba(255,255,255,0.2)] active:scale-95"
            >
              {isPlaying ? (
