import { useState, useCallback } from 'react';
import { Project, Asset, Clip, Track } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [] },
    { id: 'track-v2', name: 'Video 2', type: 'video', clips: [] },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [] }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    const newClip: Clip = {
      id: `clip-${Math.random().toString(36).substr(2, 9)}`,
      assetId: asset.id,
      startTime: startTime,
      offset: 0,
      duration: asset.duration || 5,
      layer: 0,
      effects: []
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => 
        t.id === trackId ? { ...t, clips: [...t.clips, newClip] } : t
      )
    }));
  }, []);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => ({
        ...t,
        clips: t.clips.filter(c => c.id !== clipId)
      }))
    }));
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string, time: number) => {
    setProject(prev => {
      let newlyCreatedId: string | null = null;
      const newTracks = prev.tracks.map(track => {
        const clipIdx = track.clips.findIndex(c => c.id === clipId);
        if (clipIdx === -1) return track;

        const clip = track.clips[clipIdx];
        const relativeSplitPoint = time - clip.startTime;

        if (relativeSplitPoint <= 0 || relativeSplitPoint >= clip.duration) return track;

        const leftClip: Clip = { ...clip, duration: relativeSplitPoint };
        const rightClipId = `clip-${Math.random().toString(36).substr(2, 9)}`;
        newlyCreatedId = rightClipId;
        const rightClip: Clip = {
          ...clip,
          id: rightClipId,
          startTime: time,
          offset: clip.offset + relativeSplitPoint,
          duration: clip.duration - relativeSplitPoint
        };

        const filteredClips = track.clips.filter(c => c.id !== clipId);
        return { ...track, clips: [...filteredClips, leftClip, rightClip].sort((a, b) => a.startTime - b.startTime) };
      });

      // Keep selection on the newly created right-side clip for better UX
      if (newlyCreatedId) setSelectedClipId(newlyCreatedId);
      return { ...prev, tracks: newTracks };
    });
  }, []);

  const moveClip = useCallback((clipId: string, trackId: string, newStartTime: number, useSnapping: boolean = true) => {
    setProject(prev => {
      let activeClip: Clip | null = null;
      for (const track of prev.tracks) {
        const found = track.clips.find(c => c.id === clipId);
        if (found) {
          activeClip = found;
          break;
        }
      }

      if (!activeClip) return prev;

      let adjustedStartTime = Math.max(0, newStartTime);

      // Magnet / Snapping Logic
      if (useSnapping) {
        const snapThreshold = 0.2;
        const pointsToSnap = [0, currentTime];
        prev.tracks.forEach(t => t.clips.forEach(c => {
          if (c.id !== clipId) {
            pointsToSnap.push(c.startTime);
            pointsToSnap.push(c.startTime + c.duration);
          }
        }));

        for (const point of pointsToSnap) {
          if (Math.abs(adjustedStartTime - point) < snapThreshold) {
            adjustedStartTime = point;
            break;
          }
          if (Math.abs((adjustedStartTime + activeClip.duration) - point) < snapThreshold) {
            adjustedStartTime = point - activeClip.duration;
            break;
          }
        }
      }

      // Advanced Ripple & Swap Logic
      const updatedTracks = prev.tracks.map(track => {
        const isTargetTrack = track.id === trackId;
        const hadClip = track.clips.some(c => c.id === clipId);

        if (!isTargetTrack) {
          return hadClip ? { ...track, clips: track.clips.filter(c => c.id !== clipId) } : track;
        }

        // We are on target track
        let others = track.clips.filter(c => c.id !== clipId).sort((a, b) => a.startTime - b.startTime);
        const movingClip = { ...activeClip!, startTime: adjustedStartTime };
        const movingEnd = movingClip.startTime + movingClip.duration;

        // Check for collision with an existing clip to perform a "Swap"
        const overlappedClip = others.find(c => 
          (movingClip.startTime >= c.startTime && movingClip.startTime < c.startTime + c.duration) ||
          (movingEnd > c.startTime && movingEnd <= c.startTime + c.duration)
        );

        if (overlappedClip) {
          // If we are significantly overlapping, we treat it as a shuffle
          const centerMoving = movingClip.startTime + movingClip.duration / 2;
          const centerOverlapped = overlappedClip.startTime + overlappedClip.duration / 2;

          if (centerMoving > centerOverlapped) {
            // Push overlapped clip back if moving right
            others = others.map(c => {
              if (c.id === overlappedClip.id) return { ...c, startTime: movingClip.startTime - c.duration };
              return c;
            });
          } else {
            // Push overlapped clip forward if moving left
            others = others.map(c => {
              if (c.id === overlappedClip.id) return { ...c, startTime: movingEnd };
              return c;
            });
          }
        }

        // Final conflict resolution to ensure no overlaps on the track
        const finalClips: Clip[] = [...others, movingClip].sort((a, b) => a.startTime - b.startTime);

        // Ensure no negative starts and handle ripple push
        for (let i = 0; i < finalClips.length; i++) {
            if (i > 0) {
                const prevClip = finalClips[i-1];
                const prevEnd = prevClip.startTime + prevClip.duration;
                if (finalClips[i].startTime < prevEnd) {
                    finalClips[i] = { ...finalClips[i], startTime: prevEnd };
                }
            }
            if (finalClips[i].startTime < 0) finalClips[i].startTime = 0;
        }

        return { ...track, clips: finalClips };
      });

      return { ...prev, tracks: updatedTracks };
    });
  }, [currentTime]);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    addAsset,
    addClip,
    deleteClip,
    splitClip,
    moveClip,
    setProject
  };
};

import React, { useRef, useState, useEffect } from 'react';
import { Project, Clip } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet } from 'lucide-react';

interface TimelineProps {
  project: Project;
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ 
  project, 
  currentTime, 
  zoom, 
  setZoom,
  onTimeChange,
  onClipMove,
  onClipSplit,
  onClipDelete,
  selectedClipId,
  onSelectClip
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [draggingClip, setDraggingClip] = useState<{ id: string, startX: number, originalStartTime: number } | null>(null);
  const [magnetEnabled, setMagnetEnabled] = useState(true);

  const pixelsPerSecond = zoom * 10;
  const HEADER_WIDTH = 150;

  const updateTimeFromEvent = (e: React.MouseEvent | MouseEvent) => {
    if (!scrollContainerRef.current) return;
    const rect = scrollContainerRef.current.getBoundingClientRect();
    const scrollLeft = scrollContainerRef.current.scrollLeft;
    const x = e.clientX - rect.left + scrollLeft - HEADER_WIDTH;
    onTimeChange(Math.max(0, x / pixelsPerSecond));
  };

  const handleMouseDownPlayhead = (e: React.MouseEvent) => {
    if (e.button !== 0) return;
    e.preventDefault();
    setIsDraggingPlayhead(true);
    updateTimeFromEvent(e);
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDraggingPlayhead) {
        updateTimeFromEvent(e);
      }
      if (draggingClip) {
        const deltaX = e.clientX - draggingClip.startX;
        const deltaSeconds = deltaX / pixelsPerSecond;
        const newTime = draggingClip.originalStartTime + deltaSeconds;

        const track = project.tracks.find(t => t.clips.some(c => c.id === draggingClip.id));
        if (track) {
          onClipMove(draggingClip.id, track.id, newTime, magnetEnabled);
        }
      }
    };

    const handleMouseUp = () => {
      setIsDraggingPlayhead(false);
      setDraggingClip(null);
    };

    if (isDraggingPlayhead || draggingClip) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDraggingPlayhead, draggingClip, pixelsPerSecond, project.tracks, magnetEnabled]);

  const handleClipMouseDown = (e: React.MouseEvent, clip: Clip) => {
    if (e.button !== 0) return;
    e.stopPropagation();
    onSelectClip(clip.id);
    setDraggingClip({
      id: clip.id,
      startX: e.clientX,
      originalStartTime: clip.startTime
    });
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    const frames = Math.floor((seconds % 1) * 30);
    return `${mins}:${secs.toString().padStart(2, '0')}:${frames.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800">
      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between select-none">
        <div className="flex items-center gap-2">
          <button 
            disabled={!selectedClipId}
            onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)}
            className="p-1.5 hover:bg-zinc-800 rounded disabled:opacity-20 text-zinc-400 hover:text-white transition-all active:scale-90"
            title="Split (B or S)"
          >
            <Scissors size={14} />
          </button>
          <button 
            disabled={!selectedClipId}
            onClick={() => selectedClipId && onClipDelete(selectedClipId)}
            className="p-1.5 hover:bg-zinc-800 rounded disabled:opacity-20 text-red-500/70 hover:text-red-500 transition-all active:scale-90"
            title="Delete (Del)"
          >
            <Trash2 size={14} />
          </button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <button 
            onClick={() => setMagnetEnabled(!magnetEnabled)}
            className={`p-1.5 rounded transition-all active:scale-90 ${magnetEnabled ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-500 hover:bg-zinc-800'}`}
            title="Toggle Magnet (Snapping)"
          >
            <Magnet size={14} />
          </button>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-3 bg-black/40 px-3 py-1 rounded-full border border-zinc-800">
            <button onClick={() => setZoom(Math.max(2, zoom - 2))} className="text-zinc-500 hover:text-zinc-200 transition-colors"><ZoomOut size={14}/></button>
            <div className="w-20 h-1 bg-zinc-800 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} />
            </div>
            <button onClick={() => setZoom(Math.min(50, zoom + 2))} className="text-zinc-500 hover:text-zinc-200 transition-colors"><ZoomIn size={14}/></button>
          </div>
          <span className="text-[10px] font-mono text-zinc-500 tabular-nums uppercase">Zoom {zoom}x</span>
        </div>
      </div>

      <div 
        ref={scrollContainerRef}
        className="flex-1 overflow-auto relative custom-scrollbar flex flex-col"
        onMouseDown={(e) => { 
          // Only clear selection if we directly clicked the timeline background, not a clip
          if (e.target === e.currentTarget) onSelectClip(null); 
        }}
      >
        <div className="min-w-max relative flex-1 flex flex-col">
          <div 
            className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch select-none"
            onMouseDown={handleMouseDownPlayhead}
          >
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {formatTime(currentTime)}
            </div>
            <div className="flex-1 relative h-full timeline-grid" style={{ width: 5000 * pixelsPerSecond }}>
              {Array.from({ length: 500 }).map((_, i) => (
                i % 5 === 0 && (
                  <div 
                    key={i} 
                    className="absolute top-0 h-full border-l border-zinc-800/50 flex flex-col justify-end pb-1 pl-1"
                    style={{ left: i * pixelsPerSecond }}
                  >
                    <span className="text-[9px] text-zinc-600 font-mono">{i}s</span>
                  </div>
                )
              ))}
            </div>
          </div>

          <div className="flex-1 flex flex-col min-w-max">
            {project.tracks.map((track) => (
              <div key={track.id} className="flex min-h-[72px] border-b border-zinc-800 group/track relative">
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-3 flex flex-col justify-center shadow-[4px_0_10px_rgba(0,0,0,0.3)]">
                  <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest group-hover/track:text-zinc-400 transition-colors">
                    {track.name}
                  </span>
                </div>

                <div 
                    className="flex-1 relative bg-[#0a0a0a] timeline-grid min-w-[5000px]"
                    onMouseDown={(e) => { if (e.target === e.currentTarget) onSelectClip(null); }}
                >
                  {track.clips.map((clip) => (
                    <div
                      key={clip.id}
                      onMouseDown={(e) => handleClipMouseDown(e, clip)}
                      className={`absolute top-2 bottom-2 rounded-lg border-2 cursor-grab active:cursor-grabbing transition-[border,box-shadow] overflow-hidden ${
                        selectedClipId === clip.id 
                          ? 'bg-indigo-600/50 border-indigo-400 shadow-[0_0_25px_rgba(99,102,241,0.4)] z-10' 
                          : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500'
                      }`}
                      style={{
                        left: clip.startTime * pixelsPerSecond,
                        width: clip.duration * pixelsPerSecond
                      }}
                    >
                       <div className="h-full flex flex-col justify-center px-3 select-none pointer-events-none">
                          <span className="text-[10px] font-bold text-white truncate drop-shadow-md uppercase">
                             {clip.id.split('-')[1]}
                          </span>
                          <div className="flex items-center gap-1.5 mt-0.5">
                            <span className="text-[8px] text-zinc-400 font-mono">
                                {clip.duration.toFixed(2)}s
                            </span>
                            {selectedClipId === clip.id && <div className="w-1 h-1 bg-indigo-400 rounded-full animate-pulse" />}
                          </div>
                       </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <div 
            className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none transition-shadow"
            style={{ 
              left: HEADER_WIDTH + (currentTime * pixelsPerSecond),
              boxShadow: '0 0 15px rgba(239, 68, 68, 0.4)'
            }}
          >
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useCallback } from 'react';
import { Project, Asset, Clip, Track } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [] },
    { id: 'track-v2', name: 'Video 2', type: 'video', clips: [] },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [] }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    const newClip: Clip = {
      id: `clip-${Math.random().toString(36).substr(2, 9)}`,
      assetId: asset.id,
      startTime: startTime,
      offset: 0,
      duration: asset.duration || 5,
      layer: 0,
      effects: []
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => {
        if (t.id !== trackId) return t;
        // Insert and ensure no overlap by simple push
        const sorted = [...t.clips, newClip].sort((a, b) => a.startTime - b.startTime);
        for(let i=0; i<sorted.length; i++) {
           if(i > 0 && sorted[i].startTime < sorted[i-1].startTime + sorted[i-1].duration) {
              sorted[i].startTime = sorted[i-1].startTime + sorted[i-1].duration;
           }
        }
        return { ...t, clips: sorted };
      })
    }));
  }, []);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => ({
        ...t,
        clips: t.clips.filter(c => c.id !== clipId)
      }))
    }));
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string, time: number) => {
    setProject(prev => {
      let newlyCreatedId: string | null = null;
      const newTracks = prev.tracks.map(track => {
        const clipIdx = track.clips.findIndex(c => c.id === clipId);
        if (clipIdx === -1) return track;

        const clip = track.clips[clipIdx];
        const relativeSplitPoint = time - clip.startTime;

        if (relativeSplitPoint <= 0.1 || relativeSplitPoint >= clip.duration - 0.1) return track;

        const leftClip: Clip = { ...clip, duration: relativeSplitPoint };
        const rightClipId = `clip-${Math.random().toString(36).substr(2, 9)}`;
        newlyCreatedId = rightClipId;
        const rightClip: Clip = {
          ...clip,
          id: rightClipId,
          startTime: time,
          offset: clip.offset + relativeSplitPoint,
          duration: clip.duration - relativeSplitPoint
        };

        const otherClips = track.clips.filter(c => c.id !== clipId);
        return { 
          ...track, 
          clips: [...otherClips, leftClip, rightClip].sort((a, b) => a.startTime - b.startTime) 
        };
      });

      if (newlyCreatedId) {
        // Use a slight timeout to ensure React finishes render before re-selecting
        setTimeout(() => setSelectedClipId(newlyCreatedId), 0);
      }
      return { ...prev, tracks: newTracks };
    });
  }, []);

  const moveClip = useCallback((clipId: string, trackId: string, newStartTime: number, useSnapping: boolean = true) => {
    setProject(prev => {
      let activeClip: Clip | null = null;
      for (const track of prev.tracks) {
        const found = track.clips.find(c => c.id === clipId);
        if (found) { activeClip = found; break; }
      }
      if (!activeClip) return prev;

      let adjustedStartTime = Math.max(0, newStartTime);

      // Snapping
      if (useSnapping) {
        const snapThreshold = 0.2;
        const points = [0, currentTime];
        prev.tracks.forEach(t => t.clips.forEach(c => {
          if (c.id !== clipId) { points.push(c.startTime); points.push(c.startTime + c.duration); }
        }));
        for (const p of points) {
          if (Math.abs(adjustedStartTime - p) < snapThreshold) { adjustedStartTime = p; break; }
          if (Math.abs((adjustedStartTime + activeClip.duration) - p) < snapThreshold) { adjustedStartTime = p - activeClip.duration; break; }
        }
      }

      const updatedTracks = prev.tracks.map(track => {
        // 1. Remove clip from its current track
        let others = track.clips.filter(c => c.id !== clipId).sort((a, b) => a.startTime - b.startTime);

        if (track.id !== trackId) return { ...track, clips: others };

        // 2. We are in the target track. Calculate order based on centers (to allow swapping)
        const movingClip = { ...activeClip!, startTime: adjustedStartTime };
        const movingCenter = adjustedStartTime + movingClip.duration / 2;

        // Find the insertion index based on where the center of our clip is relative to others
        let insertIdx = others.findIndex(c => (c.startTime + c.duration / 2) > movingCenter);
        if (insertIdx === -1) insertIdx = others.length;

        const combined = [...others];
        combined.splice(insertIdx, 0, movingClip);

        // 3. Ripple/Resolve overlaps:
        // If the user is moving it, we force the others to move away
        for (let i = 0; i < combined.length; i++) {
          if (i > 0) {
            const prevEnd = combined[i - 1].startTime + combined[i - 1].duration;
            if (combined[i].startTime < prevEnd) {
              combined[i].startTime = prevEnd;
            }
          }
        }

        return { ...track, clips: combined };
      });

      return { ...prev, tracks: updatedTracks };
    });
  }, [currentTime]);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    addAsset,
    addClip,
    deleteClip,
    splitClip,
    moveClip,
    setProject
  };
};

import React, { useState, useEffect, useCallback } from 'react';
import { Library } from './components/AssetLibrary/Library';
import { Timeline } from './components/Timeline/Timeline';
import { PreviewPlayer } from './components/Preview/PreviewPlayer';
import { useProjectStore } from './store/useProjectStore';
import { GeminiService } from './services/geminiService';
import { Settings, Download, Layers, Palette, Wand2, Type as TypeIcon, Scissors } from 'lucide-react';
import { MediaType, Asset } from './types';

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Avoid triggering when typing in an input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (e.code === 'Space') {
        e.preventDefault();
        store.setIsPlaying(!store.isPlaying);
      }
      if ((e.code === 'KeyS' || e.code === 'KeyB') && store.selectedClipId) {
        store.splitClip(store.selectedClipId, store.currentTime);
      }
      if (e.code === 'Delete' || e.code === 'Backspace') {
        if (store.selectedClipId) store.deleteClip(store.selectedClipId);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [store.selectedClipId, store.currentTime, store.isPlaying, store.splitClip, store.deleteClip, store.setIsPlaying]);

  // Playback timer
  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying, store.setCurrentTime]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) await aistudio.openSelectKey();
      } catch (err) { console.warn(err); }
    }

    const userInput = window.prompt("Describe your cinematic scene:");
    if (!userInput) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${userInput.substring(0, 10)}...`,
        type: MediaType.VIDEO,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip('track-v1', newAsset, store.currentTime);
    } catch (error: any) {
      alert("AI Video generation failed. Check connection or API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    const targetTrackId = asset.type === MediaType.AUDIO ? 'track-a1' : 'track-v1';
    store.addClip(targetTrackId, asset, store.currentTime);
  };

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200 select-none">
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer">
            <div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[11px] font-black">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">
            {['File', 'Edit', 'Sequence', 'Export'].map(item => (
              <button key={item} className="px-3 py-1 hover:text-white transition-colors">{item}</button>
            ))}
          </nav>
        </div>
        <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-bold px-5 py-1.5 rounded-full transition-all active:scale-95">
          <Download size={14} /> Render
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10"><Layers size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Palette size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><TypeIcon size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors" onClick={() => store.selectedClipId && store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
        </aside>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library 
              assets={store.assets} 
              onAddAsset={store.addAsset} 
              onGenerateAI={handleAICompose}
              onDragAssetToTimeline={handleAssetToTimeline}
            />
            <PreviewPlayer 
              project={store.project}
              assets={store.assets}
              isPlaying={store.isPlaying} 
              onTogglePlay={() => store.setIsPlaying(!store.isPlaying)} 
              currentTime={store.currentTime} 
            />
            <div className="w-[300px] bg-[#121212] border-l border-zinc-800/50 p-6 overflow-y-auto">
              <h2 className="text-[10px] font-bold uppercase tracking-widest text-zinc-600 mb-8 flex items-center gap-2">
                <Settings size={12}/> Properties
              </h2>
              {store.selectedClipId ? (
                <div className="space-y-6">
                   <div className="p-3 bg-zinc-900/50 rounded-xl border border-zinc-800">
                      <span className="text-[9px] text-zinc-500 block mb-2 font-black uppercase">Clip Info</span>
                      <p className="text-[10px] font-mono text-indigo-400 truncate">{store.selectedClipId}</p>
                   </div>
                   <div className="space-y-4">
                      <label className="text-[10px] text-zinc-500 uppercase font-black">Quick Actions</label>
                      <button 
                        onClick={() => store.selectedClipId && store.deleteClip(store.selectedClipId)}
                        className="w-full py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 text-[10px] font-bold rounded-lg transition-colors border border-red-500/20"
                      >
                        Delete Clip
                      </button>
                   </div>
                </div>
              ) : (
                <p className="text-[11px] text-zinc-600 text-center mt-20 italic">Select a clip to edit properties</p>
              )}
            </div>
          </div>

          <Timeline 
            project={store.project}
            currentTime={store.currentTime}
            zoom={store.zoom}
            setZoom={store.setZoom}
            onTimeChange={store.setCurrentTime}
            onClipMove={store.moveClip}
            onClipSplit={store.splitClip}
            onClipDelete={store.deleteClip}
            selectedClipId={store.selectedClipId}
            onSelectClip={store.setSelectedClipId}
          />
        </div>
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-sm z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6" />
          <h3 className="text-lg font-bold">AI Rendering Sequence...</h3>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize, Volume2 } from 'lucide-react';
import { Project, Asset } from '../../types';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const allClips = project.tracks.flatMap(t => t.clips.map(c => ({ ...c, trackType: t.type })));

  const activeVideoClip = allClips
    .filter(c => c.trackType === 'video')
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeAudioClip = allClips
    .filter(c => c.trackType === 'audio')
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;
  const activeAudioAsset = activeAudioClip ? assets.find(a => a.id === activeAudioClip.assetId) : null;

  useEffect(() => {
    const syncMedia = (element: HTMLMediaElement | null, clip: any, asset: any) => {
      if (!element) return;
      if (asset && clip) {
        const targetTime = (currentTime - clip.startTime) + clip.offset;
        if (Math.abs(element.currentTime - targetTime) > 0.15) {
          element.currentTime = targetTime;
        }
        if (isPlaying) {
          element.play().catch(() => {});
        } else {
          element.pause();
        }
      } else {
        element.pause();
      }
    };

    syncMedia(videoRef.current, activeVideoClip, activeVideoAsset);
    syncMedia(audioRef.current, activeAudioClip, activeAudioAsset);
  }, [currentTime, isPlaying, activeVideoAsset?.id, activeAudioAsset?.id]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden border-x border-zinc-800/50">
      <div className="flex-1 flex items-center justify-center p-6 bg-[#0a0a0a]">
        <div className="aspect-video w-full max-w-4xl bg-black rounded shadow-2xl border border-white/5 flex items-center justify-center overflow-hidden relative">
          {activeVideoAsset ? (
            <video ref={videoRef} src={activeVideoAsset.url} className="w-full h-full object-contain" muted />
          ) : (
            <div className="text-zinc-800 text-[10px] font-black uppercase tracking-widest">No Video Signal</div>
          )}

          <audio ref={audioRef} src={activeAudioAsset?.url} />

          <div className="absolute top-4 left-4 flex gap-2">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono border border-white/10 uppercase">Monitor</div>
          </div>
        </div>
      </div>

      <div className="h-14 bg-[#121212] border-t border-zinc-800 flex items-center justify-between px-6">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-9 h-9 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-all active:scale-95"
            >
              {isPlaying ? <Pause className="text-black fill-black" size={16} /> : <Play className="text-black fill-black translate-x-0.5" size={16} />}
            </button>
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipForward size={16} /></button>
          </div>
          <div className="font-mono text-[13px] text-indigo-400 tabular-nums">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">:{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>
        <div className="flex items-center gap-4 text-zinc-500">
          <Volume2 size={16} />
          <Maximize size={16} className="cursor-pointer hover:text-white" />
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Project, Clip } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet } from 'lucide-react';

interface TimelineProps {
  project: Project;
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number, snapping: boolean) => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ 
  project, currentTime, zoom, setZoom, onTimeChange, onClipMove, onClipSplit, onClipDelete, selectedClipId, onSelectClip
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [dragging, setDragging] = useState<{ id: string, startX: number, originalStart: number } | null>(null);
  const [magnet, setMagnet] = useState(true);

  const pxPerSec = zoom * 10;
  const HEADER = 150;

  const getT = (e: React.MouseEvent | MouseEvent) => {
    if (!scrollRef.current) return 0;
    const rect = scrollRef.current.getBoundingClientRect();
    return Math.max(0, (e.clientX - rect.left + scrollRef.current.scrollLeft - HEADER) / pxPerSec);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (isDraggingPlayhead) onTimeChange(getT(e));
      if (dragging) {
        const delta = (e.clientX - dragging.startX) / pxPerSec;
        const track = project.tracks.find(t => t.clips.some(c => c.id === dragging.id));
        if (track) onClipMove(dragging.id, track.id, dragging.originalStart + delta, magnet);
      }
    };
    const up = () => { setIsDraggingPlayhead(false); setDragging(null); };
    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', up);
    return () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
  }, [isDraggingPlayhead, dragging, pxPerSec, project.tracks, magnet]);

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800">
      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between">
        <div className="flex items-center gap-2">
          <button onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)} className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-all"><Scissors size={14} /></button>
          <button onClick={() => selectedClipId && onClipDelete(selectedClipId)} className="p-1.5 hover:bg-zinc-800 rounded text-red-500/70 hover:text-red-500 transition-all"><Trash2 size={14} /></button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <button onClick={() => setMagnet(!magnet)} className={`p-1.5 rounded transition-all ${magnet ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-500 hover:bg-zinc-800'}`}><Magnet size={14} /></button>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setZoom(Math.max(2, zoom - 2))}><ZoomOut size={14} className="text-zinc-500 hover:text-white" /></button>
          <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} /></div>
          <button onClick={() => setZoom(Math.min(50, zoom + 2))}><ZoomIn size={14} className="text-zinc-500 hover:text-white" /></button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto relative custom-scrollbar flex flex-col" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
        <div className="min-w-max relative flex-1">
          <div className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch" onMouseDown={(e) => { e.preventDefault(); setIsDraggingPlayhead(true); onTimeChange(getT(e)); }}>
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {Math.floor(currentTime/60)}:{(Math.floor(currentTime%60)).toString().padStart(2,'0')}
            </div>
            <div className="flex-1 relative h-full" style={{ width: 5000 * pxPerSec }}>
              {Array.from({length: 100}).map((_, i) => i%5===0 && <div key={i} className="absolute top-0 h-full border-l border-zinc-800/50 pl-1 text-[9px] text-zinc-600 font-mono" style={{ left: i*pxPerSec }}>{i}s</div>)}
            </div>
          </div>

          <div className="flex flex-col">
            {project.tracks.map(track => (
              <div key={track.id} className="flex min-h-[72px] border-b border-zinc-800 group/track relative">
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-3 flex flex-col justify-center">
                  <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">{track.name}</span>
                </div>
                <div className="flex-1 relative bg-[#0a0a0a] min-w-[5000px]" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
                  {track.clips.map(clip => (
                    <div
                      key={clip.id}
                      onMouseDown={(e) => { e.stopPropagation(); onSelectClip(clip.id); setDragging({id: clip.id, startX: e.clientX, originalStart: clip.startTime}); }}
                      className={`absolute top-2 bottom-2 rounded-lg border-2 cursor-grab active:cursor-grabbing transition-[border,box-shadow] flex flex-col justify-center px-3 overflow-hidden ${selectedClipId === clip.id ? 'bg-indigo-600/40 border-indigo-400 shadow-[0_0_20px_rgba(99,102,241,0.3)] z-10' : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500'}`}
                      style={{ left: clip.startTime * pxPerSec, width: clip.duration * pxPerSec }}
                    >
                      <span className="text-[10px] font-bold text-white truncate uppercase">{clip.id.split('-')[1]}</span>
                      <span className="text-[8px] text-zinc-500 font-mono">{clip.duration.toFixed(2)}s</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none" style={{ left: HEADER + (currentTime * pxPerSec) }}>
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useCallback } from 'react';
import { Project, Asset, Clip, Track } from '../types';

const INITIAL_PROJECT: Project = {
