        {assets.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center opacity-20 px-10">
            <div className="w-16 h-16 rounded-2xl bg-zinc-800 flex items-center justify-center mb-4">
               <Film size={32} />
            </div>
            <p className="text-[11px] font-medium">Your library is empty. Click Import to start editing.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-2">
            {assets.map(asset => (
              <div 
                key={asset.id} 
                draggable
                onDragStart={(e) => handleDragStart(e, asset)}
                onClick={() => onDragAssetToTimeline(asset)}
                className="group flex gap-3 p-2 bg-[#111] rounded-lg border border-[#333] hover:border-indigo-500 transition-all cursor-pointer hover:bg-[#161616]"
              >
                <div className="w-20 aspect-video bg-black rounded overflow-hidden flex-shrink-0 relative">
                  {asset.thumbnail ? (
                    <img src={asset.thumbnail} className="w-full h-full object-cover" />
