        )}
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Project, Clip, Track, Asset } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet, Eye, EyeOff, Volume2, VolumeX, Lock, Unlock } from 'lucide-react';

interface TimelineProps {
  project: Project;
  assets: Asset[];
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipFinalize: () => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  onToggleTrack: (trackId: string, prop: 'isVisible' | 'isMuted' | 'isLocked') => void;
  onAddClipAtPosition: (trackId: string, asset: Asset, startTime: number) => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ 
  project, assets, currentTime, zoom, setZoom, onTimeChange, onClipMove, onClipFinalize, onClipSplit, onClipDelete, onToggleTrack, onAddClipAtPosition, selectedClipId, onSelectClip
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const tracksRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [dragging, setDragging] = useState<{ id: string, startX: number, startY: number, originalStart: number } | null>(null);

  const pxPerSec = zoom * 10;
  const HEADER_WIDTH = 150;
  const TRACK_HEIGHT = 72;

  const getT = (clientX: number) => {
    if (!scrollRef.current) return 0;
    const rect = scrollRef.current.getBoundingClientRect();
    return Math.max(0, (clientX - rect.left + scrollRef.current.scrollLeft - HEADER_WIDTH) / pxPerSec);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (isDraggingPlayhead) onTimeChange(getT(e.clientX));
      if (dragging) {
        const deltaX = (e.clientX - dragging.startX) / pxPerSec;
        if (tracksRef.current) {
          const tracksRect = tracksRef.current.getBoundingClientRect();
          const relativeY = e.clientY - tracksRect.top;
          const hoveredTrackIdx = Math.floor(relativeY / TRACK_HEIGHT);
          const hoveredTrack = project.tracks[hoveredTrackIdx];
          if (hoveredTrack && !hoveredTrack.isLocked) {
             onClipMove(dragging.id, hoveredTrack.id, dragging.originalStart + deltaX);
          }
        }
      }
    };
    const up = () => { 
      if (dragging) onClipFinalize();
      setIsDraggingPlayhead(false); 
      setDragging(null); 
    };
    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', up);
    return () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
  }, [isDraggingPlayhead, dragging, pxPerSec, project.tracks]);

  const handleDrop = (e: React.DragEvent, trackId: string) => {
    e.preventDefault();
    const assetId = e.dataTransfer.getData('assetId');
    const asset = assets.find(a => a.id === assetId);
    if (asset) {
      const dropTime = getT(e.clientX);
      onAddClipAtPosition(trackId, asset, dropTime);
    }
  };

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800">
      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between select-none">
        <div className="flex items-center gap-2">
          <button onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)} className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-all"><Scissors size={14} /></button>
          <button onClick={() => selectedClipId && onClipDelete(selectedClipId)} className="p-1.5 hover:bg-zinc-800 rounded text-red-500/70 hover:text-red-500 transition-all"><Trash2 size={14} /></button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <div className="flex items-center gap-2 px-2 py-1 bg-indigo-500/10 rounded text-[10px] text-indigo-400 font-bold border border-indigo-500/20">
            <Magnet size={12} /> MAGNETIC
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setZoom(Math.max(2, zoom - 2))}><ZoomOut size={14} className="text-zinc-500 hover:text-white" /></button>
          <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} /></div>
          <button onClick={() => setZoom(Math.min(50, zoom + 2))}><ZoomIn size={14} className="text-zinc-500 hover:text-white" /></button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto relative custom-scrollbar flex flex-col" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
        <div className="min-w-max relative flex-1">
          <div className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch select-none" onMouseDown={(e) => { e.preventDefault(); setIsDraggingPlayhead(true); onTimeChange(getT(e.clientX)); }}>
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {Math.floor(currentTime/60)}:{(Math.floor(currentTime%60)).toString().padStart(2,'0')}
            </div>
            <div className="flex-1 relative h-full" style={{ width: 5000 * pxPerSec }}>
              {Array.from({length: 100}).map((_, i) => i%5===0 && <div key={i} className="absolute top-0 h-full border-l border-zinc-800/50 pl-1 text-[9px] text-zinc-600 font-mono" style={{ left: i*pxPerSec }}>{i}s</div>)}
            </div>
          </div>

          <div className="flex flex-col" ref={tracksRef}>
            {project.tracks.map(track => (
              <div 
                key={track.id} 
                onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
                onDrop={(e) => handleDrop(e, track.id)}
                className={`flex h-[72px] border-b border-zinc-800 group/track relative ${track.isVisible ? '' : 'opacity-60'}`}
              >
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-2 flex flex-col justify-center gap-1 shadow-lg">
                  <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest truncate">{track.name}</span>
                  <div className="flex items-center gap-1">
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isVisible')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isVisible ? 'text-zinc-400' : 'text-indigo-500'}`}
                    >
                      {track.isVisible ? <Eye size={12} /> : <EyeOff size={12} />}
                    </button>
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isMuted')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isMuted ? 'text-red-500' : 'text-zinc-400'}`}
                    >
                      {track.isMuted ? <VolumeX size={12} /> : <Volume2 size={12} />}
                    </button>
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isLocked')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isLocked ? 'text-orange-500' : 'text-zinc-400'}`}
                    >
                      {track.isLocked ? <Lock size={12} /> : <Unlock size={12} />}
                    </button>
                  </div>
                </div>
                <div className="flex-1 relative bg-[#0a0a0a] min-w-[5000px]" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
                  {track.clips.map(clip => (
                    <div
                      key={clip.id}
                      onMouseDown={(e) => { 
                        if (track.isLocked) return;
                        e.stopPropagation(); 
                        onSelectClip(clip.id); 
                        setDragging({id: clip.id, startX: e.clientX, startY: e.clientY, originalStart: clip.startTime}); 
                      }}
                      className={`absolute top-2 bottom-2 rounded-lg border-2 flex flex-col justify-center px-3 overflow-hidden select-none transition-all duration-300 ease-in-out ${
                        track.isLocked ? 'cursor-not-allowed grayscale' : 'cursor-grab active:cursor-grabbing'
                      } ${
                        selectedClipId === clip.id 
                          ? 'bg-indigo-600/50 border-indigo-400 shadow-[0_0_30px_rgba(99,102,241,0.4)] z-20' 
                          : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500 z-10'
                      }`}
                      style={{ 
                        left: clip.startTime * pxPerSec, 
                        width: clip.duration * pxPerSec,
                        transition: dragging && dragging.id === clip.id ? 'none' : undefined
                      }}
                    >
                      <span className="text-[10px] font-bold text-white truncate uppercase drop-shadow-md">{clip.id.split('-')[1]}</span>
                      <span className="text-[8px] text-zinc-400 font-mono font-bold tracking-tighter">{clip.duration.toFixed(2)}s</span>
                      {track.isLocked && <Lock size={10} className="absolute top-1 right-1 text-orange-500/50" />}
                    </div>
                  ))}
                  {!track.isVisible && <div className="absolute inset-0 bg-black/20 pointer-events-none flex items-center justify-end pr-4 text-[8px] text-zinc-700 font-bold uppercase tracking-widest">Visuals Hidden</div>}
                </div>
              </div>
            ))}
          </div>

          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]" style={{ left: HEADER_WIDTH + (currentTime * pxPerSec) }}>
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize, Volume2, VolumeX } from 'lucide-react';
import { Project, Asset } from '../../types';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioContainerRef = useRef<HTMLDivElement>(null);

  // Video logic: show only the topmost clip from a visible track
  const activeVideoClip = project.tracks
    .slice()
    .reverse()
    .filter(t => t.type === 'video' && t.isVisible)
    .flatMap(t => t.clips)
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;
  const isVideoMuted = project.tracks.find(t => t.clips.some(c => c.id === activeVideoClip?.id))?.isMuted;

  // Audio logic: find ALL active audio clips from non-muted tracks
  const activeAudioClips = project.tracks
    .filter(t => !t.isMuted)
    .flatMap(t => t.clips.map(c => ({ clip: c, asset: assets.find(a => a.id === c.assetId) })))
    .filter(item => item.asset && currentTime >= item.clip.startTime && currentTime <= item.clip.startTime + item.clip.duration);

  useEffect(() => {
    if (!videoRef.current) return;
    if (activeVideoAsset && activeVideoClip) {
      videoRef.current.muted = !!isVideoMuted;
      const targetTime = (currentTime - activeVideoClip.startTime) + activeVideoClip.offset;
      if (Math.abs(videoRef.current.currentTime - targetTime) > 0.15) {
        videoRef.current.currentTime = targetTime;
      }
      if (isPlaying) videoRef.current.play().catch(() => {});
      else videoRef.current.pause();
    } else {
      videoRef.current.pause();
    }
  }, [currentTime, isPlaying, activeVideoAsset?.id, isVideoMuted]);

  // Audio elements sync (simple multi-track mixing)
  useEffect(() => {
    if (!audioContainerRef.current) return;
    const container = audioContainerRef.current;

    // Manage dynamic audio tags for each active clip
    activeAudioClips.forEach(({ clip, asset }) => {
      if (!asset) return;
      let el = container.querySelector(`[data-clip-id="${clip.id}"]`) as HTMLAudioElement;
      if (!el) {
        el = document.createElement('audio');
        el.dataset.clipId = clip.id;
        el.src = asset.url;
        container.appendChild(el);
      }
      const targetTime = (currentTime - clip.startTime) + clip.offset;
      if (Math.abs(el.currentTime - targetTime) > 0.15) {
        el.currentTime = targetTime;
      }
      if (isPlaying) el.play().catch(() => {});
      else el.pause();
    });

    // Cleanup inactive audio elements
    Array.from(container.children).forEach((child) => {
      const el = child as HTMLAudioElement;
      if (!activeAudioClips.some(c => c.clip.id === el.dataset.clipId)) {
        el.pause();
        el.remove();
      }
    });
  }, [currentTime, isPlaying, activeAudioClips.length]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden border-x border-zinc-800/50">
      <div ref={audioContainerRef} className="hidden" />
      <div className="flex-1 flex items-center justify-center p-6 bg-[#0a0a0a]">
        <div className="aspect-video w-full max-w-4xl bg-black rounded shadow-2xl border border-white/5 flex items-center justify-center overflow-hidden relative">
          {activeVideoAsset ? (
            <video 
              ref={videoRef} 
              src={activeVideoAsset.url} 
              className="w-full h-full object-contain" 
            />
          ) : (
            <div className="text-zinc-800 text-[10px] font-black uppercase tracking-widest">No Signal</div>
          )}

          <div className="absolute top-4 left-4 flex gap-2">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono border border-white/10 uppercase">Nexus Monitor</div>
            {isVideoMuted && <div className="px-2 py-1 bg-red-500/20 backdrop-blur rounded text-[9px] font-mono border border-red-500/10 text-red-500 uppercase flex items-center gap-1"><VolumeX size={10} /> Video Muted</div>}
          </div>
        </div>
      </div>

      <div className="h-14 bg-[#121212] border-t border-zinc-800 flex items-center justify-between px-6">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-9 h-9 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-all active:scale-95 shadow-xl"
            >
              {isPlaying ? <Pause className="text-black fill-black" size={16} /> : <Play className="text-black fill-black translate-x-0.5" size={16} />}
            </button>
            <button className="text-zinc-500 hover:text-white transition-colors"><SkipForward size={16} /></button>
          </div>
          <div className="font-mono text-[13px] text-indigo-400 tabular-nums bg-indigo-500/5 px-3 py-1 rounded border border-indigo-500/10">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">:{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>
        <div className="flex items-center gap-4 text-zinc-500">
           <Maximize size={16} className="cursor-pointer hover:text-white transition-colors" />
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Library } from './components/AssetLibrary/Library';
import { Timeline } from './components/Timeline/Timeline';
import { PreviewPlayer } from './components/Preview/PreviewPlayer';
import { useProjectStore } from './store/useProjectStore';
import { GeminiService } from './services/geminiService';
import { Settings, Download, Layers, Palette, Wand2, Type as TypeIcon, Scissors } from 'lucide-react';
import { MediaType, Asset } from './types';

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (e.code === 'Space') {
        e.preventDefault();
        store.setIsPlaying(!store.isPlaying);
      }
      if ((e.code === 'KeyS' || e.code === 'KeyB') && store.selectedClipId) {
        store.splitClip(store.selectedClipId, store.currentTime);
      }
      if (e.code === 'Delete' || e.code === 'Backspace') {
        if (store.selectedClipId) store.deleteClip(store.selectedClipId);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [store.selectedClipId, store.currentTime, store.isPlaying]);

  // Playback timer
  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) await aistudio.openSelectKey();
      } catch (err) { console.warn(err); }
    }

    const userInput = window.prompt("Describe your cinematic scene:");
    if (!userInput) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${userInput.substring(0, 10)}...`,
        type: MediaType.VIDEO,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip('track-v1', newAsset, store.currentTime);
    } catch (error: any) {
      if (error?.message?.includes("Requested entity was not found.")) {
        const aistudio = (window as any).aistudio;
        if (aistudio) {
          await aistudio.openSelectKey();
        }
      }
      alert("AI Video generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    const targetTrackId = asset.type === MediaType.AUDIO ? 'track-a1' : 'track-v1';
    store.addClip(targetTrackId, asset, store.currentTime);
  };

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200 select-none">
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer">
            <div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[11px] font-black">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">
            {['File', 'Edit', 'Sequence', 'Export'].map(item => (
              <button key={item} className="px-3 py-1 hover:text-white transition-colors">{item}</button>
            ))}
          </nav>
        </div>
        <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-bold px-5 py-1.5 rounded-full transition-all active:scale-95">
          <Download size={14} /> Render
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10"><Layers size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Palette size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><TypeIcon size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors" onClick={() => store.selectedClipId && store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
        </aside>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library 
              assets={store.assets} 
              onAddAsset={store.addAsset} 
              onGenerateAI={handleAICompose}
              onDragAssetToTimeline={handleAssetToTimeline}
            />
            <PreviewPlayer 
              project={store.project}
              assets={store.assets}
              isPlaying={store.isPlaying} 
              onTogglePlay={() => store.setIsPlaying(!store.isPlaying)} 
              currentTime={store.currentTime} 
            />
            <div className="w-[300px] bg-[#121212] border-l border-zinc-800/50 p-6 overflow-y-auto">
              <h2 className="text-[10px] font-bold uppercase tracking-widest text-zinc-600 mb-8 flex items-center gap-2">
                <Settings size={12}/> Properties
              </h2>
              {store.selectedClipId ? (
                <div className="space-y-6">
                   <div className="p-3 bg-zinc-900/50 rounded-xl border border-zinc-800">
                      <span className="text-[9px] text-zinc-500 block mb-2 font-black uppercase">Clip Info</span>
                      <p className="text-[10px] font-mono text-indigo-400 truncate">{store.selectedClipId}</p>
                   </div>
                   <div className="space-y-4">
                      <label className="text-[10px] text-zinc-500 uppercase font-black">Quick Actions</label>
                      <button 
                        onClick={() => store.selectedClipId && store.deleteClip(store.selectedClipId)}
                        className="w-full py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 text-[10px] font-bold rounded-lg transition-colors border border-red-500/20"
                      >
                        Delete Clip
                      </button>
                   </div>
                </div>
              ) : (
                <p className="text-[11px] text-zinc-600 text-center mt-20 italic">Select a clip to edit properties</p>
              )}
            </div>
          </div>

          <Timeline 
            project={store.project}
            assets={store.assets}
            currentTime={store.currentTime}
            zoom={store.zoom}
            setZoom={store.setZoom}
            onTimeChange={store.setCurrentTime}
            onClipMove={store.moveClip}
            onClipFinalize={store.finalizeMove}
            onClipSplit={store.splitClip}
            onClipDelete={store.deleteClip}
            onToggleTrack={store.toggleTrackProperty}
            onAddClipAtPosition={store.addClipAtPosition}
            selectedClipId={store.selectedClipId}
            onSelectClip={store.setSelectedClipId}
          />
        </div>
      </main>

      {isGenerating && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-sm z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6" />
          <h3 className="text-lg font-bold">AI Rendering Sequence...</h3>
        </div>
      )}
    </div>
  );
};

export default App;

import { useState, useCallback } from 'react';
import { Project, Asset, Clip, Track, MediaType } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [], isVisible: true, isMuted: false, isLocked: false },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [], isVisible: true, isMuted: false, isLocked: false }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const toggleTrackProperty = useCallback((trackId: string, property: 'isVisible' | 'isMuted' | 'isLocked') => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => t.id === trackId ? { ...t, [property]: !t[property] } : t)
    }));
  }, []);

  const addTrack = useCallback((type: 'video' | 'audio') => {
    setProject(prev => {
      const typeCount = prev.tracks.filter(t => t.type === type).length + 1;
      const newTrack: Track = {
        id: `track-${type[0]}-${Date.now()}`,
        name: `${type.charAt(0).toUpperCase() + type.slice(1)} ${typeCount}`,
        type,
        clips: [],
        isVisible: true,
        isMuted: false,
        isLocked: false
      };
      // Keep video tracks on top
      const videoTracks = type === 'video' ? [...prev.tracks.filter(t => t.type === 'video'), newTrack] : prev.tracks.filter(t => t.type === 'video');
      const audioTracks = type === 'audio' ? [...prev.tracks.filter(t => t.type === 'audio'), newTrack] : prev.tracks.filter(t => t.type === 'audio');
      return { ...prev, tracks: [...videoTracks, ...audioTracks] };
    });
  }, []);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const addClipAtPosition = useCallback((trackId: string, asset: Asset, startTime: number) => {
    const track = project.tracks.find(t => t.id === trackId);
    if (!track || track.isLocked) return;

    const isAudioTrack = track.type === 'audio';
    const isAudioAsset = asset.type === MediaType.AUDIO;
    if (isAudioTrack !== isAudioAsset) return;

    const newClip: Clip = {
      id: `clip-${Math.random().toString(36).substr(2, 9)}`,
      assetId: asset.id,
      startTime: startTime,
      offset: 0,
      duration: asset.duration || 5,
      layer: 0,
      effects: []
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => {
        if (t.id !== trackId) return t;
        const newClips = [...t.clips, newClip].sort((a, b) => a.startTime - b.startTime);
        let cursor = 0;
        return { 
          ...t, 
          clips: newClips.map(c => {
            const start = cursor;
            cursor += c.duration;
            return { ...c, startTime: start };
          })
        };
      })
    }));
  }, [project.tracks]);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    addClipAtPosition(trackId, asset, startTime);
  }, [addClipAtPosition]);

  const detachAudio = useCallback((clipId: string) => {
    let sourceClip: Clip | null = null;
    let sourceAsset: Asset | null = null;

    project.tracks.forEach(t => {
      const found = t.clips.find(c => c.id === clipId);
      if (found) {
        sourceClip = found;
        sourceAsset = assets.find(a => a.id === found!.assetId) || null;
      }
    });

    if (!sourceClip || !sourceAsset) return;

    // Find first unlocked audio track
    const targetTrack = project.tracks.find(t => t.type === 'audio' && !t.isLocked);
    if (!targetTrack) {
      alert("Please add an unlocked audio track first.");
      return;
    }

    const audioClip: Clip = {
      ...sourceClip!,
      id: `audio-ext-${Math.random().toString(36).substr(2, 9)}`,
    };

    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => {
        if (t.id !== targetTrack.id) return t;
        const newClips = [...t.clips, audioClip].sort((a, b) => a.startTime - b.startTime);
        let cursor = 0;
        return {
          ...t,
          clips: newClips.map(c => {
            const start = cursor;
            cursor += c.duration;
            return { ...c, startTime: start };
          })
        };
      })
    }));
  }, [project.tracks, assets]);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => {
        if (t.isLocked && t.clips.some(c => c.id === clipId)) return t;
        const remaining = t.clips.filter(c => c.id !== clipId);
        let cursor = 0;
        return { 
          ...t, 
          clips: remaining.map(c => {
            const start = cursor;
            cursor += c.duration;
            return { ...c, startTime: start };
          })
        };
      })
    }));
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string, time: number) => {
    setProject(prev => {
      let newlyCreatedId: string | null = null;
      const newTracks = prev.tracks.map(track => {
        const clipIdx = track.clips.findIndex(c => c.id === clipId);
        if (clipIdx === -1 || track.isLocked) return track;

        const clip = track.clips[clipIdx];
        const relativeSplitPoint = time - clip.startTime;

        if (relativeSplitPoint <= 0.1 || relativeSplitPoint >= clip.duration - 0.1) return track;

        const leftClip: Clip = { ...clip, duration: relativeSplitPoint };
        const rightClipId = `clip-${Math.random().toString(36).substr(2, 9)}`;
        newlyCreatedId = rightClipId;
        const rightClip: Clip = {
          ...clip,
          id: rightClipId,
          startTime: time,
          offset: clip.offset + relativeSplitPoint,
          duration: clip.duration - relativeSplitPoint
        };

        const combined = [...track.clips.slice(0, clipIdx), leftClip, rightClip, ...track.clips.slice(clipIdx + 1)];
        let cursor = 0;
        return { 
          ...track, 
          clips: combined.map(c => {
            const start = cursor;
            cursor += c.duration;
            return { ...c, startTime: start };
          })
        };
      });

      if (newlyCreatedId) {
        setTimeout(() => setSelectedClipId(newlyCreatedId), 0);
      }
      return { ...prev, tracks: newTracks };
    });
  }, []);

  const moveClip = useCallback((clipId: string, targetTrackId: string, xPos: number) => {
    setProject(prev => {
      let activeClip: Clip | null = null;
      let sourceTrack: Track | null = null;

      for (const track of prev.tracks) {
        const found = track.clips.find(c => c.id === clipId);
        if (found) { 
          if (track.isLocked) return prev;
          activeClip = found; 
          sourceTrack = track;
          break; 
        }
      }
      if (!activeClip || !sourceTrack) return prev;

      const targetTrack = prev.tracks.find(t => t.id === targetTrackId);
      if (!targetTrack || targetTrack.isLocked) return prev;
      if (sourceTrack.type !== targetTrack.type) return prev;

      return {
        ...prev,
        tracks: prev.tracks.map(track => {
          if (track.id === sourceTrack!.id && track.id !== targetTrackId) {
            let cursor = 0;
            return {
              ...track,
              clips: track.clips.filter(c => c.id !== clipId).map(c => {
                const s = cursor; cursor += c.duration; return { ...c, startTime: s };
              })
            };
          }

          if (track.id === targetTrackId) {
            const others = track.clips.filter(c => c.id !== clipId).sort((a, b) => a.startTime - b.startTime);
            const movingCenter = xPos + activeClip!.duration / 2;

            let insertIdx = others.findIndex(c => (c.startTime + c.duration / 2) > movingCenter);
            if (insertIdx === -1) insertIdx = others.length;

            const newSequence = [...others];
            newSequence.splice(insertIdx, 0, activeClip!);

            let cursor = 0;
            return {
              ...track,
              clips: newSequence.map((c, idx) => {
                const start = cursor;
                cursor += c.duration;
                return { ...c, startTime: idx === insertIdx ? xPos : start };
              })
            };
          }
          return track;
        })
      };
    });
  }, []);

  const finalizeMove = useCallback(() => {
    setProject(prev => ({
      ...prev,
      tracks: prev.tracks.map(t => {
        let cursor = 0;
        const sorted = [...t.clips].sort((a, b) => a.startTime - b.startTime);
        return {
          ...t,
          clips: sorted.map(c => {
            const start = cursor;
            cursor += c.duration;
            return { ...c, startTime: start };
          })
        };
      })
    }));
  }, []);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    toggleTrackProperty,
    addTrack,
    addAsset,
    addClip,
    addClipAtPosition,
    detachAudio,
    deleteClip,
    splitClip,
    moveClip,
    finalizeMove,
    setProject
  };
};

import React, { useRef, useState, useEffect } from 'react';
import { Project, Clip, Track, Asset } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet, Eye, EyeOff, Volume2, VolumeX, Lock, Unlock, Plus, Video, Music } from 'lucide-react';

interface TimelineProps {
  project: Project;
  assets: Asset[];
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipFinalize: () => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  onToggleTrack: (trackId: string, prop: 'isVisible' | 'isMuted' | 'isLocked') => void;
  onAddClipAtPosition: (trackId: string, asset: Asset, startTime: number) => void;
  onAddTrack: (type: 'video' | 'audio') => void;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

const Waveform: React.FC = () => {
  return (
    <div className="absolute inset-0 flex items-center justify-around px-2 opacity-30 pointer-events-none">
      {Array.from({ length: 40 }).map((_, i) => (
        <div 
          key={i} 
          className="w-[2px] bg-indigo-400 rounded-full" 
          style={{ height: `${20 + Math.random() * 60}%` }}
        />
      ))}
    </div>
  );
};

export const Timeline: React.FC<TimelineProps> = ({ 
  project, assets, currentTime, zoom, setZoom, onTimeChange, onClipMove, onClipFinalize, onClipSplit, onClipDelete, onToggleTrack, onAddClipAtPosition, onAddTrack, selectedClipId, onSelectClip
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const tracksRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [dragging, setDragging] = useState<{ id: string, startX: number, startY: number, originalStart: number } | null>(null);

  const pxPerSec = zoom * 10;
  const HEADER_WIDTH = 150;
  const TRACK_HEIGHT = 72;

  const getT = (clientX: number) => {
    if (!scrollRef.current) return 0;
    const rect = scrollRef.current.getBoundingClientRect();
    return Math.max(0, (clientX - rect.left + scrollRef.current.scrollLeft - HEADER_WIDTH) / pxPerSec);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (isDraggingPlayhead) onTimeChange(getT(e.clientX));
      if (dragging) {
        const deltaX = (e.clientX - dragging.startX) / pxPerSec;
        if (tracksRef.current) {
          const tracksRect = tracksRef.current.getBoundingClientRect();
          const relativeY = e.clientY - tracksRect.top;
          const hoveredTrackIdx = Math.floor(relativeY / TRACK_HEIGHT);
          const hoveredTrack = project.tracks[hoveredTrackIdx];
          if (hoveredTrack && !hoveredTrack.isLocked) {
             onClipMove(dragging.id, hoveredTrack.id, dragging.originalStart + deltaX);
          }
        }
      }
    };
    const up = () => { 
      if (dragging) onClipFinalize();
      setIsDraggingPlayhead(false); 
      setDragging(null); 
    };
    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', up);
    return () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
  }, [isDraggingPlayhead, dragging, pxPerSec, project.tracks]);

  const handleDrop = (e: React.DragEvent, trackId: string) => {
    e.preventDefault();
    const assetId = e.dataTransfer.getData('assetId');
    const asset = assets.find(a => a.id === assetId);
    if (asset) {
      const dropTime = getT(e.clientX);
      onAddClipAtPosition(trackId, asset, dropTime);
    }
  };

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800">
      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between select-none">
        <div className="flex items-center gap-2">
          <button onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)} className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-all" title="Split Clip (S)"><Scissors size={14} /></button>
          <button onClick={() => selectedClipId && onClipDelete(selectedClipId)} className="p-1.5 hover:bg-zinc-800 rounded text-red-500/70 hover:text-red-500 transition-all" title="Delete Clip (Del)"><Trash2 size={14} /></button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <button onClick={() => onAddTrack('video')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Video size={12}/> Video Track</button>
          <button onClick={() => onAddTrack('audio')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Music size={12}/> Audio Track</button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <div className="flex items-center gap-2 px-2 py-1 bg-indigo-500/10 rounded text-[10px] text-indigo-400 font-bold border border-indigo-500/20">
            <Magnet size={12} /> MAGNETIC
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setZoom(Math.max(2, zoom - 2))}><ZoomOut size={14} className="text-zinc-500 hover:text-white" /></button>
          <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} /></div>
          <button onClick={() => setZoom(Math.min(50, zoom + 2))}><ZoomIn size={14} className="text-zinc-500 hover:text-white" /></button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto relative custom-scrollbar flex flex-col" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
        <div className="min-w-max relative flex-1">
          <div className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch select-none" onMouseDown={(e) => { e.preventDefault(); setIsDraggingPlayhead(true); onTimeChange(getT(e.clientX)); }}>
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {Math.floor(currentTime/60)}:{(Math.floor(currentTime%60)).toString().padStart(2,'0')}
            </div>
            <div className="flex-1 relative h-full" style={{ width: 5000 * pxPerSec }}>
              {Array.from({length: 100}).map((_, i) => i%5===0 && <div key={i} className="absolute top-0 h-full border-l border-zinc-800/50 pl-1 text-[9px] text-zinc-600 font-mono" style={{ left: i*pxPerSec }}>{i}s</div>)}
            </div>
          </div>

          <div className="flex flex-col" ref={tracksRef}>
            {project.tracks.map(track => (
              <div 
                key={track.id} 
                onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
                onDrop={(e) => handleDrop(e, track.id)}
                className={`flex h-[72px] border-b border-zinc-800 group/track relative ${track.isVisible ? '' : 'opacity-60'}`}
              >
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-2 flex flex-col justify-center gap-1 shadow-lg">
                  <div className="flex items-center gap-2">
                    {track.type === 'video' ? <Video size={10} className="text-zinc-500" /> : <Music size={10} className="text-zinc-500" />}
                    <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest truncate">{track.name}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isVisible')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isVisible ? 'text-zinc-400' : 'text-indigo-500'}`}
                    >
                      {track.isVisible ? <Eye size={12} /> : <EyeOff size={12} />}
                    </button>
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isMuted')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isMuted ? 'text-red-500' : 'text-zinc-400'}`}
                    >
                      {track.isMuted ? <VolumeX size={12} /> : <Volume2 size={12} />}
                    </button>
                    <button 
                      onClick={() => onToggleTrack(track.id, 'isLocked')} 
                      className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isLocked ? 'text-orange-500' : 'text-zinc-400'}`}
                    >
                      {track.isLocked ? <Lock size={12} /> : <Unlock size={12} />}
                    </button>
                  </div>
                </div>
                <div className="flex-1 relative bg-[#0a0a0a] min-w-[5000px]" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
                  {track.clips.map(clip => (
                    <div
                      key={clip.id}
                      onMouseDown={(e) => { 
                        if (track.isLocked) return;
                        e.stopPropagation(); 
                        onSelectClip(clip.id); 
                        setDragging({id: clip.id, startX: e.clientX, startY: e.clientY, originalStart: clip.startTime}); 
                      }}
                      className={`absolute top-2 bottom-2 rounded-lg border-2 flex flex-col justify-center px-3 overflow-hidden select-none transition-all duration-300 ease-in-out ${
                        track.isLocked ? 'cursor-not-allowed grayscale' : 'cursor-grab active:cursor-grabbing'
                      } ${
                        selectedClipId === clip.id 
                          ? 'bg-indigo-600/50 border-indigo-400 shadow-[0_0_30px_rgba(99,102,241,0.4)] z-20' 
                          : track.type === 'audio' ? 'bg-indigo-900/30 border-indigo-900/50 z-10' : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500 z-10'
                      }`}
                      style={{ 
                        left: clip.startTime * pxPerSec, 
                        width: clip.duration * pxPerSec,
                        transition: dragging && dragging.id === clip.id ? 'none' : undefined
                      }}
                    >
                      {track.type === 'audio' && <Waveform />}
                      <span className="text-[10px] font-bold text-white truncate uppercase drop-shadow-md z-10">{clip.id.split('-')[1]}</span>
                      <span className="text-[8px] text-zinc-400 font-mono font-bold tracking-tighter z-10">{clip.duration.toFixed(2)}s</span>
                      {track.isLocked && <Lock size={10} className="absolute top-1 right-1 text-orange-500/50" />}
                    </div>
                  ))}
                  {!track.isVisible && <div className="absolute inset-0 bg-black/20 pointer-events-none flex items-center justify-end pr-4 text-[8px] text-zinc-700 font-bold uppercase tracking-widest">Visuals Hidden</div>}
                </div>
              </div>
            ))}
          </div>

          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]" style={{ left: HEADER_WIDTH + (currentTime * pxPerSec) }}>
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Library } from './components/AssetLibrary/Library';
import { Timeline } from './components/Timeline/Timeline';
import { PreviewPlayer } from './components/Preview/PreviewPlayer';
import { useProjectStore } from './store/useProjectStore';
import { GeminiService } from './services/geminiService';
import { Settings, Download, Layers, Palette, Wand2, Type as TypeIcon, Scissors, Music } from 'lucide-react';
import { MediaType, Asset } from './types';

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (e.code === 'Space') {
        e.preventDefault();
        store.setIsPlaying(!store.isPlaying);
      }
      if ((e.code === 'KeyS' || e.code === 'KeyB') && store.selectedClipId) {
        store.splitClip(store.selectedClipId, store.currentTime);
      }
      if (e.code === 'Delete' || e.code === 'Backspace') {
        if (store.selectedClipId) store.deleteClip(store.selectedClipId);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [store.selectedClipId, store.currentTime, store.isPlaying]);

  // Playback timer
  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) await aistudio.openSelectKey();
      } catch (err) { console.warn(err); }
    }

    const userInput = window.prompt("Describe your cinematic scene:");
    if (!userInput) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${userInput.substring(0, 10)}...`,
        type: MediaType.VIDEO,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip('track-v1', newAsset, store.currentTime);
    } catch (error: any) {
      if (error?.message?.includes("Requested entity was not found.")) {
        const aistudio = (window as any).aistudio;
        if (aistudio) {
          await aistudio.openSelectKey();
        }
      }
      alert("AI Video generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetToTimeline = (asset: Asset) => {
