export default App;

export enum MediaType {
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO',
  IMAGE = 'IMAGE',
  TEXT = 'TEXT'
}

export interface Asset {
  id: string;
  name: string;
  type: MediaType;
  url: string;
  duration: number; // in seconds
  thumbnail?: string;
}

export interface Clip {
  id: string;
  assetId: string;
  startTime: number; // position on timeline in seconds
  offset: number; // start point within the asset in seconds
  duration: number; // length of the clip on timeline
  layer: number;
  effects: Effect[];
  isSilent?: boolean; // If true, this clip's source audio is disabled
  linkedClipId?: string; // ID of the linked audio or video clip
}

export interface Effect {
  id: string;
  type: 'filter' | 'transition' | 'adjustment';
  name: string;
  params: Record<string, any>;
}

export interface Project {
  id: string;
  name: string;
  resolution: { width: number; height: number };
  fps: number;
  tracks: Track[];
}

export interface Track {
  id: string;
  name: string;
  type: 'video' | 'audio';
  clips: Clip[];
  isVisible: boolean;
  isMuted: boolean;
  isLocked: boolean;
}

export interface ProjectState {
  currentProject: Project;
  assets: Asset[];
  selectedClipId: string | null;
  currentTime: number;
  isPlaying: boolean;
  zoom: number;
}

import { useState, useCallback, useRef } from 'react';
import { Project, Asset, Clip, Track, MediaType } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [], isVisible: true, isMuted: false, isLocked: false },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [], isVisible: true, isMuted: false, isLocked: false }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const historyRef = useRef<Project[]>([INITIAL_PROJECT]);
  const historyIndexRef = useRef<number>(0);

  const pushToHistory = (newProject: Project) => {
    const currentHistory = historyRef.current.slice(0, historyIndexRef.current + 1);
    const updatedHistory = [...currentHistory, JSON.parse(JSON.stringify(newProject))];
    if (updatedHistory.length > 50) updatedHistory.shift();
    historyRef.current = updatedHistory;
    historyIndexRef.current = updatedHistory.length - 1;
  };

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current -= 1;
      setProject(JSON.parse(JSON.stringify(historyRef.current[historyIndexRef.current])));
    }
  }, []);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current += 1;
      setProject(JSON.parse(JSON.stringify(historyRef.current[historyIndexRef.current])));
    }
  }, []);

  const toggleTrackProperty = useCallback((trackId: string, property: 'isVisible' | 'isMuted' | 'isLocked') => {
    setProject(prev => {
      const next = {
        ...prev,
        tracks: prev.tracks.map(t => t.id === trackId ? { ...t, [property]: !t[property] } : t)
      };
      pushToHistory(next);
      return next;
    });
  }, []);

  const addTrack = useCallback((type: 'video' | 'audio') => {
    setProject(prev => {
      const typeCount = prev.tracks.filter(t => t.type === type).length + 1;
      const newTrack: Track = {
        id: `track-${type[0]}-${Date.now()}`,
        name: `${type.charAt(0).toUpperCase() + type.slice(1)} ${typeCount}`,
        type,
        clips: [],
        isVisible: true,
        isMuted: false,
        isLocked: false
      };
      const videoTracks = type === 'video' ? [...prev.tracks.filter(t => t.type === 'video'), newTrack] : prev.tracks.filter(t => t.type === 'video');
      const audioTracks = type === 'audio' ? [...prev.tracks.filter(t => t.type === 'audio'), newTrack] : prev.tracks.filter(t => t.type === 'audio');
      const next = { ...prev, tracks: [...videoTracks, ...audioTracks] };
      pushToHistory(next);
      return next;
    });
  }, []);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const detachAudioInternal = (p: Project, clipId: string, asLink: boolean = true): Project => {
    let sourceClip: Clip | null = null;
    let sourceAsset: Asset | null = null;

    p.tracks.forEach(t => {
      const found = t.clips.find(c => c.id === clipId);
      if (found) {
        sourceClip = found;
        sourceAsset = assets.find(a => a.id === found!.assetId) || null;
      }
    });

    if (!sourceClip || !sourceAsset) return p;

    const targetTrack = p.tracks.find(t => t.type === 'audio' && !t.isLocked);
    if (!targetTrack) return p;

    const audioClipId = `audio-ext-${Math.random().toString(36).substr(2, 9)}`;
    const audioClip: Clip = {
      ...sourceClip!,
      id: audioClipId,
      linkedClipId: asLink ? sourceClip!.id : undefined,
    };

    return {
      ...p,
      tracks: p.tracks.map(t => {
        if (t.type === 'video') {
          return {
            ...t,
            clips: t.clips.map(c => c.id === clipId ? { 
              ...c, 
              isSilent: true, 
              linkedClipId: asLink ? audioClipId : undefined 
            } : c)
          };
        }
        if (t.id === targetTrack.id) {
          return { ...t, clips: [...t.clips, audioClip] };
        }
        return t;
      })
    };
  };

  const addClipAtPosition = useCallback((trackId: string, asset: Asset, startTime: number) => {
    setProject(prev => {
      const track = prev.tracks.find(t => t.id === trackId);
      if (!track || track.isLocked) return prev;

      const isAudioTrack = track.type === 'audio';
      const isAudioAsset = asset.type === MediaType.AUDIO;
      if (isAudioTrack !== isAudioAsset) return prev;

      const newClip: Clip = {
        id: `clip-${Math.random().toString(36).substr(2, 9)}`,
        assetId: asset.id,
        startTime: startTime,
        offset: 0,
        duration: asset.duration || 5,
        layer: 0,
        effects: [],
        isSilent: false
      };

      let next = {
        ...prev,
        tracks: prev.tracks.map(t => {
          if (t.id !== trackId) return t;
          return { ...t, clips: [...t.clips, newClip] };
        })
      };

      if (asset.type === MediaType.VIDEO) {
        next = detachAudioInternal(next, newClip.id, true);
      }

      pushToHistory(next);
      return next;
    });
  }, [assets]);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    addClipAtPosition(trackId, asset, startTime);
  }, [addClipAtPosition]);

  const detachAudio = useCallback((clipId: string) => {
    setProject(prev => {
      // Unlink clips when explicitly detaching via menu
      const next = prev.tracks.reduce((acc, track) => {
        return {
          ...acc,
          tracks: acc.tracks.map(t => ({
            ...t,
            clips: t.clips.map(c => {
              if (c.id === clipId || c.linkedClipId === clipId) {
                return { ...c, linkedClipId: undefined };
              }
              return c;
            })
          }))
        };
      }, detachAudioInternal(prev, clipId, false));

      pushToHistory(next);
      return next;
    });
  }, [assets]);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => {
      const next = {
        ...prev,
        tracks: prev.tracks.map(t => ({
          ...t,
          clips: t.clips.filter(c => c.id !== clipId && c.linkedClipId !== clipId)
        }))
      };
      pushToHistory(next);
      return next;
    });
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string, time: number) => {
    setProject(prev => {
      let newlyCreatedId: string | null = null;
      const newTracks = prev.tracks.map(track => {
        const clipIdx = track.clips.findIndex(c => c.id === clipId);
        if (clipIdx === -1 || track.isLocked) return track;

        const clip = track.clips[clipIdx];
        const relativeSplitPoint = time - clip.startTime;
        if (relativeSplitPoint <= 0.1 || relativeSplitPoint >= clip.duration - 0.1) return track;

        const leftClip: Clip = { ...clip, duration: relativeSplitPoint, linkedClipId: undefined };
        const rightClipId = `clip-${Math.random().toString(36).substr(2, 9)}`;
        newlyCreatedId = rightClipId;
        const rightClip: Clip = {
          ...clip,
          id: rightClipId,
          startTime: time,
          offset: clip.offset + relativeSplitPoint,
          duration: clip.duration - relativeSplitPoint,
          linkedClipId: undefined
        };

        return { ...track, clips: [...track.clips.slice(0, clipIdx), leftClip, rightClip, ...track.clips.slice(clipIdx + 1)] };
      });

      const next = { ...prev, tracks: newTracks };
      if (newlyCreatedId) {
        setTimeout(() => setSelectedClipId(newlyCreatedId), 0);
        pushToHistory(next);
      }
      return next;
    });
  }, []);

  const moveClip = useCallback((clipId: string, targetTrackId: string, xPos: number) => {
    setProject(prev => {
      let targetClip: Clip | null = null;
      for (const track of prev.tracks) {
        const found = track.clips.find(c => c.id === clipId);
        if (found) { targetClip = found; break; }
      }
      if (!targetClip) return prev;

      const deltaX = xPos - targetClip.startTime;

      return {
        ...prev,
        tracks: prev.tracks.map(track => {
          const isTargetTrack = track.id === targetTrackId;
          const hasMovingClip = track.clips.some(c => c.id === clipId || c.id === targetClip?.linkedClipId);

          if (!isTargetTrack && !hasMovingClip) return track;

          let newClips = track.clips.map(c => {
            if (c.id === clipId || c.id === targetClip?.linkedClipId) {
              return { ...c, startTime: c.startTime + deltaX };
            }
            return c;
          });

          // Handle track change for the primary dragged clip
          if (isTargetTrack && !track.clips.some(c => c.id === clipId)) {
            const clipFromOther = prev.tracks.flatMap(t => t.clips).find(c => c.id === clipId)!;
            newClips.push({ ...clipFromOther, startTime: xPos });
          } else if (!isTargetTrack && track.clips.some(c => c.id === clipId)) {
            newClips = newClips.filter(c => c.id !== clipId);
          }

          return { ...track, clips: newClips };
        })
      };
    });
  }, []);

  const finalizeMove = useCallback(() => {
    setProject(prev => {
      pushToHistory(prev);
      return prev;
    });
  }, []);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    toggleTrackProperty,
    addTrack,
    addAsset,
    addClip,
    addClipAtPosition,
    detachAudio,
    deleteClip,
    splitClip,
    moveClip,
    finalizeMove,
    undo,
    redo,
    canUndo: historyIndexRef.current > 0,
    canRedo: historyIndexRef.current < historyRef.current.length - 1,
    setProject
  };
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { Project, Clip, Track, Asset } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet, Eye, EyeOff, Volume2, VolumeX, Lock, Unlock, Plus, Video, Music, Undo, Redo, Link as LinkIcon } from 'lucide-react';

interface TimelineProps {
  project: Project;
  assets: Asset[];
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipFinalize: () => void;
  onClipSplit: (clipId: string, time: number) => void;
  onClipDelete: (clipId: string) => void;
  onToggleTrack: (trackId: string, prop: 'isVisible' | 'isMuted' | 'isLocked') => void;
  onAddClipAtPosition: (trackId: string, asset: Asset, startTime: number) => void;
  onAddTrack: (type: 'video' | 'audio') => void;
  onDetachAudio: (clipId: string) => void;
  onUndo: () => void;
  onRedo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

// Ultra-dense professional waveform
const StaticWaveform: React.FC<{ clipId: string }> = ({ clipId }) => {
  const bars = useMemo(() => {
    const seed = clipId.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    const count = 120;
    const result = [];
    for (let i = 0; i < count; i++) {
      // Create complex mountain-like shapes for realistic waveform
      const primary = Math.sin(seed + i * 0.2) * 30 + 35;
      const secondary = Math.cos(seed * 0.5 + i * 0.8) * 15;
      const tertiary = Math.random() * 10;
      const h = Math.max(5, primary + secondary + tertiary);
      result.push(h);
    }
    return result;
  }, [clipId]);

  return (
    <div className="absolute inset-0 flex items-center justify-around px-1 opacity-40 pointer-events-none gap-[1px]">
      {bars.map((h, i) => (
        <div 
          key={i} 
          className="flex-1 bg-indigo-400/80 rounded-sm" 
          style={{ height: `${h}%` }}
        />
      ))}
    </div>
  );
};

export const Timeline: React.FC<TimelineProps> = ({ 
  project, assets, currentTime, zoom, setZoom, onTimeChange, onClipMove, onClipFinalize, onClipSplit, onClipDelete, onToggleTrack, onAddClipAtPosition, onAddTrack, onDetachAudio, onUndo, onRedo, canUndo, canRedo, selectedClipId, onSelectClip
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const tracksRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [dragging, setDragging] = useState<{ id: string, startX: number, originalStart: number } | null>(null);
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, clipId: string, assetType: string } | null>(null);

  const pxPerSec = zoom * 10;
  const HEADER_WIDTH = 150;
  const TRACK_HEIGHT = 72;

  const getT = (clientX: number) => {
    if (!scrollRef.current) return 0;
    const rect = scrollRef.current.getBoundingClientRect();
    return Math.max(0, (clientX - rect.left + scrollRef.current.scrollLeft - HEADER_WIDTH) / pxPerSec);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (isDraggingPlayhead) onTimeChange(getT(e.clientX));
      if (dragging) {
        const deltaX = (e.clientX - dragging.startX) / pxPerSec;
        if (tracksRef.current) {
          const tracksRect = tracksRef.current.getBoundingClientRect();
          const relativeY = e.clientY - tracksRect.top;
          const hoveredTrackIdx = Math.floor(relativeY / TRACK_HEIGHT);
          const hoveredTrack = project.tracks[hoveredTrackIdx];
          if (hoveredTrack && !hoveredTrack.isLocked) {
             onClipMove(dragging.id, hoveredTrack.id, Math.max(0, dragging.originalStart + deltaX));
          }
        }
      }
    };
    const up = () => { 
      if (dragging) onClipFinalize();
      setIsDraggingPlayhead(false); 
      setDragging(null); 
    };
    const closeMenu = () => setContextMenu(null);

    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', up);
    window.addEventListener('mousedown', closeMenu);
    return () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('mouseup', up); 
      window.removeEventListener('mousedown', closeMenu);
    };
  }, [isDraggingPlayhead, dragging, pxPerSec, project.tracks]);

  const handleDrop = (e: React.DragEvent, trackId: string) => {
    e.preventDefault();
    const assetId = e.dataTransfer.getData('assetId');
    const asset = assets.find(a => a.id === assetId);
    if (asset) {
      const dropTime = getT(e.clientX);
      onAddClipAtPosition(trackId, asset, dropTime);
    }
  };

  const handleContextMenu = (e: React.MouseEvent, clipId: string, trackType: string) => {
    e.preventDefault();
    e.stopPropagation();
    onSelectClip(clipId);
    setContextMenu({ x: e.clientX, y: e.clientY, clipId, assetType: trackType });
  };

  const selectedClip = useMemo(() => project.tracks.flatMap(t => t.clips).find(c => c.id === selectedClipId), [project.tracks, selectedClipId]);

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800 relative">
      {contextMenu && (
        <div 
          className="fixed z-[100] w-48 bg-[#1a1a1a] border border-zinc-700 rounded-lg shadow-2xl py-1 overflow-hidden animate-in fade-in zoom-in duration-100"
          style={{ top: contextMenu.y, left: contextMenu.x }}
          onMouseDown={(e) => e.stopPropagation()}
        >
          <button onClick={() => { onClipSplit(contextMenu.clipId, currentTime); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-indigo-600 flex items-center gap-2 transition-colors font-bold">
            <Scissors size={12} /> Split at Playhead
          </button>
          {contextMenu.assetType === 'video' && (
            <button onClick={() => { onDetachAudio(contextMenu.clipId); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-indigo-600 flex items-center gap-2 transition-colors font-bold border-t border-zinc-800">
              <Music size={12} /> Detach Audio (Unlink)
            </button>
          )}
          <button onClick={() => { onClipDelete(contextMenu.clipId); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-red-600 text-red-400 hover:text-white flex items-center gap-2 transition-colors font-bold border-t border-zinc-800">
            <Trash2 size={12} /> Delete Clip
          </button>
        </div>
      )}

      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between select-none">
        <div className="flex items-center gap-2">
          <div className="flex items-center gap-1 mr-2">
            <button 
              disabled={!canUndo} 
              onClick={onUndo} 
              className={`p-1.5 rounded transition-all ${canUndo ? 'text-zinc-400 hover:bg-zinc-800 hover:text-white' : 'text-zinc-700 cursor-not-allowed'}`}
              title="Undo (Ctrl+Z)"
            >
              <Undo size={14} />
            </button>
            <button 
              disabled={!canRedo} 
              onClick={onRedo} 
              className={`p-1.5 rounded transition-all ${canRedo ? 'text-zinc-400 hover:bg-zinc-800 hover:text-white' : 'text-zinc-700 cursor-not-allowed'}`}
              title="Redo (Ctrl+Y)"
            >
              <Redo size={14} />
            </button>
          </div>
          <button onClick={() => selectedClipId && onClipSplit(selectedClipId, currentTime)} className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-all" title="Split Clip (S)"><Scissors size={14} /></button>
          <button onClick={() => selectedClipId && onClipDelete(selectedClipId)} className="p-1.5 hover:bg-zinc-800 rounded text-red-500/70 hover:text-red-500 transition-all" title="Delete Clip (Del)"><Trash2 size={14} /></button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <button onClick={() => onAddTrack('video')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Video size={12}/> Video Track</button>
          <button onClick={() => onAddTrack('audio')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Music size={12}/> Audio Track</button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <div className="flex items-center gap-2 px-2 py-1 bg-indigo-500/10 rounded text-[10px] text-indigo-400 font-bold border border-indigo-500/20">
            <Magnet size={12} /> MAGNETIC
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setZoom(Math.max(2, zoom - 2))}><ZoomOut size={14} className="text-zinc-500 hover:text-white" /></button>
          <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} /></div>
          <button onClick={() => setZoom(Math.min(50, zoom + 2))}><ZoomIn size={14} className="text-zinc-500 hover:text-white" /></button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto relative custom-scrollbar flex flex-col" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
        <div className="min-w-max relative flex-1">
          <div className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch select-none" onMouseDown={(e) => { e.preventDefault(); setIsDraggingPlayhead(true); onTimeChange(getT(e.clientX)); }}>
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {Math.floor(currentTime/60)}:{(Math.floor(currentTime%60)).toString().padStart(2,'0')}
            </div>
            <div className="flex-1 relative h-full" style={{ width: 5000 * pxPerSec }}>
              {Array.from({length: 100}).map((_, i) => i%5===0 && <div key={i} className="absolute top-0 h-full border-l border-zinc-800/50 pl-1 text-[9px] text-zinc-600 font-mono" style={{ left: i*pxPerSec }}>{i}s</div>)}
            </div>
          </div>

          <div className="flex flex-col" ref={tracksRef}>
            {project.tracks.map(track => (
              <div 
                key={track.id} 
                onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
                onDrop={(e) => handleDrop(e, track.id)}
                className={`flex h-[72px] border-b border-zinc-800 group/track relative ${track.isVisible ? '' : 'opacity-60'}`}
              >
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-2 flex flex-col justify-center gap-1 shadow-lg">
                  <div className="flex items-center gap-2">
                    {track.type === 'video' ? <Video size={10} className="text-zinc-500" /> : <Music size={10} className="text-zinc-500" />}
                    <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest truncate">{track.name}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <button onClick={() => onToggleTrack(track.id, 'isVisible')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isVisible ? 'text-zinc-400' : 'text-indigo-500'}`}>{track.isVisible ? <Eye size={12} /> : <EyeOff size={12} />}</button>
                    <button onClick={() => onToggleTrack(track.id, 'isMuted')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isMuted ? 'text-red-500' : 'text-zinc-400'}`}>{track.isMuted ? <VolumeX size={12} /> : <Volume2 size={12} />}</button>
                    <button onClick={() => onToggleTrack(track.id, 'isLocked')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isLocked ? 'text-orange-500' : 'text-zinc-400'}`}>{track.isLocked ? <Lock size={12} /> : <Unlock size={12} />}</button>
                  </div>
                </div>
                <div className="flex-1 relative bg-[#0a0a0a] min-w-[5000px]" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
                  {track.clips.map(clip => {
                    const isSelected = selectedClipId === clip.id;
                    const isLinkedToSelected = selectedClip?.linkedClipId === clip.id || clip.linkedClipId === selectedClipId;

                    return (
                      <div
                        key={clip.id}
                        onContextMenu={(e) => handleContextMenu(e, clip.id, track.type)}
                        onMouseDown={(e) => { 
                          if (track.isLocked || e.button === 2) return;
                          e.stopPropagation(); 
                          onSelectClip(clip.id); 
                          setDragging({id: clip.id, startX: e.clientX, originalStart: clip.startTime}); 
                        }}
                        className={`absolute top-2 bottom-2 rounded-lg border-2 flex flex-col justify-center px-3 overflow-hidden select-none transition-shadow duration-300 ${
                          track.isLocked ? 'cursor-not-allowed grayscale' : 'cursor-grab active:cursor-grabbing'
                        } ${
                          isSelected 
                            ? 'bg-indigo-600/50 border-indigo-400 shadow-[0_0_30px_rgba(99,102,241,0.5)] z-30 scale-[1.02]' 
                            : isLinkedToSelected
                              ? 'bg-indigo-900/40 border-indigo-500/50 z-20 border-dashed'
                              : track.type === 'audio' ? 'bg-indigo-900/20 border-indigo-900/40 z-10' : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500 z-10'
                        }`}
                        style={{ left: clip.startTime * pxPerSec, width: clip.duration * pxPerSec }}
                      >
                        {track.type === 'audio' && <StaticWaveform clipId={clip.id} />}
                        <div className="flex items-center gap-1 z-10">
                          {clip.linkedClipId && <LinkIcon size={8} className="text-indigo-400" />}
                          <span className="text-[10px] font-bold text-white truncate uppercase drop-shadow-md">{clip.id.split('-')[1]}</span>
                        </div>
                        <span className="text-[8px] text-zinc-400 font-mono font-bold tracking-tighter z-10">{clip.duration.toFixed(2)}s</span>
                        {clip.isSilent && track.type === 'video' && <Music size={10} className="absolute bottom-1 right-1 text-zinc-500 opacity-50" />}
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>

          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]" style={{ left: HEADER_WIDTH + (currentTime * pxPerSec) }}>
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

export enum MediaType {
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO',
  IMAGE = 'IMAGE',
  TEXT = 'TEXT'
}

export interface Asset {
  id: string;
  name: string;
  type: MediaType;
  url: string;
  duration: number; // in seconds
  thumbnail?: string;
  waveform?: number[]; // Normalized amplitude data (0 to 1)
}

export interface Clip {
  id: string;
  assetId: string;
  startTime: number; // position on timeline in seconds
  offset: number; // start point within the asset in seconds
  duration: number; // length of the clip on timeline
  layer: number;
  effects: Effect[];
  isSilent?: boolean; // If true, this clip's source audio is disabled
  linkedClipId?: string; // ID of the linked audio or video clip
}

export interface Effect {
  id: string;
  type: 'filter' | 'transition' | 'adjustment';
  name: string;
  params: Record<string, any>;
}

export interface Project {
  id: string;
  name: string;
  resolution: { width: number; height: number };
  fps: number;
  tracks: Track[];
}

export interface Track {
  id: string;
  name: string;
  type: 'video' | 'audio';
  clips: Clip[];
  isVisible: boolean;
  isMuted: boolean;
  isLocked: boolean;
}

export interface ProjectState {
  currentProject: Project;
  assets: Asset[];
  selectedClipId: string | null;
  currentTime: number;
  isPlaying: boolean;
  zoom: number;
}

import { Asset, MediaType } from '../types';

export class AssetService {
  static async processFile(file: File): Promise<Asset> {
    const url = URL.createObjectURL(file);
    const type = file.type.startsWith('video/') ? MediaType.VIDEO : 
                 file.type.startsWith('audio/') ? MediaType.AUDIO : 
                 MediaType.IMAGE;

    let duration = 0;
    let thumbnail = '';
    let waveform: number[] | undefined = undefined;

    try {
      if (type === MediaType.VIDEO || type === MediaType.AUDIO) {
        duration = await Promise.race([
          this.getMediaDuration(url),
          new Promise<number>((_, reject) => setTimeout(() => reject('Timeout'), 5000))
        ]).catch(() => (type === MediaType.VIDEO ? 10 : 0));

        if (type === MediaType.VIDEO) {
          thumbnail = await this.generateThumbnail(url).catch(() => '');
        }

        // Extract real waveform data
        waveform = await this.extractWaveform(url).catch(err => {
          console.warn("Waveform extraction failed", err);
          return undefined;
        });
      } else if (type === MediaType.IMAGE) {
        duration = 5;
        thumbnail = url;
      }
    } catch (e) {
      console.error("Asset processing failed", e);
    }

    return {
      id: `asset-${Math.random().toString(36).substr(2, 9)}`,
      name: file.name,
      type,
      url,
      duration: duration || 5,
      thumbnail,
      waveform
    };
  }

  private static async extractWaveform(url: string, samples = 150): Promise<number[]> {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);

    const channelData = audioBuffer.getChannelData(0);
    const blockSize = Math.floor(channelData.length / samples);
    const waveform: number[] = [];

    for (let i = 0; i < samples; i++) {
      let sum = 0;
      for (let j = 0; j < blockSize; j++) {
        sum += Math.abs(channelData[i * blockSize + j]);
      }
      // Normalize and push
      waveform.push(Math.min(1, (sum / blockSize) * 2.5)); 
    }

    await audioCtx.close();
    return waveform;
  }

  private static getMediaDuration(url: string): Promise<number> {
    return new Promise((resolve) => {
      const media = document.createElement('video');
      media.preload = 'metadata';
      media.src = url;
      media.onloadedmetadata = () => resolve(media.duration);
      media.onerror = () => resolve(0);
    });
  }

  private static generateThumbnail(url: string): Promise<string> {
    return new Promise((resolve) => {
      const video = document.createElement('video');
      video.preload = 'metadata';
      video.src = url;
      video.muted = true;
      video.currentTime = 0.5;
      video.onseeked = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 160;
        canvas.height = 90;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg'));
      };
      video.onerror = () => resolve('');
    });
  }
}

import { useState, useCallback, useRef } from 'react';
import { Project, Asset, Clip, Track, MediaType } from '../types';

const INITIAL_PROJECT: Project = {
  id: 'proj-1',
  name: 'New Project',
  resolution: { width: 1920, height: 1080 },
  fps: 30,
  tracks: [
    { id: 'track-v1', name: 'Video 1', type: 'video', clips: [], isVisible: true, isMuted: false, isLocked: false },
    { id: 'track-a1', name: 'Audio 1', type: 'audio', clips: [], isVisible: true, isMuted: false, isLocked: false }
  ]
};

export const useProjectStore = () => {
  const [project, setProject] = useState<Project>(INITIAL_PROJECT);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [zoom, setZoom] = useState(10);

  const historyRef = useRef<Project[]>([INITIAL_PROJECT]);
  const historyIndexRef = useRef<number>(0);

  const pushToHistory = (newProject: Project) => {
    const currentHistory = historyRef.current.slice(0, historyIndexRef.current + 1);
    const updatedHistory = [...currentHistory, JSON.parse(JSON.stringify(newProject))];
    if (updatedHistory.length > 50) updatedHistory.shift();
    historyRef.current = updatedHistory;
    historyIndexRef.current = updatedHistory.length - 1;
  };

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current -= 1;
      setProject(JSON.parse(JSON.stringify(historyRef.current[historyIndexRef.current])));
    }
  }, []);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current += 1;
      setProject(JSON.parse(JSON.stringify(historyRef.current[historyIndexRef.current])));
    }
  }, []);

  const toggleTrackProperty = useCallback((trackId: string, property: 'isVisible' | 'isMuted' | 'isLocked') => {
    setProject(prev => {
      const next = {
        ...prev,
        tracks: prev.tracks.map(t => t.id === trackId ? { ...t, [property]: !t[property] } : t)
      };
      pushToHistory(next);
      return next;
    });
  }, []);

  const addTrack = useCallback((type: 'video' | 'audio') => {
    setProject(prev => {
      const typeCount = prev.tracks.filter(t => t.type === type).length + 1;
      const newTrack: Track = {
        id: `track-${type[0]}-${Date.now()}`,
        name: `${type.charAt(0).toUpperCase() + type.slice(1)} ${typeCount}`,
        type,
        clips: [],
        isVisible: true,
        isMuted: false,
        isLocked: false
      };
      const videoTracks = type === 'video' ? [...prev.tracks.filter(t => t.type === 'video'), newTrack] : prev.tracks.filter(t => t.type === 'video');
      const audioTracks = type === 'audio' ? [...prev.tracks.filter(t => t.type === 'audio'), newTrack] : prev.tracks.filter(t => t.type === 'audio');
      const next = { ...prev, tracks: [...videoTracks, ...audioTracks] };
      pushToHistory(next);
      return next;
    });
  }, []);

  const addAsset = useCallback((asset: Asset) => {
    setAssets(prev => [...prev, asset]);
  }, []);

  const detachAudioInternal = (p: Project, clipId: string, asLink: boolean = true): Project => {
    let sourceClip: Clip | null = null;
    let sourceAsset: Asset | null = null;

    p.tracks.forEach(t => {
      const found = t.clips.find(c => c.id === clipId);
      if (found) {
        sourceClip = found;
        sourceAsset = assets.find(a => a.id === found!.assetId) || null;
      }
    });

    if (!sourceClip || !sourceAsset) return p;

    const targetTrack = p.tracks.find(t => t.type === 'audio' && !t.isLocked);
    if (!targetTrack) return p;

    const audioClipId = `audio-ext-${Math.random().toString(36).substr(2, 9)}`;
    const audioClip: Clip = {
      ...sourceClip!,
      id: audioClipId,
      linkedClipId: asLink ? sourceClip!.id : undefined,
    };

    return {
      ...p,
      tracks: p.tracks.map(t => {
        if (t.type === 'video') {
          return {
            ...t,
            clips: t.clips.map(c => c.id === clipId ? { 
              ...c, 
              isSilent: true, 
              linkedClipId: asLink ? audioClipId : undefined 
            } : c)
          };
        }
        if (t.id === targetTrack.id) {
          return { ...t, clips: [...t.clips, audioClip] };
        }
        return t;
      })
    };
  };

  const addClipAtPosition = useCallback((trackId: string, asset: Asset, startTime: number) => {
    setProject(prev => {
      const track = prev.tracks.find(t => t.id === trackId);
      if (!track || track.isLocked) return prev;

      const isAudioTrack = track.type === 'audio';
      const isAudioAsset = asset.type === MediaType.AUDIO;
      if (isAudioTrack !== isAudioAsset) return prev;

      const newClip: Clip = {
        id: `clip-${Math.random().toString(36).substr(2, 9)}`,
        assetId: asset.id,
        startTime: startTime,
        offset: 0,
        duration: asset.duration || 5,
        layer: 0,
        effects: [],
        isSilent: false
      };

      let next = {
        ...prev,
        tracks: prev.tracks.map(t => {
          if (t.id !== trackId) return t;
          return { ...t, clips: [...t.clips, newClip] };
        })
      };

      if (asset.type === MediaType.VIDEO) {
        next = detachAudioInternal(next, newClip.id, true);
      }

      pushToHistory(next);
      return next;
    });
  }, [assets]);

  const addClip = useCallback((trackId: string, asset: Asset, startTime: number) => {
    addClipAtPosition(trackId, asset, startTime);
  }, [addClipAtPosition]);

  const detachAudio = useCallback((clipId: string) => {
    setProject(prev => {
      const next = prev.tracks.reduce((acc, track) => {
        return {
          ...acc,
          tracks: acc.tracks.map(t => ({
            ...t,
            clips: t.clips.map(c => {
              if (c.id === clipId || c.linkedClipId === clipId) {
                return { ...c, linkedClipId: undefined };
              }
              return c;
            })
          }))
        };
      }, detachAudioInternal(prev, clipId, false));

      pushToHistory(next);
      return next;
    });
  }, [assets]);

  const deleteClip = useCallback((clipId: string) => {
    setProject(prev => {
      const next = {
        ...prev,
        tracks: prev.tracks.map(t => ({
          ...t,
          clips: t.clips.filter(c => c.id !== clipId && c.linkedClipId !== clipId)
        }))
      };
      pushToHistory(next);
      return next;
    });
    setSelectedClipId(null);
  }, []);

  const splitClip = useCallback((clipId: string | null, time: number) => {
    setProject(prev => {
      let newlyCreatedId: string | null = null;
      const newTracks = prev.tracks.map(track => {
        if (track.isLocked) return track;

        const newTrackClips: Clip[] = [];

        track.clips.forEach(clip => {
          // If a clip is selected, only split that one.
          // If no clip is selected, split all overlapping clips.
          const shouldSplit = clipId ? (clip.id === clipId) : (time > clip.startTime && time < clip.startTime + clip.duration);

          if (!shouldSplit) {
            newTrackClips.push(clip);
            return;
          }

          const relativeSplitPoint = time - clip.startTime;
          // Guard for tiny clips
          if (relativeSplitPoint <= 0.05 || relativeSplitPoint >= clip.duration - 0.05) {
            newTrackClips.push(clip);
            return;
          }

          const leftClip: Clip = { ...clip, duration: relativeSplitPoint, linkedClipId: undefined };
          const rightId = `clip-${Math.random().toString(36).substr(2, 9)}`;
          if (clipId === clip.id) newlyCreatedId = rightId;

          const rightClip: Clip = {
            ...clip,
            id: rightId,
            startTime: time,
            offset: clip.offset + relativeSplitPoint,
            duration: clip.duration - relativeSplitPoint,
            linkedClipId: undefined
          };

          newTrackClips.push(leftClip, rightClip);
        });

        return { ...track, clips: newTrackClips };
      });

      const next = { ...prev, tracks: newTracks };
      if (newlyCreatedId) {
        setTimeout(() => setSelectedClipId(newlyCreatedId), 0);
      }
      pushToHistory(next);
      return next;
    });
  }, []);

  const moveClip = useCallback((clipId: string, targetTrackId: string, xPos: number) => {
    setProject(prev => {
      let targetClip: Clip | null = null;
      for (const track of prev.tracks) {
        const found = track.clips.find(c => c.id === clipId);
        if (found) { targetClip = found; break; }
      }
      if (!targetClip) return prev;

      const deltaX = xPos - targetClip.startTime;

      return {
        ...prev,
        tracks: prev.tracks.map(track => {
          const isTargetTrack = track.id === targetTrackId;
          const hasMovingClip = track.clips.some(c => c.id === clipId || c.id === targetClip?.linkedClipId);

          if (!isTargetTrack && !hasMovingClip) return track;

          let newClips = track.clips.map(c => {
            if (c.id === clipId || c.id === targetClip?.linkedClipId) {
              return { ...c, startTime: c.startTime + deltaX };
            }
            return c;
          });

          // Handle track change for the primary dragged clip
          if (isTargetTrack && !track.clips.some(c => c.id === clipId)) {
            const allClips = prev.tracks.flatMap(t => t.clips);
            const clipFromOther = allClips.find(c => c.id === clipId);
            if (clipFromOther) {
               newClips.push({ ...clipFromOther, startTime: xPos });
            }
          } else if (!isTargetTrack && track.clips.some(c => c.id === clipId)) {
            newClips = newClips.filter(c => c.id !== clipId);
          }

          return { ...track, clips: newClips };
        })
      };
    });
  }, []);

  const finalizeMove = useCallback(() => {
    setProject(prev => {
      pushToHistory(prev);
      return prev;
    });
  }, []);

  return {
    project,
    assets,
    currentTime,
    isPlaying,
    selectedClipId,
    zoom,
    setZoom,
    setCurrentTime,
    setIsPlaying,
    setSelectedClipId,
    toggleTrackProperty,
    addTrack,
    addAsset,
    addClip,
    addClipAtPosition,
    detachAudio,
    deleteClip,
    splitClip,
    moveClip,
    finalizeMove,
    undo,
    redo,
    canUndo: historyIndexRef.current > 0,
    canRedo: historyIndexRef.current < historyRef.current.length - 1,
    setProject
  };
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { Project, Clip, Track, Asset } from '../../types';
import { Scissors, Trash2, ZoomIn, ZoomOut, Magnet, Eye, EyeOff, Volume2, VolumeX, Lock, Unlock, Plus, Video, Music, Undo, Redo, Link as LinkIcon } from 'lucide-react';

interface TimelineProps {
  project: Project;
  assets: Asset[];
  currentTime: number;
  zoom: number;
  setZoom: (z: number) => void;
  onTimeChange: (time: number) => void;
  onClipMove: (clipId: string, trackId: string, time: number) => void;
  onClipFinalize: () => void;
  onClipSplit: (clipId: string | null, time: number) => void;
  onClipDelete: (clipId: string) => void;
  onToggleTrack: (trackId: string, prop: 'isVisible' | 'isMuted' | 'isLocked') => void;
  onAddClipAtPosition: (trackId: string, asset: Asset, startTime: number) => void;
  onAddTrack: (type: 'video' | 'audio') => void;
  onDetachAudio: (clipId: string) => void;
  onUndo: () => void;
  onRedo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  selectedClipId: string | null;
  onSelectClip: (id: string | null) => void;
}

// Accurate professional waveform based on real audio data
const StaticWaveform: React.FC<{ asset: Asset | undefined, clip: Clip }> = ({ asset, clip }) => {
  const bars = useMemo(() => {
    if (!asset || !asset.waveform) {
      // Fallback stable pseudo-random waveform if data is missing
      const seed = clip.id.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
      return Array.from({ length: 150 }, (_, i) => Math.max(5, Math.sin(seed + i * 0.2) * 30 + 40));
    }

    // Calculate visible portion of the asset's waveform
    const sampleCount = asset.waveform.length;
    const startIdx = Math.floor((clip.offset / asset.duration) * sampleCount);
    const endIdx = Math.floor(((clip.offset + clip.duration) / asset.duration) * sampleCount);

    return asset.waveform.slice(startIdx, endIdx).map(v => v * 85 + 5);
  }, [asset, clip.id, clip.offset, clip.duration]);

  return (
    <div className="absolute inset-0 flex items-center justify-around px-0.5 opacity-60 pointer-events-none gap-[1px]">
      {bars.map((h, i) => (
        <div 
          key={i} 
          className="flex-1 bg-indigo-400 rounded-sm min-h-[1px]" 
          style={{ height: `${h}%` }}
        />
      ))}
    </div>
  );
};

export const Timeline: React.FC<TimelineProps> = ({ 
  project, assets, currentTime, zoom, setZoom, onTimeChange, onClipMove, onClipFinalize, onClipSplit, onClipDelete, onToggleTrack, onAddClipAtPosition, onAddTrack, onDetachAudio, onUndo, onRedo, canUndo, canRedo, selectedClipId, onSelectClip
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const tracksRef = useRef<HTMLDivElement>(null);
  const [isDraggingPlayhead, setIsDraggingPlayhead] = useState(false);
  const [dragging, setDragging] = useState<{ id: string, startX: number, originalStart: number } | null>(null);
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, clipId: string, assetType: string } | null>(null);

  const pxPerSec = zoom * 10;
  const HEADER_WIDTH = 150;
  const TRACK_HEIGHT = 72;

  const getT = (clientX: number) => {
    if (!scrollRef.current) return 0;
    const rect = scrollRef.current.getBoundingClientRect();
    return Math.max(0, (clientX - rect.left + scrollRef.current.scrollLeft - HEADER_WIDTH) / pxPerSec);
  };

  useEffect(() => {
    const move = (e: MouseEvent) => {
      if (isDraggingPlayhead) onTimeChange(getT(e.clientX));
      if (dragging) {
        const deltaX = (e.clientX - dragging.startX) / pxPerSec;
        if (tracksRef.current) {
          const tracksRect = tracksRef.current.getBoundingClientRect();
          const relativeY = e.clientY - tracksRect.top;
          const hoveredTrackIdx = Math.floor(relativeY / TRACK_HEIGHT);
          const hoveredTrack = project.tracks[hoveredTrackIdx];
          if (hoveredTrack && !hoveredTrack.isLocked) {
             onClipMove(dragging.id, hoveredTrack.id, Math.max(0, dragging.originalStart + deltaX));
          }
        }
      }
    };
    const up = () => { 
      if (dragging) onClipFinalize();
      setIsDraggingPlayhead(false); 
      setDragging(null); 
    };
    const closeMenu = () => setContextMenu(null);

    window.addEventListener('mousemove', move);
    window.addEventListener('mouseup', up);
    window.addEventListener('mousedown', closeMenu);
    return () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('mouseup', up); 
      window.removeEventListener('mousedown', closeMenu);
    };
  }, [isDraggingPlayhead, dragging, pxPerSec, project.tracks]);

  const handleDrop = (e: React.DragEvent, trackId: string) => {
    e.preventDefault();
    const assetId = e.dataTransfer.getData('assetId');
    const asset = assets.find(a => a.id === assetId);
    if (asset) {
      const dropTime = getT(e.clientX);
      onAddClipAtPosition(trackId, asset, dropTime);
    }
  };

  const handleContextMenu = (e: React.MouseEvent, clipId: string, trackType: string) => {
    e.preventDefault();
    e.stopPropagation();
    onSelectClip(clipId);
    setContextMenu({ x: e.clientX, y: e.clientY, clipId, assetType: trackType });
  };

  const selectedClip = useMemo(() => project.tracks.flatMap(t => t.clips).find(c => c.id === selectedClipId), [project.tracks, selectedClipId]);

  return (
    <div className="flex-1 bg-[#0f0f0f] flex flex-col overflow-hidden border-t border-zinc-800 relative">
      {contextMenu && (
        <div 
          className="fixed z-[100] w-48 bg-[#1a1a1a] border border-zinc-700 rounded-lg shadow-2xl py-1 overflow-hidden animate-in fade-in zoom-in duration-100"
          style={{ top: contextMenu.y, left: contextMenu.x }}
          onMouseDown={(e) => e.stopPropagation()}
        >
          <button onClick={() => { onClipSplit(contextMenu.clipId, currentTime); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-indigo-600 flex items-center gap-2 transition-colors font-bold">
            <Scissors size={12} /> Split Selected Clip
          </button>
          {contextMenu.assetType === 'video' && (
            <button onClick={() => { onDetachAudio(contextMenu.clipId); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-indigo-600 flex items-center gap-2 transition-colors font-bold border-t border-zinc-800">
              <Music size={12} /> Detach Audio (Unlink)
            </button>
          )}
          <button onClick={() => { onClipDelete(contextMenu.clipId); setContextMenu(null); }} className="w-full px-4 py-2 text-left text-[11px] hover:bg-red-600 text-red-400 hover:text-white flex items-center gap-2 transition-colors font-bold border-t border-zinc-800">
            <Trash2 size={12} /> Delete Clip
          </button>
        </div>
      )}

      <div className="h-10 bg-[#161616] border-b border-zinc-800 flex items-center px-4 justify-between select-none">
        <div className="flex items-center gap-2">
          <div className="flex items-center gap-1 mr-2">
            <button 
              disabled={!canUndo} 
              onClick={onUndo} 
              className={`p-1.5 rounded transition-all ${canUndo ? 'text-zinc-400 hover:bg-zinc-800 hover:text-white' : 'text-zinc-700 cursor-not-allowed'}`}
              title="Undo (Ctrl+Z)"
            >
              <Undo size={14} />
            </button>
            <button 
              disabled={!canRedo} 
              onClick={onRedo} 
              className={`p-1.5 rounded transition-all ${canRedo ? 'text-zinc-400 hover:bg-zinc-800 hover:text-white' : 'text-zinc-700 cursor-not-allowed'}`}
              title="Redo (Ctrl+Y)"
            >
              <Redo size={14} />
            </button>
          </div>
          <button onClick={() => onClipSplit(selectedClipId, currentTime)} className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-all" title={selectedClipId ? "Split Clip (S/B)" : "Split All Tracks (S/B)"}>
            <Scissors size={14} />
          </button>
          <button onClick={() => selectedClipId && onClipDelete(selectedClipId)} className="p-1.5 hover:bg-zinc-800 rounded text-red-500/70 hover:text-red-500 transition-all" title="Delete Clip (Del)"><Trash2 size={14} /></button>
          <div className="w-px h-4 bg-zinc-800 mx-2" />
          <button onClick={() => onAddTrack('video')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Video size={12}/> Video Track</button>
          <button onClick={() => onAddTrack('audio')} className="flex items-center gap-1.5 px-2 py-1 hover:bg-zinc-800 rounded text-[10px] text-zinc-400 font-bold transition-all"><Plus size={12}/> <Music size={12}/> Audio Track</button>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setZoom(Math.max(2, zoom - 2))}><ZoomOut size={14} className="text-zinc-500 hover:text-white" /></button>
          <div className="w-24 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-500" style={{ width: `${(zoom/50)*100}%` }} /></div>
          <button onClick={() => setZoom(Math.min(50, zoom + 2))}><ZoomIn size={14} className="text-zinc-500 hover:text-white" /></button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto relative custom-scrollbar flex flex-col" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
        <div className="min-w-max relative flex-1">
          <div className="sticky top-0 h-8 bg-[#161616] border-b border-zinc-800 z-30 flex items-stretch select-none" onMouseDown={(e) => { e.preventDefault(); setIsDraggingPlayhead(true); onTimeChange(getT(e.clientX)); }}>
            <div className="w-[150px] sticky left-0 bg-[#161616] z-40 border-r border-zinc-800 flex items-center px-4 font-mono text-[11px] text-indigo-400 font-bold">
              {Math.floor(currentTime/60)}:{(Math.floor(currentTime%60)).toString().padStart(2,'0')}
            </div>
            <div className="flex-1 relative h-full" style={{ width: 5000 * pxPerSec }}>
              {Array.from({length: 100}).map((_, i) => i%5===0 && <div key={i} className="absolute top-0 h-full border-l border-zinc-800/50 pl-1 text-[9px] text-zinc-600 font-mono" style={{ left: i*pxPerSec }}>{i}s</div>)}
            </div>
          </div>

          <div className="flex flex-col" ref={tracksRef}>
            {project.tracks.map(track => (
              <div 
                key={track.id} 
                onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
                onDrop={(e) => handleDrop(e, track.id)}
                className={`flex h-[72px] border-b border-zinc-800 group/track relative ${track.isVisible ? '' : 'opacity-60'}`}
              >
                <div className="w-[150px] sticky left-0 bg-[#121212] z-20 border-r border-zinc-800 p-2 flex flex-col justify-center gap-1 shadow-lg">
                  <div className="flex items-center gap-2">
                    {track.type === 'video' ? <Video size={10} className="text-zinc-500" /> : <Music size={10} className="text-zinc-500" />}
                    <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest truncate">{track.name}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <button onClick={() => onToggleTrack(track.id, 'isVisible')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isVisible ? 'text-zinc-400' : 'text-indigo-500'}`}>{track.isVisible ? <Eye size={12} /> : <EyeOff size={12} />}</button>
                    <button onClick={() => onToggleTrack(track.id, 'isMuted')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isMuted ? 'text-red-500' : 'text-zinc-400'}`}>{track.isMuted ? <VolumeX size={12} /> : <Volume2 size={12} />}</button>
                    <button onClick={() => onToggleTrack(track.id, 'isLocked')} className={`p-1 rounded hover:bg-zinc-800 transition-colors ${track.isLocked ? 'text-orange-500' : 'text-zinc-400'}`}>{track.isLocked ? <Lock size={12} /> : <Unlock size={12} />}</button>
                  </div>
                </div>
                <div className="flex-1 relative bg-[#0a0a0a] min-w-[5000px]" onMouseDown={(e) => e.target === e.currentTarget && onSelectClip(null)}>
                  {track.clips.map(clip => {
                    const isSelected = selectedClipId === clip.id;
                    const isLinkedToSelected = selectedClip?.linkedClipId === clip.id || clip.linkedClipId === selectedClipId;
                    const asset = assets.find(a => a.id === clip.assetId);

                    return (
                      <div
                        key={clip.id}
                        onContextMenu={(e) => handleContextMenu(e, clip.id, track.type)}
                        onMouseDown={(e) => { 
                          if (track.isLocked || e.button === 2) return;
                          e.stopPropagation(); 
                          onSelectClip(clip.id); 
                          setDragging({id: clip.id, startX: e.clientX, originalStart: clip.startTime}); 
                        }}
                        className={`absolute top-2 bottom-2 rounded-lg border-2 flex flex-col justify-center px-3 overflow-hidden select-none transition-shadow duration-300 ${
                          track.isLocked ? 'cursor-not-allowed grayscale' : 'cursor-grab active:cursor-grabbing'
                        } ${
                          isSelected 
                            ? 'bg-indigo-600/50 border-indigo-400 shadow-[0_0_30px_rgba(99,102,241,0.5)] z-30 scale-[1.02]' 
                            : isLinkedToSelected
                              ? 'bg-indigo-900/40 border-indigo-500/50 z-20 border-dashed'
                              : track.type === 'audio' ? 'bg-indigo-900/20 border-indigo-900/40 z-10' : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500 z-10'
                        }`}
                        style={{ left: clip.startTime * pxPerSec, width: clip.duration * pxPerSec }}
                      >
                        {track.type === 'audio' && <StaticWaveform asset={asset} clip={clip} />}
                        <div className="flex items-center gap-1 z-10">
                          {clip.linkedClipId && <LinkIcon size={8} className="text-indigo-400" />}
                          <span className="text-[10px] font-bold text-white truncate uppercase drop-shadow-md">{clip.id.split('-')[1]}</span>
                        </div>
                        <span className="text-[8px] text-zinc-400 font-mono font-bold tracking-tighter z-10">{clip.duration.toFixed(2)}s</span>
                        {clip.isSilent && track.type === 'video' && <Music size={10} className="absolute bottom-1 right-1 text-zinc-500 opacity-50" />}
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>

          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]" style={{ left: HEADER_WIDTH + (currentTime * pxPerSec) }}>
            <div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Library } from './components/AssetLibrary/Library';
import { Timeline } from './components/Timeline/Timeline';
import { PreviewPlayer } from './components/Preview/PreviewPlayer';
import { useProjectStore } from './store/useProjectStore';
import { GeminiService } from './services/geminiService';
import { Settings, Download, Layers, Palette, Wand2, Type as TypeIcon, Scissors, Music } from 'lucide-react';
import { MediaType, Asset } from './types';

const App: React.FC = () => {
  const store = useProjectStore();
  const [isGenerating, setIsGenerating] = useState(false);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      // Play/Pause
      if (e.code === 'Space') {
        e.preventDefault();
        store.setIsPlaying(!store.isPlaying);
      }

      // Undo/Redo
      if ((e.ctrlKey || e.metaKey) && e.code === 'KeyZ') {
        if (e.shiftKey) store.redo();
        else store.undo();
      }
      if ((e.ctrlKey || e.metaKey) && e.code === 'KeyY') {
        store.redo();
      }

      // Split - If clip selected: split only that. Else: split all layers at playhead.
      if (e.code === 'KeyS' || e.code === 'KeyB') {
        store.splitClip(store.selectedClipId, store.currentTime);
      }

      // Delete
      if (e.code === 'Delete' || e.code === 'Backspace') {
        if (store.selectedClipId) store.deleteClip(store.selectedClipId);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [store.selectedClipId, store.currentTime, store.isPlaying, store.undo, store.redo]);

  // Playback timer
  useEffect(() => {
    let interval: number;
    if (store.isPlaying) {
      interval = window.setInterval(() => {
        store.setCurrentTime(prev => prev + 1/30);
      }, 1000/30);
    }
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) await aistudio.openSelectKey();
      } catch (err) { console.warn(err); }
    }

    const userInput = window.prompt("Describe your cinematic scene:");
    if (!userInput) return;

    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = {
        id: `ai-${Date.now()}`,
        name: `AI: ${userInput.substring(0, 10)}...`,
        type: MediaType.VIDEO,
        url: videoUrl,
        duration: 5,
        thumbnail: 'https://picsum.photos/320/180'
      };
      store.addAsset(newAsset);
      store.addClip('track-v1', newAsset, store.currentTime);
    } catch (error: any) {
      if (error?.message?.includes("Requested entity was not found.")) {
        const aistudio = (window as any).aistudio;
        if (aistudio) {
          await aistudio.openSelectKey();
        }
      }
      alert("AI Video generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    const targetTrackId = asset.type === MediaType.AUDIO ? 
      (store.project.tracks.find(t => t.type === 'audio')?.id || 'track-a1') : 
      (store.project.tracks.find(t => t.type === 'video')?.id || 'track-v1');
    store.addClip(targetTrackId, asset, store.currentTime);
  };

  const selectedClip = store.project.tracks.flatMap(t => t.clips).find(c => c.id === store.selectedClipId);
  const selectedAsset = selectedClip ? store.assets.find(a => a.id === selectedClip.assetId) : null;

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200 select-none">
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer">
            <div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[11px] font-black">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">
            {['File', 'Edit', 'Sequence', 'Export'].map(item => (
              <button key={item} className="px-3 py-1 hover:text-white transition-colors">{item}</button>
            ))}
          </nav>
        </div>
        <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-bold px-5 py-1.5 rounded-full transition-all active:scale-95">
          <Download size={14} /> Render
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10"><Layers size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Palette size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><TypeIcon size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors" onClick={() => store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
        </aside>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library 
              assets={store.assets} 
              onAddAsset={store.addAsset} 
              onGenerateAI={handleAICompose}
              onDragAssetToTimeline={handleAssetToTimeline}
            />
            <PreviewPlayer 
              project={store.project}
              assets={store.assets}
