          <div className="absolute top-0 bottom-0 w-px bg-red-500 z-50 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]" style={{ left: HEADER_WIDTH + (currentTime * pxPerSec) }}><div className="absolute top-0 -left-1.5 w-3 h-3 bg-red-500 rounded-sm rotate-45" /></div>
