  const shortcutStore = useShortcutStore();
  const [isGenerating, setIsGenerating] = useState(false);
  const [isShortcutModalOpen, setIsShortcutModalOpen] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      const action = shortcutStore.getAction(e);
      if (!action) return;

      e.preventDefault();

      switch (action) {
        case 'play_pause':
          store.setIsPlaying(!store.isPlaying);
          break;
        case 'split':
          store.splitClip(store.selectedClipId, store.currentTime);
          break;
        case 'delete':
          if (store.selectedClipId) store.deleteClip(store.selectedClipId);
          break;
        case 'undo':
          store.undo();
          break;
        case 'redo':
          store.redo();
          break;
        case 'zoom_in':
          store.setZoom(Math.min(100, store.zoom + 5));
          break;
        case 'zoom_out':
          store.setZoom(Math.max(1, store.zoom - 5));
          break;
        case 'toggle_magnet':
          store.setIsMagnetEnabled(!store.isMagnetEnabled);
          break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [store, shortcutStore]);

  useEffect(() => {
    let interval: number;
    if (store.isPlaying) interval = window.setInterval(() => store.setCurrentTime(prev => prev + 1 / 30), 1000 / 30);
    return () => clearInterval(interval);
  }, [store.isPlaying]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try { const hasKey = await aistudio.hasSelectedApiKey(); if (!hasKey) await aistudio.openSelectKey(); } catch (err) { console.warn(err); }
    }
    const userInput = window.prompt("Describe your cinematic scene:");
    if (!userInput) return;
    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = { id: `ai-${Date.now()}`, name: `AI: ${userInput.substring(0, 10)}...`, type: MediaType.VIDEO, url: videoUrl, duration: 5, thumbnail: 'https://picsum.photos/320/180' };
      store.addAsset(newAsset);
      store.addClipAtPosition('track-v1', newAsset, store.currentTime);
    } catch (error: any) {
      if (error?.message?.includes("Requested entity was not found.")) (window as any).aistudio?.openSelectKey();
      alert("AI Video generation failed.");
    } finally { setIsGenerating(false); }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    const targetTrackId = asset.type === MediaType.AUDIO ? (store.project.tracks.find(t => t.type === 'audio')?.id || 'track-a1') : (store.project.tracks.find(t => t.type === 'video')?.id || 'track-v1');
    store.addClipAtPosition(targetTrackId, asset, store.currentTime);
  };

  const selectedClip = store.project.tracks.flatMap(t => t.clips).find(c => c.id === store.selectedClipId);
  const selectedAsset = selectedClip ? store.assets.find(a => a.id === selectedClip.assetId) : null;

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200 select-none">
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer"><div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[11px] font-black">NX</div><h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1></div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">{['File', 'Edit', 'Sequence', 'Project'].map(item => (<button key={item} className="px-3 py-1 hover:text-white transition-colors">{item}</button>))}</nav>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => setIsShortcutModalOpen(true)}
            className="p-1.5 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white transition-all mr-2"
            title="Keyboard Shortcuts"
          >
            <Keyboard size={18} />
          </button>
          <button 
            onClick={() => setIsExportModalOpen(true)}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-bold px-5 py-1.5 rounded-full transition-all active:scale-95 shadow-lg shadow-indigo-600/20"
          >
            <Download size={14} /> Render
          </button>
        </div>
      </header>
      <main className="flex-1 flex overflow-hidden">
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10"><Layers size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><Palette size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors"><TypeIcon size={22} /></button>
          <button className="text-zinc-600 hover:text-zinc-300 transition-colors" onClick={() => store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
        </aside>
        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library assets={store.assets} onAddAsset={store.addAsset} onGenerateAI={handleAICompose} onDragAssetToTimeline={handleAssetToTimeline} />
            <PreviewPlayer project={store.project} assets={store.assets} isPlaying={store.isPlaying} onTogglePlay={() => store.setIsPlaying(!store.isPlaying)} currentTime={store.currentTime} />
            <div className="w-[300px] bg-[#121212] border-l border-zinc-800/50 p-6 overflow-y-auto">
              <h2 className="text-[10px] font-bold uppercase tracking-widest text-zinc-600 mb-8 flex items-center gap-2"><Settings size={12}/> Properties</h2>
              {selectedClip ? (<div className="space-y-6"><div className="p-3 bg-zinc-900/50 rounded-xl border border-zinc-800"><span className="text-[9px] text-zinc-500 block mb-2 font-black uppercase">Clip Info</span><p className="text-[10px] font-mono text-indigo-400 truncate mb-1">{selectedClip.id}</p><p className="text-[9px] text-zinc-500 truncate">{selectedAsset?.name}</p></div><div className="space-y-4"><label className="text-[10px] text-zinc-500 uppercase font-black">Actions</label>{selectedAsset?.type === MediaType.VIDEO && (<button onClick={() => store.detachAudio(selectedClip.id)} className="w-full py-2 bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-400 text-[10px] font-bold rounded-lg transition-colors border border-indigo-500/20 flex items-center justify-center gap-2"><Music size={12}/> Detach Audio</button>)}<button onClick={() => store.deleteClip(selectedClip.id)} className="w-full py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 text-[10px] font-bold rounded-lg transition-colors border border-red-500/20">Delete Clip</button></div></div>) : (<p className="text-[11px] text-zinc-600 text-center mt-20 italic">Select a clip to edit</p>)}
            </div>
          </div>
          <Timeline 
            project={store.project} assets={store.assets} currentTime={store.currentTime} zoom={store.zoom} isMagnetEnabled={store.isMagnetEnabled}
            setZoom={store.setZoom} setIsMagnetEnabled={store.setIsMagnetEnabled} onTimeChange={store.setCurrentTime}
            onClipMove={store.moveClip} onClipFinalize={store.finalizeMove} onClipSplit={store.splitClip} onClipDelete={store.deleteClip}
            onToggleTrack={store.toggleTrackProperty} onSetTrackHeight={store.setTrackHeight} onAddClipAtPosition={store.addClipAtPosition} onAddTrack={store.addTrack}
            onDetachAudio={store.detachAudio} onUndo={store.undo} onRedo={store.redo} canUndo={store.canUndo} canRedo={store.canRedo}
            selectedClipId={store.selectedClipId} onSelectClip={store.setSelectedClipId}
          />
        </div>
      </main>

      {isShortcutModalOpen && (
        <ShortcutModal 
