    </div>
  );
};

export default App;

import { useState } from 'react';

export type ShortcutAction = 'play_pause' | 'split' | 'delete' | 'undo' | 'redo' | 'zoom_in' | 'zoom_out' | 'toggle_magnet';

export interface ShortcutMapping {
  action: ShortcutAction;
  key: string;
  label: string;
  ctrl?: boolean;
  shift?: boolean;
}

const DEFAULT_SHORTCUTS: ShortcutMapping[] = [
  { action: 'play_pause', key: 'Space', label: 'Play / Pause' },
  { action: 'split', key: 'KeyS', label: 'Split Clip' },
  { action: 'split', key: 'KeyB', label: 'Split Clip (Alternative)' },
  { action: 'delete', key: 'Delete', label: 'Delete Selected' },
  { action: 'delete', key: 'Backspace', label: 'Delete Selected (Alt)' },
  { action: 'undo', key: 'KeyZ', label: 'Undo', ctrl: true },
  { action: 'redo', key: 'KeyZ', label: 'Redo', ctrl: true, shift: true },
  { action: 'zoom_in', key: 'Equal', label: 'Zoom In', ctrl: true },
  { action: 'zoom_out', key: 'Minus', label: 'Zoom Out', ctrl: true },
  { action: 'toggle_magnet', key: 'KeyM', label: 'Toggle Magnetism' },
];

export const useShortcutStore = () => {
  const [shortcuts, setShortcuts] = useState<ShortcutMapping[]>(() => {
    const saved = localStorage.getItem('nexus_shortcuts');
    return saved ? JSON.parse(saved) : DEFAULT_SHORTCUTS;
  });

  const updateShortcut = (action: ShortcutAction, index: number, newKey: string, ctrl: boolean = false, shift: boolean = false) => {
    const updated = [...shortcuts];
    updated[index] = { ...updated[index], key: newKey, ctrl, shift };
    setShortcuts(updated);
    localStorage.setItem('nexus_shortcuts', JSON.stringify(updated));
  };

  const getAction = (e: KeyboardEvent): ShortcutAction | null => {
    const match = shortcuts.find(s => 
      s.key === e.code && 
      (s.ctrl ? (e.ctrlKey || e.metaKey) : !(e.ctrlKey || e.metaKey)) &&
      (s.shift ? e.shiftKey : !e.shiftKey)
    );
    return match ? match.action : null;
  };

  return { shortcuts, updateShortcut, getAction };
};

import React, { useMemo } from 'react';
import { Asset, Clip } from '../../types';

interface WaveformProps {
  asset: Asset | undefined;
  clip: Clip;
  isExpanded?: boolean;
}

export const Waveform: React.FC<WaveformProps> = ({ asset, clip, isExpanded }) => {
  const pathData = useMemo(() => {
    const rawData = asset?.waveform || [];
    if (rawData.length === 0) {
      const seed = clip.id.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
      return Array.from({ length: 300 }, (_, i) => Math.max(0.01, Math.abs(Math.sin(seed + i * 0.1)) * 0.4));
    }
    const sampleCount = rawData.length;
    const startIdx = Math.floor((clip.offset / asset!.duration) * sampleCount);
    const endIdx = Math.floor(((clip.offset + clip.duration) / asset!.duration) * sampleCount);
    return rawData.slice(startIdx, endIdx);
  }, [asset, clip.id, clip.offset, clip.duration]);

  const svgPath = useMemo(() => {
    if (pathData.length === 0) return "";
    const width = 1000;
    const height = 100;
    const mid = height / 2;
    const step = width / (pathData.length - 1);

    // Aggressive vertical scaling for "surgical" visibility
    const gain = isExpanded ? 2.5 : 1.2;

    let upper = `M 0 ${mid}`;
    let lower = `L ${width} ${mid}`;
    pathData.forEach((val, i) => {
      const x = i * step;
      const amp = val * (height / 2) * gain;
      const cappedAmp = Math.min(mid - 1, amp);
      upper += ` L ${x} ${mid - cappedAmp}`;
      lower = ` L ${x} ${mid + cappedAmp}` + lower;
    });
    return upper + lower + " Z";
  }, [pathData, isExpanded]);

  return (
    <div className={`absolute inset-0 pointer-events-none transition-all duration-500 ${isExpanded ? 'opacity-100 bg-indigo-500/5' : 'opacity-60'}`}>
      <svg viewBox="0 0 1000 100" preserveAspectRatio="none" className="w-full h-full shape-rendering-auto">
        <defs>
          <linearGradient id={`grad-${clip.id}`} x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor={isExpanded ? "#818cf8" : "#4f46e5"} />
            <stop offset="50%" stopColor={isExpanded ? "#e0e7ff" : "#818cf8"} />
            <stop offset="100%" stopColor={isExpanded ? "#818cf8" : "#4f46e5"} />
          </linearGradient>
        </defs>
        <path 
          d={svgPath} 
          fill={`url(#grad-${clip.id})`} 
          stroke={isExpanded ? "#6366f1" : "transparent"} 
          strokeWidth={isExpanded ? "0.3" : "0"} 
        />
        <line x1="0" y1="50" x2="1000" y2="50" stroke="#4338ca" strokeWidth="0.1" strokeDasharray="2,2" className="opacity-20" />
      </svg>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize, VolumeX } from 'lucide-react';
import { Project, Asset } from '../../types';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
  onTimeUpdate: (t: number) => void;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime, onTimeUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioContainerRef = useRef<HTMLDivElement>(null);
  const audioElementsRef = useRef<Map<string, HTMLAudioElement>>(new Map());
  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(performance.now());

  // Direct DOM Sync Loop
  const animate = (time: number) => {
    if (isPlaying) {
      const deltaTime = (time - lastTimeRef.current) / 1000;
      const nextTime = currentTime + deltaTime;
      onTimeUpdate(nextTime);
    }
    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, currentTime]);

  const activeVideoClip = project.tracks
    .slice()
    .reverse()
    .filter(t => t.type === 'video' && t.isVisible)
    .flatMap(t => t.clips)
    .find(c => currentTime >= c.startTime && currentTime <= c.startTime + c.duration);

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;
  const videoTrackMuted = project.tracks.find(t => t.clips.some(c => c.id === activeVideoClip?.id))?.isMuted;
  const isVideoSilenceNeeded = activeVideoClip?.isSilent || videoTrackMuted;

  const activeAudioSources = project.tracks
    .filter(t => !t.isMuted)
    .flatMap(t => t.clips.map(c => ({ clip: c, asset: assets.find(a => a.id === c.assetId) })))
    .filter(item => 
      item.asset && 
      !item.clip.isSilent && 
      currentTime >= item.clip.startTime && 
      currentTime <= item.clip.startTime + item.clip.duration
    );

  // Video Element Sync
  useEffect(() => {
    if (!videoRef.current) return;
    if (activeVideoAsset && activeVideoClip) {
      videoRef.current.muted = !!isVideoSilenceNeeded;
      const targetTime = (currentTime - activeVideoClip.startTime) + activeVideoClip.offset;
      if (Math.abs(videoRef.current.currentTime - targetTime) > 0.05) {
        videoRef.current.currentTime = targetTime;
      }
      if (isPlaying) videoRef.current.play().catch(() => {});
      else videoRef.current.pause();
    } else {
      videoRef.current.pause();
    }
  }, [isPlaying, activeVideoAsset?.id, isVideoSilenceNeeded]);

  // Audio elements management
  useEffect(() => {
    if (!audioContainerRef.current) return;
    const container = audioContainerRef.current;
    const currentActiveIds = new Set(activeAudioSources.map(s => s.clip.id));

    // Cleanup
    for (const [id, el] of audioElementsRef.current.entries()) {
      if (!currentActiveIds.has(id)) {
        el.pause();
        el.src = "";
        el.remove();
        audioElementsRef.current.delete(id);
      }
    }

    // Sync
    activeAudioSources.forEach(({ clip, asset }) => {
      if (!asset) return;
      let el = audioElementsRef.current.get(clip.id);
      if (!el) {
        el = document.createElement('audio');
        el.src = asset.url;
        el.preload = "auto";
        container.appendChild(el);
        audioElementsRef.current.set(clip.id, el);
      }
      const targetTime = (currentTime - clip.startTime) + clip.offset;
      if (Math.abs(el.currentTime - targetTime) > 0.05) {
        el.currentTime = targetTime;
      }
      if (isPlaying) el.play().catch(() => {});
      else el.pause();
    });
  }, [isPlaying, activeAudioSources.length]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden border-x border-zinc-800/50">
      <div ref={audioContainerRef} className="hidden" aria-hidden="true" />
      <div className="flex-1 flex items-center justify-center p-6 bg-[#0a0a0a]">
        <div className="aspect-video w-full max-w-4xl bg-black rounded shadow-2xl border border-white/5 flex items-center justify-center overflow-hidden relative">
          {activeVideoAsset ? (
            <video 
              ref={videoRef} 
              src={activeVideoAsset.url} 
              className="w-full h-full object-contain pointer-events-none" 
            />
          ) : (
            <div className="text-zinc-800 text-[10px] font-black uppercase tracking-widest animate-pulse">Standby...</div>
          )}

          <div className="absolute top-4 left-4 flex gap-2">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono border border-white/10 uppercase">Master Preview</div>
          </div>
        </div>
      </div>

      <div className="h-14 bg-[#121212] border-t border-zinc-800 flex items-center justify-between px-6">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white" onClick={() => onTimeUpdate(0)}><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-9 h-9 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-all shadow-xl"
            >
              {isPlaying ? <Pause className="text-black fill-black" size={16} /> : <Play className="text-black fill-black translate-x-0.5" size={16} />}
            </button>
            <button className="text-zinc-500 hover:text-white"><SkipForward size={16} /></button>
          </div>
          <div className="font-mono text-[13px] text-indigo-400 tabular-nums bg-indigo-500/5 px-3 py-1 rounded border border-indigo-500/10">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">:{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>
        <div className="flex items-center gap-4 text-zinc-500">
           <Maximize size={16} className="cursor-pointer hover:text-white" />
        </div>
      </div>
    </div>
  );
};

