export const ExportModal: React.FC<ExportModalProps> = ({ onClose, project, assets }) => {
  const [step, setStep] = useState<'settings' | 'exporting' | 'finished'>('settings');
  const [progress, setProgress] = useState(0);
  const [filename, setFilename] = useState(project.name || 'nexus_master_export');

  // Determine defaults based on assets
  const defaults = useMemo(() => {
    const videoAssets = assets.filter(a => a.type === MediaType.VIDEO);
    if (videoAssets.length === 0) return { res: '1920x1080', fps: '30' };

    // Simplification: use the most common resolution or the first one
    // In a real app we would probe the actual dimensions
    return { res: '1920x1080', fps: '30' };
  }, [assets]);

  const [config, setConfig] = useState({
    format: 'MP4',
    resolution: defaults.res,
    framerate: defaults.fps,
    bitrate: '12 Mbps',
    quality: 'High'
  });

  useEffect(() => {
    if (step === 'exporting') {
      const interval = setInterval(() => {
        setProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            setTimeout(() => setStep('finished'), 400);
            return 100;
          }
          return prev + (Math.random() * 4 + 1);
        });
      }, 80);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleDownload = () => {
    // Simulate downloading the rendered file
    const dummyContent = "This is a simulated video file exported from Nexus Studio Pro.";
    const blob = new Blob([dummyContent], { type: 'video/mp4' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${filename}.${config.format.toLowerCase()}`;
