interface ExportModalProps {
  onClose: () => void;
  project: Project;
  assets: Asset[];
}

export const ExportModal: React.FC<ExportModalProps> = ({ onClose, project, assets }) => {
  const [step, setStep] = useState<'settings' | 'exporting' | 'finished'>('settings');
  const [progress, setProgress] = useState(0);
  const [filename, setFilename] = useState(project.name.toLowerCase().replace(/\s+/g, '_') || 'nexus_export');

  // Determine optimal defaults based on sequence content
  const sequenceDefaults = useMemo(() => {
    const videoAssets = assets.filter(a => a.type === MediaType.VIDEO);

    // If only one video, match its common standard (simulated)
    // If multiple, default to 1080p as the "optimal" but not extreme setting
    if (videoAssets.length === 1) {
      return { resolution: '1920x1080', framerate: '30' };
    }

    return { resolution: '1920x1080', framerate: '30' };
  }, [assets]);

  const [config, setConfig] = useState({
    format: 'MP4',
    resolution: sequenceDefaults.resolution,
    framerate: sequenceDefaults.framerate,
    bitrate: '12 Mbps',
    quality: 'High'
  });

  // Performance optimization: Using a lighter progress loop
  useEffect(() => {
    if (step === 'exporting') {
      let currentProgress = 0;
      const interval = setInterval(() => {
        const increment = Math.random() * 3 + 0.5;
        currentProgress += increment;

        if (currentProgress >= 100) {
          setProgress(100);
          clearInterval(interval);
          setTimeout(() => setStep('finished'), 600);
        } else {
          setProgress(currentProgress);
        }
      }, 100);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleDownloadMaster = () => {
    // Creating a more "substantial" dummy file for the demonstration
    // In a production environment, this would be the blob returned by a media recorder or ffmpeg.wasm
    const exportData = new Uint8Array(1024 * 10); // 10KB dummy buffer
    const blob = new Blob([exportData], { type: 'video/mp4' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${filename}.${config.format.toLowerCase()}`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[300] flex items-center justify-center p-6 animate-in fade-in duration-200">
