                        <span className="text-[9px] font-mono text-zinc-500">{config.framerate} FPS</span>
                     </div>
                     <div className="px-3 py-1 bg-indigo-600/20 border border-indigo-500/20 rounded text-[10px] font-bold text-indigo-400 uppercase tracking-widest">
                        {config.format}
                     </div>
                  </div>
                </div>

                <div className="mt-8 space-y-4">
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500 block mb-2 px-1">Target Filename</label>
                    <div className="relative group">
                      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500 group-focus-within:text-indigo-400 transition-colors">
                        <FileText size={16} />
                      </div>
                      <input 
                        type="text" 
                        value={filename}
                        onChange={(e) => setFilename(e.target.value)}
                        className="w-full bg-zinc-900/50 border border-zinc-800 rounded-xl pl-12 pr-4 py-3.5 text-sm font-bold focus:border-indigo-500 outline-none transition-all placeholder:text-zinc-700"
