  // Performance Optimization: Pause playback when export or shortcut modal is open
  useEffect(() => {
    if ((isExportModalOpen || isShortcutModalOpen) && store.isPlaying) {
      store.setIsPlaying(false);
    }
  }, [isExportModalOpen, isShortcutModalOpen]);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
    const action = shortcutStore.getAction(e);
    if (!action) return;
    e.preventDefault();
    switch (action) {
      case 'play_pause': store.setIsPlaying(!store.isPlaying); break;
      case 'split': store.splitClip(store.selectedClipId, store.currentTime); break;
      case 'delete': if (store.selectedClipId) store.deleteClip(store.selectedClipId); break;
      case 'undo': store.undo(); break;
      case 'redo': store.redo(); break;
      case 'zoom_in': store.setZoom(Math.min(100, store.zoom + 5)); break;
      case 'zoom_out': store.setZoom(Math.max(1, store.zoom - 5)); break;
      case 'toggle_magnet': store.setIsMagnetEnabled(!store.isMagnetEnabled); break;
    }
  }, [store, shortcutStore]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try { const hasKey = await aistudio.hasSelectedApiKey(); if (!hasKey) await aistudio.openSelectKey(); } catch (err) {}
    }
    const userInput = window.prompt("Describe your scene:");
    if (!userInput) return;
    setIsGenerating(true);
    try {
      const videoUrl = await GeminiService.getInstance().generateVideo(userInput);
      const newAsset: Asset = { id: `ai-${Date.now()}`, name: `AI Video`, type: MediaType.VIDEO, url: videoUrl, duration: 5, thumbnail: 'https://picsum.photos/320/180' };
      store.addAsset(newAsset);
      store.addClipAtPosition('track-v1', newAsset, store.currentTime);
    } catch (error) {
      alert("AI Generation failed.");
    } finally { setIsGenerating(false); }
  };

  const handleAssetToTimeline = (asset: Asset) => {
    const targetTrackId = asset.type === MediaType.AUDIO ? (store.project.tracks.find(t => t.type === 'audio')?.id || 'track-a1') : (store.project.tracks.find(t => t.type === 'video')?.id || 'track-v1');
    store.addClipAtPosition(targetTrackId, asset, store.currentTime);
  };

  const selectedClip = store.project.tracks.flatMap(t => t.clips).find(c => c.id === store.selectedClipId);
  const selectedAsset = selectedClip ? store.assets.find(a => a.id === selectedClip.assetId) : null;

  return (
    <div className="h-screen flex flex-col bg-[#080808] text-zinc-200 select-none overflow-hidden">
      {/* Dynamic Header */}
      <header className="h-12 bg-[#121212] border-b border-zinc-800/50 flex items-center justify-between px-4 z-50">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer">
            <div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[11px] font-black shadow-lg shadow-indigo-600/20 group-hover:scale-110 transition-transform">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">
            {['File', 'Edit', 'Sequence', 'Project'].map(item => (
              <Tooltip key={item} text={`${item} Menu Options`} position="bottom">
                <button className="px-3 py-1 hover:text-white transition-colors">{item}</button>
              </Tooltip>
            ))}
          </nav>
        </div>
        <div className="flex items-center gap-2">
          <Tooltip text="View Project History" position="bottom" shortcut="CTRL+H">
             <button className="p-1.5 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white transition-all"><History size={18}/></button>
          </Tooltip>
          <Tooltip text="Keyboard Shortcuts Manager" position="bottom" shortcut="K">
            <button onClick={() => setIsShortcutModalOpen(true)} className="p-1.5 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white mr-2 transition-all"><Keyboard size={18} /></button>
          </Tooltip>
          <Tooltip text="Final Export Master" position="bottom">
            <button onClick={() => setIsExportModalOpen(true)} className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-black px-5 py-1.5 rounded-full transition-all active:scale-95 shadow-lg shadow-indigo-600/30 tracking-widest"><Download size={14} /> EXPORT</button>
          </Tooltip>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Sidebar Tools */}
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <Tooltip text="Layer Management" position="right">
            <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10 hover:bg-indigo-500/20 transition-all"><Layers size={22} /></button>
          </Tooltip>
          <Tooltip text="Visual Grading & FX" position="right">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all"><Palette size={22} /></button>
          </Tooltip>
          <Tooltip text="Typography & Overlay" position="right">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all"><TypeIcon size={22} /></button>
          </Tooltip>
          <Tooltip text="Razor Tool (Split)" position="right" shortcut="S/B">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all" onClick={() => store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
          </Tooltip>
          <div className="mt-auto pb-4">
             <Tooltip text="Help & Tutorials" position="right">
                <button className="text-zinc-700 hover:text-zinc-400 transition-all"><HelpCircle size={18}/></button>
             </Tooltip>
          </div>
        </aside>

        <div className="flex-1 flex flex-col overflow-hidden">
          <div className="h-[55%] flex border-b border-zinc-800/50">
            <Library assets={store.assets} onAddAsset={store.addAsset} onGenerateAI={handleAICompose} onDragAssetToTimeline={handleAssetToTimeline} />
            <PreviewPlayer project={store.project} assets={store.assets} isPlaying={store.isPlaying} onTogglePlay={() => store.setIsPlaying(!store.isPlaying)} currentTime={store.currentTime} onTimeUpdate={store.setCurrentTime} />

            {/* Properties Panel */}
            <div className="w-[300px] bg-[#121212] border-l border-zinc-800/50 p-6 overflow-y-auto">
              <h2 className="text-[10px] font-black uppercase tracking-widest text-zinc-600 mb-8 flex items-center gap-2"><Settings size={12}/> Properties</h2>
              {selectedClip ? (
                <div className="space-y-6 animate-in slide-in-from-right-2 duration-300">
                  <div className="p-4 bg-zinc-900/50 rounded-2xl border border-zinc-800">
                    <span className="text-[9px] text-zinc-500 block mb-2 font-black uppercase tracking-widest">Active Clip</span>
                    <p className="text-[11px] font-black text-indigo-400 truncate mb-1">{selectedAsset?.name || selectedClip.id}</p>
                    <p className="text-[9px] text-zinc-500 font-mono">{(selectedClip.duration).toFixed(3)}s @ {selectedClip.startTime.toFixed(2)}s</p>
                  </div>
                  <div className="space-y-4">
                    <label className="text-[10px] text-zinc-600 uppercase font-black tracking-widest px-1">Clip Operations</label>
                    {selectedAsset?.type === MediaType.VIDEO && (
                      <button onClick={() => store.detachAudio(selectedClip.id)} className="w-full py-3 bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-400 text-[10px] font-black rounded-xl border border-indigo-500/20 flex items-center justify-center gap-2 transition-all"><Music size={14}/> DETACH AUDIO</button>
                    )}
                    <button onClick={() => store.deleteClip(selectedClip.id)} className="w-full py-3 bg-red-500/10 hover:bg-red-500/20 text-red-500 text-[10px] font-black rounded-xl border border-red-500/20 transition-all">DELETE CLIP</button>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center px-6">
                   <div className="w-12 h-12 bg-zinc-800/50 rounded-2xl flex items-center justify-center text-zinc-600 mb-4 border border-zinc-800">
                      <Settings size={20}/>
                   </div>
                   <p className="text-[11px] text-zinc-600 font-medium italic">Select a sequence clip to modify properties and effects.</p>
                </div>
              )}
            </div>
          </div>
          <Timeline 
            project={store.project} assets={store.assets} currentTime={store.currentTime} zoom={store.zoom} isMagnetEnabled={store.isMagnetEnabled}
            setZoom={store.setZoom} setIsMagnetEnabled={store.setIsMagnetEnabled} onTimeChange={store.setCurrentTime}
            onClipMove={store.moveClip} onClipFinalize={store.finalizeMove} onClipSplit={store.splitClip} onClipDelete={store.deleteClip}
            onToggleTrack={store.toggleTrackProperty} onSetTrackHeight={store.setTrackHeight} onAddClipAtPosition={store.addClipAtPosition} onAddTrack={store.addTrack}
            onDetachAudio={store.detachAudio} onUndo={store.undo} onRedo={store.redo} canUndo={store.canUndo} canRedo={store.canRedo}
            selectedClipId={store.selectedClipId} onSelectClip={store.setSelectedClipId}
          />
        </div>
      </main>

      {/* Modals */}
      {isShortcutModalOpen && <ShortcutModal shortcuts={shortcutStore.shortcuts} onUpdate={shortcutStore.updateShortcut} onClose={() => setIsShortcutModalOpen(false)} />}
      {isExportModalOpen && <ExportModal project={store.project} assets={store.assets} onClose={() => setIsExportModalOpen(false)} />}

      {/* Loading Overlays */}
      {isGenerating && (<div className="fixed inset-0 bg-black/90 backdrop-blur-sm z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500"><div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6 shadow-2xl shadow-indigo-500/50" /><h3 className="text-xl font-black uppercase tracking-tighter">AI rendering sequence...</h3><p className="text-xs text-zinc-500 mt-2 font-medium">This may take a minute depending on complex reasoning.</p></div>)}
    </div>
  );
};

