import React, { useRef } from 'react';
import { Upload, Film, Music, Sparkles, Search } from 'lucide-react';
import { Asset, MediaType } from '../../types';
import { AssetService } from '../../services/AssetService';
import { Tooltip } from '../UI/Tooltip';

interface LibraryProps {
  assets: Asset[];
  onAddAsset: (asset: Asset) => void;
  onGenerateAI: () => void;
  onDragAssetToTimeline: (asset: Asset) => void;
}

export const Library: React.FC<LibraryProps> = ({ assets, onAddAsset, onGenerateAI, onDragAssetToTimeline }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    for (const file of Array.from(files) as File[]) {
      const asset = await AssetService.processFile(file);
      onAddAsset(asset);
    }
  };

  const handleDragStart = (e: React.DragEvent, asset: Asset) => {
    e.dataTransfer.setData('assetId', asset.id);
    e.dataTransfer.effectAllowed = 'copy';
  };

  return (
    <div className="w-[300px] bg-[#1a1a1a] border-r border-[#333] flex flex-col shadow-xl">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        multiple 
        accept="video/*,audio/*,image/*" 
        onChange={handleFileChange}
      />

      <div className="p-4 border-b border-[#333] bg-[#1c1c1c]">
        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-500 mb-4">Master Media Library</h2>
        <div className="flex gap-2 mb-4">
          <Tooltip text="Import Local Media" position="bottom">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex-1 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg px-3 py-2.5 text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all border border-zinc-700 active:scale-95 shadow-sm"
            >
              <Upload size={14} /> IMPORT
            </button>
          </Tooltip>
          <Tooltip text="Generate AI Video Asset" position="bottom">
            <button 
              onClick={onGenerateAI}
              className="flex-1 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg px-3 py-2.5 text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-lg shadow-indigo-600/20 active:scale-95"
            >
              <Sparkles size={14} /> AI BUILD
            </button>
          </Tooltip>
        </div>
        <div className="relative group">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-600 group-focus-within:text-indigo-400 transition-colors" size={12} />
          <input 
            type="text" 
            placeholder="Search assets..." 
            className="w-full bg-[#111] border border-[#333] rounded-lg px-8 py-2 text-xs focus:outline-none focus:border-indigo-500 transition-colors placeholder:text-zinc-700 font-bold"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-2">
        {assets.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center opacity-20 px-10">
            <div className="w-16 h-16 rounded-2xl bg-zinc-800 flex items-center justify-center mb-4 border border-zinc-700">
               <Film size={32} />
            </div>
            <p className="text-[11px] font-black uppercase tracking-tighter">Library Standby</p>
            <p className="text-[9px] mt-1 font-medium">Import assets to begin sequence assembly.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-3">
            {assets.map(asset => (
              <Tooltip key={asset.id} text={`Click to add ${asset.name} to sequence`} position="right">
                <div 
                  draggable
                  onDragStart={(e) => handleDragStart(e, asset)}
                  onClick={() => onDragAssetToTimeline(asset)}
                  className="group flex gap-3 p-2.5 bg-[#111] rounded-xl border border-[#333] hover:border-indigo-500/50 transition-all cursor-pointer hover:bg-[#161616] relative"
                >
                  <div className="w-20 aspect-video bg-black rounded-lg overflow-hidden flex-shrink-0 relative border border-white/5">
                    {asset.thumbnail ? (
                      <img src={asset.thumbnail} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center opacity-40">
                        {asset.type === MediaType.VIDEO ? <Film size={20} /> : <Music size={20} />}
                      </div>
                    )}
                    <div className="absolute bottom-1 right-1 bg-black/80 text-[8px] px-1 rounded font-mono text-zinc-300 backdrop-blur-sm font-bold">
                      {asset.duration.toFixed(1)}s
                    </div>
                  </div>
                  <div className="flex-1 min-w-0 flex flex-col justify-center">
                    <p className="text-[11px] font-black truncate text-zinc-300 tracking-tight leading-none mb-1 group-hover:text-white transition-colors">{asset.name}</p>
                    <p className="text-[9px] text-zinc-600 font-black uppercase tracking-[0.1em]">{asset.type}</p>
                  </div>
                </div>
              </Tooltip>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { X, Download, Film, HardDrive, CheckCircle2, Loader2, FileText, Monitor, ChevronRight } from 'lucide-react';
import { Project, Asset, MediaType } from '../../types';

interface ExportModalProps {
  onClose: () => void;
  project: Project;
  assets: Asset[];
}

export const ExportModal: React.FC<ExportModalProps> = ({ onClose, project, assets }) => {
  const [step, setStep] = useState<'settings' | 'exporting' | 'finished'>('settings');
  const [progress, setProgress] = useState(0);
  const [filename, setFilename] = useState(project.name.toLowerCase().replace(/\s+/g, '_') || 'nexus_export');
  const [isDownloading, setIsDownloading] = useState(false);

  // Intelligent defaults based on sequence content
  const sequenceDefaults = useMemo(() => {
    const videoAssets = assets.filter(a => a.type === MediaType.VIDEO);
    // If we have video assets, we default to 1080p which is professional yet safe
    // We explicitly avoid 2K/4K as defaults as per request
    return { 
      resolution: '1920x1080', 
      framerate: '30',
      isSingleAsset: videoAssets.length === 1 
    };
  }, [assets]);

  const [config, setConfig] = useState({
    format: 'MP4',
    resolution: sequenceDefaults.resolution,
    framerate: sequenceDefaults.framerate,
    bitrate: '12 Mbps',
    quality: 'High'
  });

  // Optimized render simulation loop
  useEffect(() => {
    if (step === 'exporting') {
      let currentProgress = 0;
      const interval = setInterval(() => {
        const increment = Math.random() * 2 + 0.3;
        currentProgress += increment;

        if (currentProgress >= 100) {
          setProgress(100);
          clearInterval(interval);
          setTimeout(() => setStep('finished'), 600);
        } else {
          setProgress(currentProgress);
        }
      }, 80);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleDownloadMaster = async () => {
    setIsDownloading(true);
    try {
      // 1. Locate the primary video asset to use as the base for the "rendered" result
      const primaryAsset = assets.find(a => a.type === MediaType.VIDEO) || assets[0];

      if (!primaryAsset) {
        throw new Error("No assets found to export");
      }

      // 2. Fetch the actual blob of the asset
      const response = await fetch(primaryAsset.url);
      const blob = await response.blob();

      // 3. Create a clean download link with the user's chosen filename
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `${filename || 'nexus_master'}.${config.format.toLowerCase()}`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("Export failed:", error);
      alert("Export failed: Could not retrieve media buffer. Please ensure assets are loaded.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/90 z-[300] flex items-center justify-center p-6 animate-in fade-in duration-200">
      <div className="bg-[#0f0f0f] border border-zinc-800 w-full max-w-4xl h-[640px] rounded-3xl shadow-2xl flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-zinc-800 flex items-center justify-between bg-[#141414]">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-600/20">
              <Download size={20} />
            </div>
            <div>
              <h2 className="text-lg font-black tracking-tight uppercase">Master Export Engine</h2>
              <p className="text-[10px] text-zinc-500 font-bold tracking-widest uppercase">Sequence: {project.name}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-zinc-800 rounded-full text-zinc-500 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 flex min-h-0 bg-[#0a0a0a]">
          {step === 'settings' && (
            <>
              {/* Left: Metadata & Filename */}
              <div className="w-2/3 p-10 flex flex-col border-r border-zinc-800 bg-[#080808]">
                <div className="w-full aspect-video bg-zinc-900 rounded-2xl border border-zinc-800 flex flex-col items-center justify-center relative overflow-hidden">
                  <Film className="text-zinc-800" size={64} />
                  <div className="mt-4 text-[9px] font-black uppercase tracking-[0.4em] text-zinc-600">Final Sequence Preview</div>

                  <div className="absolute bottom-6 left-6 right-6 flex items-center justify-between">
                     <div className="flex flex-col gap-0.5">
                        <span className="text-[11px] font-black text-indigo-400">{config.resolution}</span>
                        <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">{config.framerate} FPS SOURCE</span>
                     </div>
                     <div className="px-3 py-1 bg-white/5 border border-white/10 rounded-lg text-[10px] font-black text-white uppercase">
                        {config.format} MASTER
                     </div>
                  </div>
                </div>

                <div className="mt-10 space-y-6">
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 block mb-3 px-1">Output Filename</label>
                    <div className="relative">
                      <FileText className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" size={16} />
                      <input 
                        type="text" 
                        value={filename}
                        onChange={(e) => setFilename(e.target.value)}
                        className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl pl-12 pr-4 py-4 text-sm font-bold focus:border-indigo-500 outline-none transition-all placeholder:text-zinc-700 shadow-inner"
                        placeholder="Enter file name..."
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="p-5 bg-zinc-900/30 rounded-2xl border border-zinc-800/50 flex items-center gap-4">
                       <div className="w-10 h-10 rounded-xl bg-zinc-800/50 flex items-center justify-center text-zinc-500">
                          <HardDrive size={18} />
                       </div>
                       <div>
                          <p className="text-[9px] text-zinc-600 uppercase font-black">Est. Master Size</p>
                          <p className="text-sm font-black text-zinc-400">~128.5 MB</p>
                       </div>
                    </div>
                    <div className="p-5 bg-zinc-900/30 rounded-2xl border border-zinc-800/50 flex items-center gap-4">
                       <div className="w-10 h-10 rounded-xl bg-zinc-800/50 flex items-center justify-center text-zinc-500">
                          <Monitor size={18} />
                       </div>
                       <div>
                          <p className="text-[9px] text-zinc-600 uppercase font-black">Processing</p>
                          <p className="text-sm font-black text-zinc-400">Linear Render</p>
                       </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Right: Technical Controls */}
              <div className="w-1/3 p-8 flex flex-col bg-[#121212] border-l border-white/5">
                <div className="space-y-8 flex-1">
                  <section>
                    <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500 block mb-4">Export Preset</label>
                    <div className="space-y-2">
                       {['3840x2160', '2560x1440', '1920x1080', '1280x720'].map(res => (
                         <button 
                          key={res}
                          onClick={() => setConfig({...config, resolution: res})}
                          className={`w-full flex items-center justify-between px-4 py-3 rounded-xl border text-[11px] font-bold transition-all ${config.resolution === res ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600 hover:border-zinc-700'}`}
                         >
                           {res.includes('3840') ? '4K Ultra HD' : res.includes('2560') ? '2K Quad HD' : res.includes('1920') ? '1080p Master' : '720p HD'}
                           {config.resolution === res && <CheckCircle2 size={14} />}
                         </button>
                       ))}
                    </div>
                  </section>

                  <section>
                    <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500 block mb-4">Master Framerate</label>
                    <div className="grid grid-cols-3 gap-2">
                      {['24', '30', '60'].map(fps => (
                        <button 
                          key={fps}
                          onClick={() => setConfig({...config, framerate: fps})}
                          className={`py-3 rounded-xl text-[10px] font-black border transition-all ${config.framerate === fps ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}
                        >
                          {fps} FPS
                        </button>
                      ))}
                    </div>
                  </section>
                </div>

                <div className="pt-8">
                  <button 
                    onClick={() => setStep('exporting')}
                    className="w-full bg-white text-black font-black uppercase tracking-widest py-5 rounded-2xl flex items-center justify-center gap-3 hover:scale-[1.02] active:scale-[0.98] transition-all shadow-xl shadow-white/5"
                  >
                    <Download size={18} /> Compile & Save
                  </button>
