        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5 group cursor-pointer">
            <div className="w-7 h-7 bg-indigo-600 rounded-lg flex items-center justify-center text-[10px] font-black shadow-lg shadow-indigo-600/20 group-hover:scale-105 transition-transform">NX</div>
            <h1 className="text-sm font-black tracking-tighter uppercase">Nexus <span className="text-zinc-600 font-medium">Studio</span></h1>
          </div>
          <nav className="flex items-center gap-1 ml-4 text-[11px] font-bold text-zinc-500">
            {['File', 'Edit', 'Sequence', 'Project'].map(item => (
              <Tooltip key={item} text={`${item} Menu`} position="bottom">
                <button className="px-3 py-1 hover:text-white transition-colors">{item}</button>
              </Tooltip>
            ))}
          </nav>
        </div>
        <div className="flex items-center gap-2">
          <Tooltip text="Keyboard Mapping" position="bottom" shortcut="K">
            <button onClick={() => setIsShortcutModalOpen(true)} className="p-1.5 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white mr-1 transition-all"><Keyboard size={18} /></button>
          </Tooltip>
          <Tooltip text="Render Master" position="bottom">
            <button onClick={() => setIsExportModalOpen(true)} className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-black px-6 py-2 rounded-full transition-all active:scale-95 shadow-lg shadow-indigo-600/30 tracking-widest"><Download size={14} /> EXPORT</button>
          </Tooltip>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        {/* Professional Sidebar */}
        <aside className="w-14 bg-[#121212] border-r border-zinc-800/50 flex flex-col items-center py-6 gap-8">
          <Tooltip text="Asset Layers" position="right">
            <button className="text-indigo-500 p-2 rounded-xl bg-indigo-500/10 hover:bg-indigo-500/20 transition-all"><Layers size={22} /></button>
          </Tooltip>
          <Tooltip text="Color & Grading" position="right">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all"><Palette size={22} /></button>
          </Tooltip>
          <Tooltip text="Titles & GFX" position="right">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all"><TypeIcon size={22} /></button>
          </Tooltip>
          <Tooltip text="Razor Tool" position="right" shortcut="S/B">
            <button className="text-zinc-600 hover:text-indigo-400 transition-all" onClick={() => store.splitClip(store.selectedClipId, store.currentTime)}><Scissors size={22} /></button>
          </Tooltip>
          <div className="mt-auto pb-4">
