        <div className="p-6 border-b border-zinc-800 flex items-center justify-between bg-[#141414]">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-600/20">
              <Download size={20} />
            </div>
            <div>
              <h2 className="text-lg font-black tracking-tight uppercase italic">Nexus Export v2.0</h2>
              <p className="text-[10px] text-zinc-500 font-bold tracking-widest uppercase">Project Master: {project.name}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-zinc-800 rounded-full text-zinc-500 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 flex min-h-0 bg-[#0a0a0a]">
          {step === 'settings' && (
            <>
              <div className="w-2/3 p-10 flex flex-col border-r border-zinc-800 bg-[#080808]">
                <div className="w-full aspect-video bg-zinc-900 rounded-2xl border border-zinc-800 flex flex-col items-center justify-center relative overflow-hidden group">
                  <Film className="text-zinc-800 group-hover:text-zinc-700 transition-colors" size={64} />
                  <div className="mt-4 text-[9px] font-black uppercase tracking-[0.4em] text-zinc-600">Composition Output</div>

                  {error && (
                    <div className="absolute top-4 left-4 right-4 bg-red-500/10 border border-red-500/20 p-3 rounded-lg flex items-center gap-3 text-red-500 animate-in slide-in-from-top-2">
                       <AlertCircle size={16} />
                       <span className="text-[10px] font-bold uppercase">{error}</span>
                    </div>
                  )}

                  <div className="absolute bottom-6 left-6 right-6 flex items-center justify-between">
                     <div className="flex flex-col gap-0.5">
                        <span className="text-[11px] font-black text-indigo-400">{config.resolution}</span>
                        <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Client-Side Compositing</span>
                     </div>
                     <div className="px-3 py-1 bg-white/5 border border-white/10 rounded-lg text-[10px] font-black text-white uppercase">
                        {config.format} Container
                     </div>
                  </div>
                </div>

                <div className="mt-10 space-y-6">
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 block mb-3 px-1">Output Filename</label>
                    <div className="relative">
                      <FileText className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" size={16} />
                      <input 
                        type="text" 
                        value={filename}
                        onChange={(e) => setFilename(e.target.value)}
                        className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl pl-12 pr-4 py-4 text-sm font-bold focus:border-indigo-500 outline-none transition-all"
                        placeholder="Export name..."
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="p-5 bg-zinc-900/30 rounded-2xl border border-zinc-800/50 flex items-center gap-4">
                       <HardDrive size={18} className="text-zinc-500" />
                       <div>
                          <p className="text-[9px] text-zinc-600 uppercase font-black">Est. Bitrate</p>
