import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;
    const context = this.canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    // Fix: the correct method name on AudioContext is createMediaStreamDestination
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    const duration = this.calculateProjectDuration(project);
    const stream = this.canvas.captureStream(project.fps);

    // Add audio tracks to stream
    this.audioDest.stream.getAudioTracks().forEach(track => stream.addTrack(track));

    this.recorder = new MediaRecorder(stream, {
      mimeType: 'video/webm;codecs=vp9,opus',
      videoBitsPerSecond: 8000000 // 8Mbps
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => e.data.size > 0 && this.chunks.push(e.data);

    // Prepare video elements for all clips to avoid seeking delays during render
    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.src = asset.url;
          v.muted = true;
          v.preload = 'auto';
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.src = asset.url;
          a.preload = 'auto';
          audioElements.set(clip.id, a);
        }
      }
    }

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder not initialized");

      this.recorder.onstop = () => {
        const blob = new Blob(this.chunks, { type: 'video/webm' });
        resolve(blob);
      };

      this.recorder.start();

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;

      // Render Loop
      while (currentTime <= duration) {
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, this.width, this.height);

        // Render each track (bottom to top)
        for (const track of project.tracks) {
          if (!track.isVisible) continue;

          for (const clip of track.clips) {
            if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
              const asset = assets.find(a => a.id === clip.assetId);
              if (!asset) continue;

              const element = videoElements.get(clip.id);
              if (element) {
                const clipTime = (currentTime - clip.startTime) + clip.offset;
                element.currentTime = clipTime;
                // Wait a bit for seek if necessary (simplified for performance)
                this.ctx.drawImage(element, 0, 0, this.width, this.height);
              }

              // Handle Audio (Simplified: In a full engine we would use AudioBufferSourceNodes)
              const audioEl = audioElements.get(clip.id);
              if (audioEl && !track.isMuted && !clip.isSilent) {
                if (audioEl.paused) audioEl.play();
                const targetTime = (currentTime - clip.startTime) + clip.offset;
                if (Math.abs(audioEl.currentTime - targetTime) > 0.1) audioEl.currentTime = targetTime;
              }
            } else {
              const audioEl = audioElements.get(clip.id);
              if (audioEl && !audioEl.paused) audioEl.pause();
            }
          }
        }

        currentTime += frameDuration;
        onProgress((currentTime / duration) * 100);

        // Let the browser breathe to avoid freezing
        await new Promise(r => requestAnimationFrame(r));
      }

      this.recorder.stop();
      // Cleanup
      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return max || 5;
  }
}

import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;
    const context = this.canvas.getContext('2d', { alpha: false });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private async seekAndWait(video: HTMLVideoElement, time: number): Promise<void> {
    return new Promise((resolve) => {
      const onSeeked = () => {
        video.removeEventListener('seeked', onSeeked);
        resolve();
      };
      video.addEventListener('seeked', onSeeked);
      video.currentTime = time;
      // Safety timeout for stuck frames
      setTimeout(resolve, 100);
    });
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    const duration = this.calculateProjectDuration(project);
    const stream = this.canvas.captureStream(project.fps);

    // Connect audio destination to the recording stream
    this.audioDest.stream.getAudioTracks().forEach(track => stream.addTrack(track));

    // Try to find the best supported format
    const mimeType = MediaRecorder.isTypeSupported('video/mp4;codecs=h264') 
      ? 'video/mp4;codecs=h264' 
      : 'video/webm;codecs=vp9,opus';

    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 12000000 // 12Mbps for high quality
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => e.data.size > 0 && this.chunks.push(e.data);

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();
    const audioSources = new Map<string, MediaElementAudioSourceNode>();

    // Prepare elements and route audio
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.src = asset.url;
          v.muted = true; // We handle audio separately
          v.crossOrigin = "anonymous";
          v.preload = 'auto';
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.src = asset.url;
          a.crossOrigin = "anonymous";
          a.preload = 'auto';
          audioElements.set(clip.id, a);

          // Connect to WebAudio graph for recording
          const source = this.audioCtx.createMediaElementSource(a);
          source.connect(this.audioDest);
          audioSources.set(clip.id, source);
        }
      }
    }

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder failed");

      this.recorder.onstop = () => {
        const finalType = mimeType.includes('mp4') ? 'video/mp4' : 'video/webm';
        resolve(new Blob(this.chunks, { type: finalType }));
      };

      this.recorder.start();

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;

      // Ensure AudioContext is running
      if (this.audioCtx.state === 'suspended') {
        await this.audioCtx.resume();
      }

      // Render Loop
      while (currentTime <= duration) {
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, this.width, this.height);

        for (const track of project.tracks) {
          if (!track.isVisible) continue;

          for (const clip of track.clips) {
            const asset = assets.find(a => a.id === clip.assetId);
            if (!asset) continue;

            if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
              const video = videoElements.get(clip.id);
              if (video) {
                const clipTime = (currentTime - clip.startTime) + clip.offset;
                await this.seekAndWait(video, clipTime);
                this.ctx.drawImage(video, 0, 0, this.width, this.height);
              }

              const audio = audioElements.get(clip.id);
              if (audio && !track.isMuted && !clip.isSilent) {
                const targetTime = (currentTime - clip.startTime) + clip.offset;
                audio.currentTime = targetTime;
                if (audio.paused) audio.play().catch(() => {});
              }
            } else {
              audioElements.get(clip.id)?.pause();
            }
          }
        }

        currentTime += frameDuration;
        onProgress((currentTime / duration) * 100);

        // Wait for one animation frame to keep UI responsive and allow recorder to capture
        await new Promise(r => requestAnimationFrame(r));
      }

      this.recorder.stop();

      // Cleanup nodes
      audioSources.forEach(s => s.disconnect());
      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return max || 5;
  }
}

import React, { useState, useEffect, useMemo } from 'react';
