interface ExportModalProps {
  onClose: () => void;
  project: Project;
  assets: Asset[];
}

export const ExportModal: React.FC<ExportModalProps> = ({ onClose, project, assets }) => {
  const [step, setStep] = useState<'settings' | 'exporting' | 'finished'>('settings');
  const [progress, setProgress] = useState(0);
  const [filename, setFilename] = useState(project.name.toLowerCase().replace(/\s+/g, '_') || 'nexus_export');
  const [exportBlob, setExportBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  const sequenceDefaults = useMemo(() => ({
    resolution: '1280x720', 
    framerate: '30'
  }), []);

  const [config, setConfig] = useState({
    format: 'MP4', 
    resolution: sequenceDefaults.resolution,
    framerate: sequenceDefaults.framerate,
    quality: 'High'
  });

  const startExport = async () => {
    setStep('exporting');
    setProgress(0);
    setError(null);

    try {
      const [width, height] = config.resolution.split('x').map(Number);
      const engine = new ExportEngine(width, height);

      const blob = await engine.render(project, assets, (p) => {
        setProgress(Math.min(99, p));
      });

      setExportBlob(blob);
      setStep('finished');
    } catch (err) {
      console.error("Render Error:", err);
      setError("Rendering failed. Please ensure all assets are accessible and hardware acceleration is enabled.");
      setStep('settings');
    }
  };

  const handleDownloadMaster = () => {
    if (!exportBlob) return;
    const url = URL.createObjectURL(exportBlob);
    const link = document.createElement('a');
    link.href = url;
    // We force .mp4 extension. Even if the container is webm, most players will handle it.
    // If MediaRecorder produced a real mp4, this is perfect.
    link.download = `${filename}.mp4`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
