import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;
    // הגדרת קנבס איכותי
    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false // חשוב לרינדור אסינכרוני
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private async seekAndWait(video: HTMLVideoElement, time: number): Promise<void> {
    return new Promise((resolve) => {
      const timeout = setTimeout(() => {
        video.removeEventListener('seeked', onSeeked);
        resolve();
      }, 500); // Max wait per frame

      const onSeeked = () => {
        clearTimeout(timeout);
        video.removeEventListener('seeked', onSeeked);
        // נותנים לדפדפן רגע לצייר את הפריים החדש פנימית
        requestAnimationFrame(() => resolve());
      };

      video.addEventListener('seeked', onSeeked);
      video.currentTime = time;
    });
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    const duration = this.calculateProjectDuration(project);
    // לכידת הזרם מהקנבס ב-FPS קבוע
    const stream = this.canvas.captureStream(project.fps);

    // חיבור האודיו לזרם ההקלטה
    this.audioDest.stream.getAudioTracks().forEach(track => stream.addTrack(track));

    // זיהוי פורמט נתמך - מעדיפים VP9 לאיכות גבוהה
    const supportedTypes = [
      'video/webm;codecs=vp9,opus',
      'video/webm;codecs=vp8,opus',
      'video/webm',
      'video/mp4'
    ];
    const mimeType = supportedTypes.find(t => MediaRecorder.isTypeSupported(t)) || '';

    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 15000000 // 15Mbps - איכות גבוהה מאוד
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data.size > 0) {
        this.chunks.push(e.data);
      }
    };

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    // הכנת אלמנטים
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.src = asset.url;
          v.muted = true;
          v.crossOrigin = "anonymous";
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.src = asset.url;
          a.crossOrigin = "anonymous";
          audioElements.set(clip.id, a);

          const source = this.audioCtx.createMediaElementSource(a);
          source.connect(this.audioDest);
        }
      }
    }

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder init failed");

      this.recorder.onstop = () => {
        if (this.chunks.length === 0) {
          reject("Render failed: No data recorded. Check assets.");
          return;
        }
        const blob = new Blob(this.chunks, { type: mimeType });
        resolve(blob);
      };

      // שלב חימום: מציירים פריים שחור ומתחילים הקלטה
      this.ctx.fillStyle = '#000000';
      this.ctx.fillRect(0, 0, this.width, this.height);
      this.recorder.start(100); // נותנים Timeslice קטן כדי שהנתונים ייכתבו כל 100ms

      // המתנה קלה לוודא שהמקליט "ער"
      await new Promise(r => setTimeout(r, 200));

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      // לולאת הרינדור הקשיחה
      while (currentTime <= duration) {
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, this.width, this.height);

        for (const track of project.tracks) {
          if (!track.isVisible) continue;

          for (const clip of track.clips) {
            const asset = assets.find(a => a.id === clip.assetId);
            if (!asset) continue;

            if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
              const video = videoElements.get(clip.id);
              if (video) {
                const clipTime = (currentTime - clip.startTime) + clip.offset;
                await this.seekAndWait(video, clipTime);
                this.ctx.drawImage(video, 0, 0, this.width, this.height);
              }

              const audio = audioElements.get(clip.id);
              if (audio && !track.isMuted && !clip.isSilent) {
                const targetTime = (currentTime - clip.startTime) + clip.offset;
                audio.currentTime = targetTime;
                if (audio.paused) audio.play().catch(() => {});
              }
            } else {
              const audio = audioElements.get(clip.id);
              if (audio && !audio.paused) audio.pause();
            }
          }
        }

        currentTime += frameDuration;
        onProgress((currentTime / duration) * 100);

        // השהייה קטנה נוספת כדי לוודא שהפריים הועבר ל-Buffer של המקליט
        await new Promise(r => setTimeout(r, 10));
      }

      // המתנה קצרה בסוף לוודא שכל הנתונים נשלחו
      await new Promise(r => setTimeout(r, 500));
      this.recorder.stop();

      // ניקוי
      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 1);
  }
}

