import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, 
      willReadFrequently: true 
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toISOString().split('T')[1].split('Z')[0];
    this.logs.push(`[${timestamp}] ${msg}`);
    console.log(`[ExportEngine] ${msg}`);
  }

  private async seekAndWait(video: HTMLVideoElement, time: number): Promise<void> {
    // If we're already very close to the target time, don't trigger a new seek
    if (Math.abs(video.currentTime - time) < 0.01) return;

    return new Promise((resolve) => {
      const timeout = setTimeout(() => {
        video.removeEventListener('seeked', onSeeked);
        this.addLog(`Warning: Seek to ${time.toFixed(2)} timed out for ${video.src.substring(0, 30)}...`);
        resolve();
      }, 1500); // Reduced timeout but still generous

      const onSeeked = () => {
        clearTimeout(timeout);
        video.removeEventListener('seeked', onSeeked);
        resolve();
      };

      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration || 0));
    });
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`Initializing Render: ${this.width}x${this.height} @ ${project.fps}fps`);

    const duration = this.calculateProjectDuration(project);
    this.addLog(`Total Duration: ${duration.toFixed(2)}s`);

    // Ensure the canvas has at least one initial frame before capture
    this.ctx.fillStyle = '#000000';
    this.ctx.fillRect(0, 0, this.width, this.height);

    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(track => {
      stream.addTrack(track);
      this.addLog(`Audio track attached: ${track.label}`);
    });

    // Codec compatibility order: VP8 is often more stable for real-time capture than VP9 on some hardware
    const mimeType = [
      'video/webm;codecs=vp8,opus',
      'video/webm;codecs=vp9,opus',
      'video/webm',
      'video/mp4',
      'video/x-matroska'
    ].find(type => MediaRecorder.isTypeSupported(type)) || '';

    this.addLog(`MimeType selected: ${mimeType || 'None'}`);
    if (!mimeType) throw new Error("This browser does not support any valid recording formats.");

    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 15000000 // 15Mbps for high quality
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`CHUNK RECEIVED: ${e.data.size} bytes. Total: ${this.chunks.length}`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    this.addLog("Loading assets into background buffer...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.crossOrigin = "anonymous";
          a.src = asset.url;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          const source = this.audioCtx.createMediaElementSource(a);
          source.connect(this.audioDest);
        }
      }
    }

    this.addLog(`Pipeline ready: ${videoElements.size} video nodes, ${audioElements.size} audio nodes`);

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder failed initialization");

      this.recorder.onstop = () => {
        this.addLog(`Recorder stopped. Final data state: ${this.chunks.length} chunks.`);
        if (this.chunks.length === 0) {
          reject(new Error("RENDER FAILED: No data was recorded. Possible causes: hardware acceleration issues, tab visibility throttling, or browser security restrictions on the video stream."));
        } else {
          const finalBlob = new Blob(this.chunks, { type: mimeType });
          this.addLog(`RENDER SUCCESS: File generated. Size: ${(finalBlob.size / 1024 / 1024).toFixed(2)} MB`);
          resolve(finalBlob);
        }
      };

      this.recorder.onerror = (err) => {
        this.addLog(`RECORDER ERROR: ${err}`);
        reject(err);
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.addLog("Starting MediaRecorder Stream...");
      // Use a smaller timeslice to ensure data is flushed more frequently during the process
      this.recorder.start(500); 

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;

      try {
        while (currentTime <= duration) {
          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const clipRelTime = (currentTime - clip.startTime) + clip.offset;
                  await this.seekAndWait(video, clipRelTime);
                  this.ctx.drawImage(video, 0, 0, this.width, this.height);
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted && !clip.isSilent) {
                  const targetTime = (currentTime - clip.startTime) + clip.offset;
                  audio.currentTime = targetTime;
                  if (audio.paused) await audio.play().catch(() => {});
                }
              } else {
                const audio = audioElements.get(clip.id);
                if (audio && !audio.paused) audio.pause();
              }
            }
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);

          // Technical yield to keep the browser responsive and allow MediaRecorder to process frames
          await new Promise(r => setTimeout(r, 0));
        }

        this.addLog("Render loop finished. Flushing final stream data...");
        // Critical: request data one last time before stopping
        this.recorder.requestData();

        // Wait a bit longer to ensure the last frames are encoded and sent to the buffer
        await new Promise(r => setTimeout(r, 2000));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`CRITICAL EXCEPTION: ${err.message}`);
        if (this.recorder.state === 'recording') this.recorder.stop();
        reject(err);
      }

      // Resource Disposal
      videoElements.forEach(v => { v.pause(); v.src = ''; v.load(); });
      audioElements.forEach(a => { a.pause(); a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 0.5); // Ensure at least a minimal duration
  }
}

import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, 
      willReadFrequently: true 
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toISOString().split('T')[1].split('Z')[0];
    this.logs.push(`[${timestamp}] ${msg}`);
    console.log(`[ExportEngine] ${msg}`);
  }

  private async seekAndWait(video: HTMLVideoElement, time: number): Promise<void> {
    if (Math.abs(video.currentTime - time) < 0.01) return;

    return new Promise((resolve) => {
      const timeout = setTimeout(() => {
        video.removeEventListener('seeked', onSeeked);
        this.addLog(`Warning: Seek timeout at ${time.toFixed(2)}s for asset ${video.src.substring(0, 40)}...`);
        resolve();
      }, 3000); // 3 second timeout for slow seeks

      const onSeeked = () => {
        clearTimeout(timeout);
        video.removeEventListener('seeked', onSeeked);
        resolve();
      };

      video.addEventListener('seeked', onSeeked);
      video.currentTime = Math.max(0, Math.min(time, video.duration || 0));
    });
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`STARTING RENDER: ${this.width}x${this.height} @ ${project.fps}fps`);

    const duration = this.calculateProjectDuration(project);
    this.addLog(`Duration to render: ${duration.toFixed(2)}s`);

    // Draw initial black frame
    this.ctx.fillStyle = '#000000';
    this.ctx.fillRect(0, 0, this.width, this.height);

    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(track => {
      stream.addTrack(track);
      this.addLog(`Audio destination track synced.`);
    });

    const mimeType = [
      'video/webm;codecs=vp8,opus',
      'video/webm;codecs=vp9,opus',
      'video/webm',
      'video/mp4'
    ].find(type => MediaRecorder.isTypeSupported(type)) || '';

    this.addLog(`Codec selected: ${mimeType}`);
    if (!mimeType) throw new Error("No compatible video codec found in this browser.");

    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 12000000 
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`DATA CHUNK: ${e.data.size} bytes captured.`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    this.addLog("Step 1: Initializing assets...");
    const loadPromises: Promise<void>[] = [];

    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);

          loadPromises.push(new Promise((res) => {
            v.onloadedmetadata = () => res();
            v.onerror = () => {
              this.addLog(`ERROR: Failed to load video ${asset.name}`);
              res(); // Resolve anyway to avoid hanging
            };
            // If already loaded
            if (v.readyState >= 1) res();
          }));
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.crossOrigin = "anonymous";
          a.src = asset.url;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          const source = this.audioCtx.createMediaElementSource(a);
          source.connect(this.audioDest);

          loadPromises.push(new Promise((res) => {
            a.onloadedmetadata = () => res();
            a.onerror = () => res();
            if (a.readyState >= 1) res();
          }));
        }
      }
    }

    this.addLog("Step 2: Waiting for assets metadata...");
    await Promise.all(loadPromises);
    this.addLog(`Assets ready. Starting render loop...`);

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder failed");

      this.recorder.onstop = () => {
        if (this.chunks.length === 0) {
          this.addLog(`CRITICAL: Stop signal received but 0 bytes recorded.`);
          reject(new Error("Render produced no data. This can happen if the browser's hardware encoder crashed or the canvas was tainted by cross-origin files without proper headers."));
        } else {
          const finalBlob = new Blob(this.chunks, { type: mimeType });
          this.addLog(`SUCCESS: Exported ${finalBlob.size} bytes.`);
          resolve(finalBlob);
        }
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.recorder.start(1000); 

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;
      let lastLogTime = -1;

      try {
        while (currentTime <= duration) {
          // Log heartbeat every 1 second of project time
          if (Math.floor(currentTime) > lastLogTime) {
            this.addLog(`Processing: ${currentTime.toFixed(1)}s / ${duration.toFixed(1)}s`);
            lastLogTime = Math.floor(currentTime);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const clipRelTime = (currentTime - clip.startTime) + clip.offset;
                  await this.seekAndWait(video, clipRelTime);
                  try {
                    this.ctx.drawImage(video, 0, 0, this.width, this.height);
                  } catch (e) {
                    this.addLog(`Canvas Error: Could not draw frame at ${currentTime.toFixed(2)}s. Possibly CORS issue.`);
                  }
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted && !clip.isSilent) {
                  const targetTime = (currentTime - clip.startTime) + clip.offset;
                  audio.currentTime = targetTime;
                  if (audio.paused) await audio.play().catch(() => {});
                }
              } else {
                const audio = audioElements.get(clip.id);
                if (audio && !audio.paused) audio.pause();
              }
            }
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);

          // Yield to UI and allow MediaRecorder to process
          await new Promise(r => setTimeout(r, 0));
        }

        this.addLog("Finishing render sequence...");
        this.recorder.requestData();
        await new Promise(r => setTimeout(r, 1500));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`LOOP EXCEPTION: ${err.message}`);
        this.recorder.stop();
        reject(err);
      }

      // Cleanup
      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 1.0);
  }
}

import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, 
      willReadFrequently: true 
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toISOString().split('T')[1].split('Z')[0];
    const logLine = `[${timestamp}] ${msg}`;
    this.logs.push(logLine);
    console.log(`[ExportEngine] ${logLine}`);
  }

  private async seekWithTimeout(video: HTMLVideoElement, time: number): Promise<boolean> {
    if (Math.abs(video.currentTime - time) < 0.03) return true;

    return new Promise((resolve) => {
      let resolved = false;
      const timeout = setTimeout(() => {
        if (!resolved) {
          resolved = true;
          video.removeEventListener('seeked', onSeeked);
          this.addLog(`⚠️ Seek Timeout: Asset ${video.src.split('/').pop()} skipped at ${time.toFixed(2)}s`);
          resolve(false);
        }
      }, 1500); // 1.5 seconds per frame max wait

      const onSeeked = () => {
        if (!resolved) {
          resolved = true;
          clearTimeout(timeout);
          video.removeEventListener('seeked', onSeeked);
          resolve(true);
        }
      };

      video.addEventListener('seeked', onSeeked);
      try {
        video.currentTime = Math.max(0, Math.min(time, video.duration || 0));
      } catch (e) {
        this.addLog(`❌ Seek Exception: ${e}`);
        resolve(false);
      }
    });
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`INIT: ${this.width}x${this.height} @ ${project.fps}fps`);

    const duration = this.calculateProjectDuration(project);
    this.addLog(`DURATION: ${duration.toFixed(2)}s`);

    // Ensure first frame is drawn BEFORE capture
    this.ctx.fillStyle = '#000000';
    this.ctx.fillRect(0, 0, this.width, this.height);

    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(track => stream.addTrack(track));

    const mimeType = [
      'video/webm;codecs=vp8,opus',
      'video/webm;codecs=vp9,opus',
      'video/webm',
      'video/mp4'
    ].find(type => MediaRecorder.isTypeSupported(type)) || '';

    this.addLog(`CODEC: ${mimeType}`);
    if (!mimeType) throw new Error("No compatible video codec found in this browser.");

    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 10000000 
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`📦 CHUNK: ${e.data.size} bytes captured.`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    this.addLog("STEP 1: Mapping assets...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.crossOrigin = "anonymous";
          a.src = asset.url;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          try {
            const source = this.audioCtx.createMediaElementSource(a);
            source.connect(this.audioDest);
          } catch(e) {
            this.addLog(`⚠️ Audio source error for ${asset.name}`);
          }
        }
      }
    }

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder init failed");

      this.recorder.onstop = () => {
        if (this.chunks.length === 0) {
          this.addLog(`❌ CRITICAL: No data recorded.`);
          reject(new Error("The render process finished but no video data was captured. This is likely due to 'Tainted Canvas' (CORS issues) or the browser suspending the tab. Ensure all assets are loaded from trusted sources with proper headers."));
        } else {
          const finalBlob = new Blob(this.chunks, { type: mimeType });
          this.addLog(`✅ SUCCESS: ${finalBlob.size} bytes ready.`);
          resolve(finalBlob);
        }
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.addLog("STEP 2: Igniting MediaRecorder...");
      this.recorder.start(1000); 

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;
      let lastHeartbeat = -1;

      try {
        while (currentTime <= duration) {
          if (Math.floor(currentTime) > lastHeartbeat) {
            this.addLog(`🚀 Progress: ${currentTime.toFixed(1)}s / ${duration.toFixed(1)}s`);
            lastHeartbeat = Math.floor(currentTime);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const clipRelTime = (currentTime - clip.startTime) + clip.offset;
                  const seekSuccess = await this.seekWithTimeout(video, clipRelTime);
                  if (seekSuccess) {
                    try {
                      this.ctx.drawImage(video, 0, 0, this.width, this.height);
                    } catch (e) {
                      this.addLog(`🛑 SECURITY ERROR: Canvas Tainted. Render blocked by browser.`);
                      throw new Error("Canvas Tainted: One of your assets (video/image) is blocked by browser security (CORS). Export cannot proceed.");
                    }
                  }
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted && !clip.isSilent) {
                  const targetTime = (currentTime - clip.startTime) + clip.offset;
                  audio.currentTime = targetTime;
                  if (audio.paused) await audio.play().catch(() => {});
                }
              } else {
                const audio = audioElements.get(clip.id);
                if (audio && !audio.paused) audio.pause();
              }
            }
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);

          // Technical yield to keep recorder alive
          await new Promise(r => setTimeout(r, 1));
        }

        this.addLog("STEP 3: Finalizing Stream...");
        this.recorder.requestData();
        await new Promise(r => setTimeout(r, 2000));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`❌ EXCEPTION: ${err.message}`);
        this.recorder.stop();
        reject(err);
      }

      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 1.0);
  }
}

import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, 
      willReadFrequently: true 
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toISOString().split('T')[1].split('Z')[0];
    const logLine = `[${timestamp}] ${msg}`;
    this.logs.push(logLine);
    console.log(`[ExportEngine] ${logLine}`);
  }

  private async seekWithTimeout(video: HTMLVideoElement, time: number): Promise<boolean> {
    // If the video is in an error state, don't even try
    if (video.error) {
      this.addLog(`❌ Video Error state: ${video.error.code} for ${video.src.split('/').pop()}`);
      return false;
    }

    if (Math.abs(video.currentTime - time) < 0.04) return true;

    return new Promise((resolve) => {
      let resolved = false;
      const timeout = setTimeout(() => {
        if (!resolved) {
          resolved = true;
          video.removeEventListener('seeked', onSeeked);
          this.addLog(`⚠️ Seek Timeout (${time.toFixed(2)}s). State: RS=${video.readyState}, Net=${video.networkState}`);
          resolve(false);
        }
      }, 2000); 

      const onSeeked = () => {
        if (!resolved) {
          resolved = true;
          clearTimeout(timeout);
          video.removeEventListener('seeked', onSeeked);
          resolve(true);
        }
      };

      video.addEventListener('seeked', onSeeked);
      try {
        video.currentTime = Math.max(0, Math.min(time, video.duration || 0));
      } catch (e) {
        this.addLog(`❌ Seek Exception: ${e}`);
        resolve(false);
      }
    });
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`ENGINE START: ${this.width}x${this.height} @ ${project.fps}fps`);

    const duration = this.calculateProjectDuration(project);
    this.addLog(`TOTAL DURATION: ${duration.toFixed(2)}s`);

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    this.addLog("STEP 1: Initializing & Pre-warming assets...");
    const warmUpPromises: Promise<void>[] = [];

    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);

          warmUpPromises.push(new Promise((res) => {
            const check = () => {
              if (v.readyState >= 3) { // HAVE_FUTURE_DATA
                res();
              } else if (v.error) {
                this.addLog(`❌ Asset Fail: ${asset.name} (Error ${v.error.code})`);
                res();
              } else {
                setTimeout(check, 100);
              }
            };
            check();
            // Safety timeout for pre-warm
            setTimeout(res, 5000);
          }));
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.crossOrigin = "anonymous";
          a.src = asset.url;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          try {
            const source = this.audioCtx.createMediaElementSource(a);
            source.connect(this.audioDest);
          } catch(e) {
            this.addLog(`⚠️ Audio source error for ${asset.name}`);
          }
          warmUpPromises.push(new Promise(res => {
            a.oncanplaythrough = () => res();
            setTimeout(res, 3000);
          }));
        }
      }
    }

    await Promise.all(warmUpPromises);
    this.addLog("Assets pre-warmed. Initializing capture stream...");

    // Setup Canvas and Recorder
    this.ctx.fillStyle = '#000000';
    this.ctx.fillRect(0, 0, this.width, this.height);

    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(track => {
      stream.addTrack(track);
      this.addLog(`Audio Track Attached: ${track.label}`);
    });

    const mimeType = [
      'video/webm;codecs=vp8,opus',
      'video/webm;codecs=vp9,opus',
      'video/webm',
      'video/mp4'
    ].find(type => MediaRecorder.isTypeSupported(type)) || '';

    this.addLog(`RECORDER CONFIG: ${mimeType}`);
    this.recorder = new MediaRecorder(stream, {
      mimeType,
      videoBitsPerSecond: 8000000 
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`📦 Data Chunk: ${e.data.size} bytes. Total chunks: ${this.chunks.length}`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder init failed");

      this.recorder.onstop = () => {
        this.addLog(`Recorder Stopped. Final Chunk Count: ${this.chunks.length}`);
        if (this.chunks.length === 0) {
          reject(new Error("Zero bytes recorded. Browser blocked capture or assets failed to render. Check if the tab was backgrounded or if assets have CORS issues."));
        } else {
          const finalBlob = new Blob(this.chunks, { type: mimeType });
          this.addLog(`✅ Export Successful: ${finalBlob.size} bytes.`);
          resolve(finalBlob);
        }
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.addLog("IGNITION: MediaRecorder started.");
      this.recorder.start(1000); 

      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;
      let lastHeartbeat = -1;

      try {
        while (currentTime <= duration) {
          if (Math.floor(currentTime) > lastHeartbeat) {
            this.addLog(`🎬 Processing: ${currentTime.toFixed(1)}s / ${duration.toFixed(1)}s`);
            lastHeartbeat = Math.floor(currentTime);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          // Clear frame
          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          // Force a tiny visual change to keep some encoders from "optimizing away" static frames
          this.ctx.fillStyle = `rgba(255,255,255,${(Math.random() * 0.01).toFixed(4)})`;
          this.ctx.fillRect(0, 0, 1, 1);

          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const clipRelTime = (currentTime - clip.startTime) + clip.offset;
                  const seekSuccess = await this.seekWithTimeout(video, clipRelTime);

                  if (seekSuccess || video.readyState >= 2) {
                    try {
                      this.ctx.drawImage(video, 0, 0, this.width, this.height);
                    } catch (e) {
                      this.addLog(`🛑 DRAW ERROR: ${e}. Tainted?`);
                    }
                  }
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted && !clip.isSilent) {
                  const targetTime = (currentTime - clip.startTime) + clip.offset;
                  audio.currentTime = targetTime;
                  if (audio.paused) await audio.play().catch(() => {});
                }
              } else {
                const audio = audioElements.get(clip.id);
                if (audio && !audio.paused) audio.pause();
              }
            }
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);

          // Technical yield
          await new Promise(r => setTimeout(r, 5)); 
        }

        this.addLog("Render Loop Complete. Requesting final data...");
        this.recorder.requestData();
        await new Promise(r => setTimeout(r, 2000));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`❌ EXCEPTION: ${err.message}`);
        if (this.recorder.state !== 'inactive') this.recorder.stop();
        reject(err);
      }

      // Cleanup
      videoElements.forEach(v => { v.src = ''; v.load(); });
      audioElements.forEach(a => { a.src = ''; a.load(); });
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 1.0);
  }
}

import { Project, Asset, MediaType } from '../types';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];
  private container: HTMLDivElement | null = null;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    // Some browsers require the canvas to be in the DOM to capture it properly
    this.container = document.createElement('div');
    this.container.style.position = 'fixed';
    this.container.style.top = '-10000px';
    this.container.style.left = '-10000px';
    this.container.style.pointerEvents = 'none';
    this.container.style.opacity = '0';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, 
      willReadFrequently: true 
    });
    if (!context) throw new Error("Could not initialize canvas context");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toISOString().split('T')[1].split('Z')[0];
    const logLine = `[${timestamp}] ${msg}`;
    this.logs.push(logLine);
    console.log(`[ExportEngine] ${logLine}`);
  }

  private async seekWithTimeout(video: HTMLVideoElement, time: number): Promise<boolean> {
    if (video.error) {
      this.addLog(`❌ Video Error: ${video.error.code}`);
      return false;
    }
    if (Math.abs(video.currentTime - time) < 0.04) return true;

    return new Promise((resolve) => {
      let resolved = false;
      const timeout = setTimeout(() => {
        if (!resolved) {
          resolved = true;
          video.removeEventListener('seeked', onSeeked);
          this.addLog(`⚠️ Seek Timeout (${time.toFixed(2)}s). RS=${video.readyState}`);
          resolve(false);
        }
      }, 3000); 

      const onSeeked = () => {
        if (!resolved) {
          resolved = true;
          clearTimeout(timeout);
          video.removeEventListener('seeked', onSeeked);
          resolve(true);
        }
      };

      video.addEventListener('seeked', onSeeked);
      try {
        video.currentTime = Math.max(0, Math.min(time, video.duration || 0));
      } catch (e) {
        resolve(false);
      }
    });
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`🚀 ENGINE BOOT: ${this.width}x${this.height} @ ${project.fps}fps`);
    this.addLog(`Project Duration: ${this.calculateProjectDuration(project).toFixed(2)}s`);

    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    this.addLog("STEP 1: Pre-warming assets...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;
        if (asset.type === MediaType.VIDEO) {
          const v = document.createElement('video');
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else if (asset.type === MediaType.AUDIO) {
          const a = document.createElement('audio');
          a.crossOrigin = "anonymous";
          a.src = asset.url;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          try {
            this.audioCtx.createMediaElementSource(a).connect(this.audioDest);
          } catch(e) {}
        }
      }
    }

    // Capture Setup
    this.ctx.fillStyle = '#000000';
    this.ctx.fillRect(0, 0, this.width, this.height);

    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(t => stream.addTrack(t));

    const mimeType = [
      'video/webm;codecs=vp9,opus',
      'video/webm;codecs=vp8,opus',
      'video/webm',
      'video/mp4'
    ].find(t => MediaRecorder.isTypeSupported(t)) || '';

    this.addLog(`Selected Mime: ${mimeType}`);
    this.recorder = new MediaRecorder(stream, { mimeType, videoBitsPerSecond: 8000000 });
    this.chunks = [];

    this.recorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`📦 Data Received: ${e.data.size} bytes. (Total: ${this.chunks.length} chunks)`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder failed");

      this.recorder.onstop = () => {
        this.addLog(`🛑 Recorder Stop Signal. Chunks: ${this.chunks.length}`);
        if (this.chunks.length === 0) {
          reject(new Error("No data was recorded. This usually means the browser blocked the MediaStream because of CORS or background throttling."));
        } else {
          resolve(new Blob(this.chunks, { type: mimeType }));
        }
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.addLog("STARTING CAPTURE LOOP");
      this.recorder.start(); // No timeslice, we will request data manually

      const duration = this.calculateProjectDuration(project);
      const fps = project.fps;
      const frameDuration = 1 / fps;
      let currentTime = 0;
      let frameCount = 0;

      try {
        while (currentTime <= duration) {
          if (frameCount % fps === 0) {
            this.addLog(`🎬 Heartbeat: ${currentTime.toFixed(1)}s / ${duration.toFixed(1)}s`);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          // Clear & Draw
          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          // Technical "Jitter" to keep encoder awake
          this.ctx.fillStyle = `rgba(255,255,255,0.001)`; 
          this.ctx.fillRect(0,0,1,1);

          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const clipTime = (currentTime - clip.startTime) + clip.offset;
                  await this.seekWithTimeout(video, clipTime);
                  try {
                    this.ctx.drawImage(video, 0, 0, this.width, this.height);
                  } catch (e) {}
                }
              }
            }
          }

          currentTime += frameDuration;
          frameCount++;
          onProgress((currentTime / duration) * 100);

          // Force data request every 30 frames to check health
          if (frameCount % 30 === 0) {
            this.recorder.requestData();
          }

          // Important: Longer yield to give browser room to breathe
          await new Promise(r => setTimeout(r, 10)); 
        }

        this.addLog("Loop finished. Requesting final flush...");
        this.recorder.requestData();
        await new Promise(r => setTimeout(r, 2000));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`❌ Fatal Loop Error: ${err.message}`);
        this.recorder.stop();
        reject(err);
      } finally {
        if (this.container) document.body.removeChild(this.container);
      }
    });
  }

  private calculateProjectDuration(project: Project): number {
    let max = 0;
    project.tracks.forEach(t => {
      t.clips.forEach(c => {
        max = Math.max(max, c.startTime + c.duration);
      });
    });
    return Math.max(max, 1.0);
  }
}

export interface ValidationResult {
  ok: boolean;
  error?: string;
  blobUrl?: string;
}

export class AssetValidator {
  static async validateAndPrefetch(url: string): Promise<ValidationResult> {
    try {
      const response = await fetch(url, { mode: 'cors' });
      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const blob = await response.blob();
      const blobUrl = URL.createObjectURL(blob);

      return { ok: true, blobUrl };
    } catch (err: any) {
      return { 
        ok: false, 
        error: `CORS/Access Error: The server hosting this file does not allow programmatic access. (${err.message})` 
      };
    }
  }
}

import { Project, Asset, MediaType } from '../types';
import { AssetValidator } from './AssetValidator';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];
  private container: HTMLDivElement | null = null;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;opacity:0;pointer-events:none;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      willReadFrequently: true 
    });
    if (!context) throw new Error("Canvas Context Init Failed");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toLocaleTimeString();
    this.logs.push(`[${timestamp}] ${msg}`);
    console.log(`[ExportEngine] ${msg}`);
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`--- STARTING EXPORT PIPELINE v2.0 ---`);
    this.addLog(`Resolution: ${this.width}x${this.height} | FPS: ${project.fps}`);

    const localAssetMap = new Map<string, string>(); // Original ID -> Local Blob URL
    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    // PHASE 1: DIAGNOSTICS & PRE-FETCH
    this.addLog("PHASE 1: Security & CORS Pre-flight check...");
    if (onLogUpdate) onLogUpdate([...this.logs]);

    const uniqueAssetIds = new Set(project.tracks.flatMap(t => t.clips.map(c => c.assetId)));

    for (const assetId of uniqueAssetIds) {
      const asset = assets.find(a => a.id === assetId);
      if (!asset) continue;

      this.addLog(`Checking: ${asset.name}...`);
      const result = await AssetValidator.validateAndPrefetch(asset.url);

      if (!result.ok) {
        this.addLog(`❌ SECURITY BLOCK: ${asset.name}`);
        throw new Error(result.error);
      }

      localAssetMap.set(assetId, result.blobUrl!);
      this.addLog(`✅ Verified: ${asset.name} (Buffered)`);
      if (onLogUpdate) onLogUpdate([...this.logs]);
    }

    // PHASE 2: WARM-UP
    this.addLog("PHASE 2: Mapping Virtual Elements...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const localUrl = localAssetMap.get(clip.assetId);
        if (!localUrl) continue;

        if (track.type === 'video') {
          const v = document.createElement('video');
          v.src = localUrl;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else {
          const a = document.createElement('audio');
          a.src = localUrl;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          try {
            this.audioCtx.createMediaElementSource(a).connect(this.audioDest);
          } catch(e) {}
        }
      }
    }

    // PHASE 3: RECORDER INIT
    const stream = this.canvas.captureStream(0); // 0 means we push frames manually
    this.audioDest.stream.getAudioTracks().forEach(t => stream.addTrack(t));

    const mimeType = ['video/webm;codecs=vp9,opus', 'video/webm;codecs=vp8,opus', 'video/webm'].find(t => MediaRecorder.isTypeSupported(t)) || '';
    this.recorder = new MediaRecorder(stream, { mimeType, videoBitsPerSecond: 12000000 });
    this.chunks = [];

    this.recorder.ondataavailable = (e) => {
      if (e.data.size > 0) {
        this.chunks.push(e.data);
        this.addLog(`📦 Data Chunk: ${e.data.size} bytes captured.`);
        if (onLogUpdate) onLogUpdate([...this.logs]);
      }
    };

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder error");

      this.recorder.onstop = () => {
        if (this.chunks.length === 0) reject(new Error("Zero data recorded."));
        else resolve(new Blob(this.chunks, { type: mimeType }));
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.recorder.start();
      this.addLog("PHASE 4: Frame-by-Frame Render Loop Ignited.");

      const duration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 1);
      const frameDuration = 1 / project.fps;
      let currentTime = 0;

      try {
        while (currentTime <= duration) {
          // 1. CLEAR FRAME
          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          // 2. RENDER CLIPS
          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const seekTime = (currentTime - clip.startTime) + clip.offset;
                  video.currentTime = seekTime;
                  // WAIT FOR FRAME DATA
                  await new Promise((res) => {
                    const onSeeked = () => { video.removeEventListener('seeked', onSeeked); res(true); };
                    video.addEventListener('seeked', onSeeked);
                    setTimeout(res, 1000); // Fail-safe
                  });
                  this.ctx.drawImage(video, 0, 0, this.width, this.height);
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted) {
                  audio.currentTime = (currentTime - clip.startTime) + clip.offset;
                  if (audio.paused) audio.play().catch(() => {});
                }
              }
            }
          }

          // 3. PUSH FRAME TO STREAM
          (stream.getVideoTracks()[0] as any).requestFrame?.();

          // 4. PERIODIC DATA FLUSH (To prevent memory bloat)
          if (Math.round(currentTime * project.fps) % 30 === 0) {
            this.recorder.requestData();
            this.addLog(`Processing: ${currentTime.toFixed(1)}s...`);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);
          await new Promise(r => setTimeout(r, 10)); // Give CPU air
        }

        this.addLog("FINALIZING: Requesting last data flush...");
        this.recorder.requestData();
        await new Promise(r => setTimeout(r, 1000));
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`❌ CRITICAL ERROR: ${err.message}`);
        this.recorder.stop();
        reject(err);
      } finally {
        if (this.container) document.body.removeChild(this.container);
        localAssetMap.forEach(url => URL.revokeObjectURL(url));
      }
    });
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { X, Download, Film, HardDrive, CheckCircle2, AlertCircle, Terminal, Copy, ChevronDown, ChevronUp } from 'lucide-react';
import { Project, Asset } from '../../types';
import { ExportEngine } from '../../services/ExportEngine';

interface ExportModalProps {
  onClose: () => void;
  project: Project;
  assets: Asset[];
}

export const ExportModal: React.FC<ExportModalProps> = ({ onClose, project, assets }) => {
  const [step, setStep] = useState<'settings' | 'exporting' | 'finished'>('settings');
  const [progress, setProgress] = useState(0);
  const [filename, setFilename] = useState(project.name.toLowerCase().replace(/\s+/g, '_') || 'nexus_export');
  const [exportBlob, setExportBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [logs, setLogs] = useState<string[]>([]);
  const [showLogs, setShowLogs] = useState(false);
  const logEndRef = useRef<HTMLDivElement>(null);

  const [config, setConfig] = useState({
    format: 'MP4', 
    resolution: '1280x720', 
    quality: 'Balanced'
  });

  useEffect(() => {
    if (logEndRef.current) logEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const startExport = async () => {
    setStep('exporting');
    setProgress(0);
    setError(null);
    setLogs([]);
    setShowLogs(true); // Always show logs during export in v2 for transparency

    try {
      const [width, height] = config.resolution.split('x').map(Number);
      const engine = new ExportEngine(width, height);

      const blob = await engine.render(
        project, 
        assets, 
        (p) => setProgress(Math.min(99, p)),
        (newLogs) => setLogs(newLogs)
      );

      setExportBlob(blob);
      setStep('finished');
      setShowLogs(false);
    } catch (err: any) {
      setError(err.message || "Export failed.");
      setStep('settings');
    }
  };

  const handleDownloadMaster = () => {
    if (!exportBlob) return;
    const url = URL.createObjectURL(exportBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${filename}.webm`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="fixed inset-0 bg-black/95 z-[300] flex items-center justify-center p-6 animate-in fade-in duration-200">
      <div className="bg-[#0f0f0f] border border-zinc-800 w-full max-w-4xl h-[720px] rounded-3xl shadow-2xl flex flex-col overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-zinc-800 flex items-center justify-between bg-[#141414]">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Download size={20} />
            </div>
            <div>
              <h2 className="text-lg font-black tracking-tight uppercase italic">Nexus Render Engine v2.0</h2>
              <p className="text-[10px] text-zinc-500 font-bold tracking-widest uppercase">Diagnostic Output Mode</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-zinc-800 rounded-full text-zinc-500 hover:text-white"><X size={24} /></button>
        </div>

        <div className="flex-1 flex min-h-0 bg-[#0a0a0a] relative">
          {step === 'settings' && (
            <div className="flex w-full">
              <div className="w-2/3 p-8 border-r border-zinc-800">
                <div className="w-full aspect-video bg-zinc-900 rounded-2xl border border-zinc-800 flex flex-col items-center justify-center mb-6">
                  {error ? (
                    <div className="text-center p-6">
                      <AlertCircle size={40} className="text-red-500 mb-4 mx-auto" />
                      <h4 className="text-red-500 font-black uppercase text-sm mb-2">Export Terminated</h4>
                      <p className="text-xs text-zinc-400 max-w-sm">{error}</p>
                    </div>
                  ) : (
                    <Film className="text-zinc-800" size={64} />
                  )}
                </div>
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 block mb-2">Filename</label>
                <input 
                  type="text" 
                  value={filename}
                  onChange={(e) => setFilename(e.target.value)}
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-5 py-4 text-sm font-bold outline-none mb-4"
                />
              </div>
              <div className="w-1/3 p-8 bg-[#121212] flex flex-col">
                <label className="text-[10px] font-black uppercase tracking-widest text-zinc-500 block mb-4">Output Format</label>
                <div className="space-y-2 mb-auto">
                   {['1920x1080', '1280x720'].map(res => (
                     <button key={res} onClick={() => setConfig({...config, resolution: res})} className={`w-full px-4 py-3 rounded-xl border text-[11px] font-bold text-left flex justify-between items-center ${config.resolution === res ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}>
                       {res} {res === '1920x1080' ? '(Full HD)' : '(HD)'}
                       {config.resolution === res && <CheckCircle2 size={14} />}
                     </button>
                   ))}
                </div>
                <button onClick={startExport} className="w-full bg-white text-black font-black uppercase tracking-widest py-5 rounded-2xl flex items-center justify-center gap-3">
                  <Download size={18} /> Run Diagnostics & Export
                </button>
              </div>
            </div>
          )}

          {(step === 'exporting' || showLogs) && (
            <div className="absolute inset-0 z-50 flex flex-col bg-black">
              <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900">
                <div className="flex items-center gap-2 text-indigo-400 font-mono text-[10px] font-bold">
                  <Terminal size={14}/> ENGINE_LOG_STREAM :: {Math.floor(progress)}%
                </div>
                <button onClick={() => setStep('settings')} className="text-[10px] font-black text-red-500">ABORT</button>
              </div>
              <div className="flex-1 overflow-y-auto p-6 font-mono text-[11px] text-zinc-400 custom-scrollbar">
                {logs.map((log, i) => (
                  <div key={i} className="mb-1">
                    <span className="text-zinc-700 mr-4">{i.toString().padStart(4, '0')}</span>
                    <span className={log.includes('❌') || log.includes('ERROR') ? 'text-red-400' : log.includes('✅') ? 'text-green-400' : ''}>{log}</span>
                  </div>
                ))}
                <div ref={logEndRef} />
              </div>
              {step === 'exporting' && (
                <div className="p-1 bg-zinc-800">
                  <div className="h-1 bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }} />
                </div>
              )}
            </div>
          )}

          {step === 'finished' && (
            <div className="w-full flex flex-col items-center justify-center p-20 animate-in zoom-in-95">
               <div className="w-20 h-20 bg-green-500/10 text-green-500 rounded-full flex items-center justify-center mb-8 border border-green-500/20">
                  <CheckCircle2 size={40} />
               </div>
               <h3 className="text-2xl font-black mb-2 uppercase italic text-white">Export Validated</h3>
               <p className="text-zinc-500 mb-12 text-center text-sm">The media pipeline successfully rendered the composition.</p>
               <div className="flex gap-4">
                 <button onClick={onClose} className="px-10 py-4 bg-zinc-800 rounded-xl font-black uppercase text-[10px] tracking-widest">Close</button>
                 <button onClick={handleDownloadMaster} className="px-10 py-4 bg-indigo-600 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-3">
                   <Download size={18} /> Download Master File
                 </button>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import { Project, Asset, MediaType } from '../types';
import { AssetValidator } from './AssetValidator';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];
  private container: HTMLDivElement | null = null;
  private selectedMime: string = '';

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;opacity:0;pointer-events:none;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    const context = this.canvas.getContext('2d', { 
      alpha: false,
      desynchronized: false, // Set to false for cleaner frames in video
      willReadFrequently: true 
    });
    if (!context) throw new Error("Canvas Context Init Failed");
    this.ctx = context;

    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 48000 });
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toLocaleTimeString();
    this.logs.push(`[${timestamp}] ${msg}`);
    console.log(`[ExportEngine] ${msg}`);
  }

  public getExtension(): string {
    if (this.selectedMime.includes('mp4')) return 'mp4';
    return 'webm';
  }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.logs = [];
    this.addLog(`--- MASTER RENDER ENGINE v2.1 ---`);
    this.addLog(`Target: ${this.width}x${this.height} @ ${project.fps}fps`);

    const localAssetMap = new Map<string, string>(); 
    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    // PHASE 1: PRE-FETCH (No CORS issues)
    this.addLog("PHASE 1: Asset Pre-fetch & Memory Buffering...");
    if (onLogUpdate) onLogUpdate([...this.logs]);

    const uniqueAssetIds = new Set(project.tracks.flatMap(t => t.clips.map(c => c.assetId)));
    for (const assetId of uniqueAssetIds) {
      const asset = assets.find(a => a.id === assetId);
      if (!asset) continue;
      const result = await AssetValidator.validateAndPrefetch(asset.url);
      if (!result.ok) throw new Error(`Asset Failed: ${asset.name}`);
      localAssetMap.set(assetId, result.blobUrl!);
      this.addLog(`✅ Ready: ${asset.name}`);
      if (onLogUpdate) onLogUpdate([...this.logs]);
    }

    // PHASE 2: SETUP
    this.addLog("PHASE 2: Engine Warm-up...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const localUrl = localAssetMap.get(clip.assetId);
        if (!localUrl) continue;
        if (track.type === 'video') {
          const v = document.createElement('video');
          v.src = localUrl;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else {
          const a = document.createElement('audio');
          a.src = localUrl;
          a.preload = "auto";
          audioElements.set(clip.id, a);
          try { this.audioCtx.createMediaElementSource(a).connect(this.audioDest); } catch(e) {}
        }
      }
    }

    // PHASE 3: RECORDER SETUP (Prioritize H264 for MP4)
    this.selectedMime = [
      'video/mp4;codecs=avc1',
      'video/mp4',
      'video/webm;codecs=vp9,opus',
      'video/webm;codecs=vp8,opus',
      'video/webm'
    ].find(t => MediaRecorder.isTypeSupported(t)) || '';

    this.addLog(`Selected Codec: ${this.selectedMime}`);

    // Use a steady captureStream for smooth FPS
    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(t => stream.addTrack(t));

    this.recorder = new MediaRecorder(stream, { 
      mimeType: this.selectedMime,
      videoBitsPerSecond: 25000000 // High bitrate (25Mbps) for master quality
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => {
      if (e.data.size > 0) this.chunks.push(e.data);
    };

    return new Promise(async (resolve, reject) => {
      if (!this.recorder) return reject("Recorder init failed");

      this.recorder.onstop = () => {
        if (this.chunks.length === 0) reject(new Error("Zero data recorded."));
        else resolve(new Blob(this.chunks, { type: this.selectedMime }));
      };

      if (this.audioCtx.state === 'suspended') await this.audioCtx.resume();

      this.recorder.start();
      this.addLog("PHASE 4: Sequential Frame Synthesis...");

      const duration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 1);
      const frameDuration = 1 / project.fps;
      let currentTime = 0;

      try {
        while (currentTime <= duration) {
          // Clear Frame
          this.ctx.fillStyle = '#000000';
          this.ctx.fillRect(0, 0, this.width, this.height);

          // Render Elements for this frame
          for (const track of project.tracks) {
            if (!track.isVisible) continue;
            for (const clip of track.clips) {
              if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
                const video = videoElements.get(clip.id);
                if (video) {
                  const seekTime = (currentTime - clip.startTime) + clip.offset;
                  video.currentTime = seekTime;

                  // SYNC WAIT: Ensure GPU actually has the frame data
                  await new Promise((res) => {
                    const onSeeked = () => {
                      video.removeEventListener('seeked', onSeeked);
                      // One more rAF for GPU texture upload safety
                      requestAnimationFrame(() => requestAnimationFrame(res));
                    };
                    video.addEventListener('seeked', onSeeked);
                    setTimeout(res, 1000); 
                  });

                  this.ctx.drawImage(video, 0, 0, this.width, this.height);
                }
                const audio = audioElements.get(clip.id);
                if (audio && !track.isMuted) {
                  audio.currentTime = (currentTime - clip.startTime) + clip.offset;
                  if (audio.paused) audio.play().catch(() => {});
                }
              } else {
                const audio = audioElements.get(clip.id);
                if (audio && !audio.paused) audio.pause();
              }
            }
          }

          // Heartbeat log
          if (Math.round(currentTime * project.fps) % (project.fps * 2) === 0) {
            this.addLog(`Syncing frame at ${currentTime.toFixed(1)}s...`);
            if (onLogUpdate) onLogUpdate([...this.logs]);
          }

          currentTime += frameDuration;
          onProgress((currentTime / duration) * 100);

          // Technical Wait: Allow the recorder and UI to breathe
          await new Promise(r => setTimeout(r, 16)); 
        }

        this.addLog("COMPLETED. Wrapping container...");
        this.recorder.stop();

      } catch (err: any) {
        this.addLog(`❌ ERROR: ${err.message}`);
        this.recorder.stop();
        reject(err);
      } finally {
        if (this.container) document.body.removeChild(this.container);
        localAssetMap.forEach(url => URL.revokeObjectURL(url));
      }
    });
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { X, Download, Film, HardDrive, CheckCircle2, AlertCircle, Terminal, Copy, ChevronDown, ChevronUp } from 'lucide-react';
import { Project, Asset } from '../../types';
