import { Project, Asset } from '../types';
import { AssetValidator } from './AssetValidator';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private audioCtx: AudioContext;
  private audioDest: MediaStreamAudioDestinationNode;
  private recorder: MediaRecorder | null = null;
  private chunks: Blob[] = [];
  private logs: string[] = [];
  private container: HTMLDivElement | null = null;
  private selectedMime: string = '';
  private isRunning: boolean = false;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;opacity:0;pointer-events:none;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    this.ctx = this.canvas.getContext('2d', { alpha: false })!;
    this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 44100 });
    this.audioDest = this.audioCtx.createMediaStreamDestination();
  }

  private addLog(msg: string) {
    const timestamp = new Date().toLocaleTimeString();
    this.logs.push(`[${timestamp}] ${msg}`);
  }

  public getExtension() { return 'webm'; }

  async render(
    project: Project, 
    assets: Asset[], 
    onProgress: (p: number) => void,
    onLogUpdate?: (logs: string[]) => void
  ): Promise<Blob> {
    this.isRunning = true;
    this.addLog("Initializing High-Efficiency Render...");
    if (onLogUpdate) onLogUpdate([...this.logs]);

    // PRE-FETCH ASSETS (Essential for smooth playback)
    const localAssetMap = new Map<string, string>();
    const videoElements = new Map<string, HTMLVideoElement>();
    const audioElements = new Map<string, HTMLAudioElement>();

    const uniqueAssetIds = new Set(project.tracks.flatMap(t => t.clips.map(c => c.assetId)));
    for (const id of uniqueAssetIds) {
      const asset = assets.find(a => a.id === id);
      if (!asset) continue;
      const res = await AssetValidator.validateAndPrefetch(asset.url);
      if (res.ok) localAssetMap.set(id, res.blobUrl!);
    }

    // PREPARE ELEMENTS
    project.tracks.forEach(track => {
      track.clips.forEach(clip => {
        const url = localAssetMap.get(clip.assetId);
        if (!url) return;
        if (track.type === 'video') {
          const v = document.createElement('video');
          v.src = url;
          v.muted = true;
          v.preload = "auto";
          videoElements.set(clip.id, v);
        } else {
          const a = document.createElement('audio');
          a.src = url;
          audioElements.set(clip.id, a);
          try { this.audioCtx.createMediaElementSource(a).connect(this.audioDest); } catch(e) {}
        }
      });
    });

    this.selectedMime = 'video/webm;codecs=vp8,opus';
    const stream = this.canvas.captureStream(project.fps);
    this.audioDest.stream.getAudioTracks().forEach(t => stream.addTrack(t));

    this.recorder = new MediaRecorder(stream, { 
      mimeType: this.selectedMime,
      videoBitsPerSecond: 8000000 // 8Mbps - High quality but efficient
    });

    this.chunks = [];
    this.recorder.ondataavailable = (e) => this.chunks.push(e.data);

    return new Promise((resolve, reject) => {
      this.recorder!.onstop = () => {
        const blob = new Blob(this.chunks, { type: this.selectedMime });
        this.isRunning = false;
        resolve(blob);
      };

      const duration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 1);
      let startTime = performance.now();

      this.recorder!.start();
      this.addLog(`Recording started. Target duration: ${duration.toFixed(1)}s`);
      if (onLogUpdate) onLogUpdate([...this.logs]);

      const renderFrame = () => {
        if (!this.isRunning) return;

        const elapsed = (performance.now() - startTime) / 1000;
        if (elapsed >= duration) {
          this.recorder!.stop();
          this.addLog("Capture complete.");
          if (onLogUpdate) onLogUpdate([...this.logs]);
          return;
        }

        // Draw background
        this.ctx.fillStyle = '#000000';
        this.ctx.fillRect(0, 0, this.width, this.height);

        // Draw active clips
        project.tracks.forEach(track => {
          if (!track.isVisible) return;
          track.clips.forEach(clip => {
            if (elapsed >= clip.startTime && elapsed <= clip.startTime + clip.duration) {
              const video = videoElements.get(clip.id);
              if (video) {
                const playTime = (elapsed - clip.startTime) + clip.offset;
                if (Math.abs(video.currentTime - playTime) > 0.1) video.currentTime = playTime;
                if (video.paused) video.play().catch(() => {});
                this.ctx.drawImage(video, 0, 0, this.width, this.height);
              }
              const audio = audioElements.get(clip.id);
              if (audio && !track.isMuted) {
                const audioTime = (elapsed - clip.startTime) + clip.offset;
                if (Math.abs(audio.currentTime - audioTime) > 0.1) audio.currentTime = audioTime;
                if (audio.paused) audio.play().catch(() => {});
              }
            } else {
              videoElements.get(clip.id)?.pause();
              audioElements.get(clip.id)?.pause();
            }
          });
        });

        onProgress((elapsed / duration) * 100);
        requestAnimationFrame(renderFrame);
      };

      requestAnimationFrame(renderFrame);
    });
  }
}

