import { Project, Asset } from '../types';
import { Muxer, ArrayBufferTarget } from 'mp4-muxer';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private container: HTMLDivElement | null = null;
  private videoElements: Map<string, HTMLVideoElement> = new Map();
  private isRendering: boolean = false;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;width:1px;height:1px;overflow:hidden;opacity:0;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    this.ctx = this.canvas.getContext('2d', { alpha: false, willReadFrequently: true })!;
    console.log(`[ExportEngine] Initialized for WebCodecs MP4 at ${width}x${height}`);
  }

  private async prepareAssets(project: Project, assets: Asset[]) {
    console.log("[ExportEngine] Validating assets with CORS visibility...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset) continue;

        if (asset.type === 'VIDEO') {
          const v = document.createElement('video');
          // CRITICAL: Set crossOrigin BEFORE src
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          v.muted = true;
          v.preload = "auto";
          this.container?.appendChild(v);
          this.videoElements.set(clip.id, v);

          await new Promise((resolve) => {
            v.onloadedmetadata = () => resolve(true);
            v.onerror = (e) => {
              console.error(`[ExportEngine] CORS or Load Failure for ${asset.name}`, e);
              resolve(false);
            };
            // Safety timeout
            setTimeout(resolve, 5000);
          });
        }
      }
    }
  }

  private cleanup() {
    this.videoElements.forEach(v => {
      v.pause();
      v.src = "";
      v.load();
      v.remove();
    });
    this.videoElements.clear();
    if (this.container) {
      document.body.removeChild(this.container);
      this.container = null;
    }
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    if (!window.VideoEncoder) {
      throw new Error("WebCodecs (VideoEncoder) is not supported in this browser. Please use a modern version of Chrome.");
    }

    this.isRendering = true;
    const projectDuration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 0.1);
    const fps = 30;
    const totalFrames = Math.ceil(projectDuration * fps);

    await this.prepareAssets(project, assets);

    // Initialize mp4-muxer
    const muxer = new Muxer({
      target: new ArrayBufferTarget(),
      video: {
        codec: 'avc',
        width: this.width,
        height: this.height
      },
      fastStart: 'in-memory'
    });

    // Initialize VideoEncoder
    const videoEncoder = new VideoEncoder({
      output: (chunk, metadata) => muxer.addVideoChunk(chunk, metadata),
      error: (e) => console.error("[ExportEngine] VideoEncoder error:", e)
    });

    const config: VideoEncoderConfig = {
      codec: 'avc1.42E01E', // Baseline profile for maximum compatibility
      width: this.width,
      height: this.height,
      bitrate: 5_000_000, // 5 Mbps
      framerate: fps,
    };
    videoEncoder.configure(config);

    console.log(`[ExportEngine] Encoding ${totalFrames} frames using WebCodecs...`);

    // Faster than real-time rendering loop
    for (let frame = 0; frame <= totalFrames; frame++) {
      if (!this.isRendering) break;

      const timestamp = frame / fps;
      const timestampMicros = timestamp * 1_000_000;

      // Draw frame to canvas
      this.ctx.fillStyle = '#000000';
      this.ctx.fillRect(0, 0, this.width, this.height);

      for (const track of project.tracks) {
        if (!track.isVisible || track.type !== 'video') continue;
        for (const clip of track.clips) {
          if (timestamp >= clip.startTime && timestamp <= clip.startTime + clip.duration) {
            const video = this.videoElements.get(clip.id);
            if (video) {
              const targetTime = (timestamp - clip.startTime) + clip.offset;

              // We need to seek the video to the specific frame
              video.currentTime = targetTime;

              // Wait for seek to complete (this makes the loop "async-serial")
              await new Promise(resolve => {
                const onSeek = () => {
                  video.removeEventListener('seeked', onSeek);
                  resolve(true);
                };
                video.addEventListener('seeked', onSeek);
                // Fallback for very small seeks
                setTimeout(resolve, 20);
              });

              this.ctx.drawImage(video, 0, 0, this.width, this.height);
            }
          }
        }
      }

      // Encode frame
      const bitmap = await createImageBitmap(this.canvas);
      const videoFrame = new VideoFrame(bitmap, { timestamp: timestampMicros });
      videoEncoder.encode(videoFrame, { keyFrame: frame % 30 === 0 });
      videoFrame.close();
      bitmap.close();

      onProgress((frame / totalFrames) * 100);

      // Yield every 10 frames to keep UI responsive
      if (frame % 10 === 0) {
        await new Promise(r => setTimeout(r, 0));
      }
    }

    await videoEncoder.flush();
    muxer.finalize();

    this.cleanup();
    this.isRendering = false;

    const { buffer } = muxer.target as ArrayBufferTarget;
    return new Blob([buffer], { type: 'video/mp4' });
  }
}

import { Asset, MediaType } from '../types';

export class AssetService {
  static async processFile(file: File): Promise<Asset> {
    const url = URL.createObjectURL(file);
    const type = file.type.startsWith('video/') ? MediaType.VIDEO : 
                 file.type.startsWith('audio/') ? MediaType.AUDIO : 
                 MediaType.IMAGE;

    let duration = 0;
    let thumbnail = '';
    let waveform: number[] | undefined = undefined;

    try {
      if (type === MediaType.VIDEO || type === MediaType.AUDIO) {
        duration = await Promise.race([
          this.getMediaDuration(url),
          new Promise<number>((_, reject) => setTimeout(() => reject('Timeout'), 5000))
        ]).catch(() => (type === MediaType.VIDEO ? 10 : 0));

        if (type === MediaType.VIDEO) {
          thumbnail = await this.generateThumbnail(url).catch(() => '');
        }

        waveform = await this.extractWaveform(url, 1000).catch(err => {
          console.warn("Waveform extraction failed", err);
          return undefined;
        });
      } else if (type === MediaType.IMAGE) {
        duration = 5;
        thumbnail = url;
      }
    } catch (e) {
      console.error("Asset processing failed", e);
    }

    return {
      id: `asset-${Math.random().toString(36).substr(2, 9)}`,
      name: file.name,
      type,
      url,
      duration: duration || 5,
      thumbnail,
      waveform
    };
  }

  private static async extractWaveform(url: string, samples = 1000): Promise<number[]> {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);

    const channelData = audioBuffer.getChannelData(0);
    const blockSize = Math.floor(channelData.length / samples);
    const waveform: number[] = [];

    for (let i = 0; i < samples; i++) {
      let max = 0;
      for (let j = 0; j < blockSize; j++) {
        const val = Math.abs(channelData[i * blockSize + j]);
        if (val > max) max = val;
      }
      waveform.push(Math.min(1, max * 1.5)); 
    }

    await audioCtx.close();
    return waveform;
  }

  private static getMediaDuration(url: string): Promise<number> {
    return new Promise((resolve) => {
      const media = document.createElement('video');
      media.preload = 'metadata';
      media.src = url;
      media.onloadedmetadata = () => resolve(media.duration);
      media.onerror = () => resolve(0);
    });
  }

  private static generateThumbnail(url: string): Promise<string> {
    return new Promise((resolve) => {
      const video = document.createElement('video');
      video.crossOrigin = "anonymous"; // CRITICAL
      video.preload = 'metadata';
      video.src = url;
      video.muted = true;
      video.currentTime = 0.5;
      video.onseeked = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 160;
        canvas.height = 90;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg'));
      };
      video.onerror = () => resolve('');
    });
  }
}

import { Project, Asset } from '../types';
import * as Mp4Muxer from 'mp4-muxer';
import { AssetValidator } from './AssetValidator';

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private container: HTMLDivElement | null = null;
  private videoElements: Map<string, HTMLVideoElement> = new Map();
  private blobUrls: string[] = [];
  private isRendering: boolean = false;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;width:1px;height:1px;overflow:hidden;opacity:0;pointer-events:none;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    this.ctx = this.canvas.getContext('2d', { alpha: false, willReadFrequently: true })!;
    console.log(`[ExportEngine] Initialized for WebCodecs at ${width}x${height}`);
  }

  private async prepareAssets(project: Project, assets: Asset[]) {
    console.log("[ExportEngine] Pre-fetching assets with CORS validation...");

    for (const track of project.tracks) {
      for (const clip of track.clips) {
        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset || asset.type !== 'VIDEO') continue;

        const v = document.createElement('video');
        v.muted = true;
        v.preload = "auto";

        // Attempt pre-fetch to get around CORS tainting if possible
        const validation = await AssetValidator.validateAndPrefetch(asset.url);
        if (validation.ok && validation.blobUrl) {
          v.src = validation.blobUrl;
          this.blobUrls.push(validation.blobUrl);
          console.log(`[ExportEngine] Loaded via Blob: ${asset.name}`);
        } else {
          // Fallback to anonymous if CORS pre-fetch failed (might still fail on draw)
          v.crossOrigin = "anonymous";
          v.src = asset.url;
          console.warn(`[ExportEngine] CORS pre-fetch failed for ${asset.name}. Falling back to anonymous loading.`);
        }

        this.container?.appendChild(v);
        this.videoElements.set(clip.id, v);

        await new Promise((resolve) => {
          v.onloadedmetadata = () => resolve(true);
          v.onerror = (e) => {
            console.error(`[ExportEngine] Error loading video ${asset.name}`, e);
            resolve(false);
          };
          setTimeout(resolve, 5000); // 5s timeout
        });
      }
    }
  }

  private cleanup() {
    this.videoElements.forEach(v => {
      v.pause();
      v.src = "";
      v.load();
      v.remove();
    });
    this.videoElements.clear();
    this.blobUrls.forEach(url => URL.revokeObjectURL(url));
    this.blobUrls = [];

    if (this.container) {
      document.body.removeChild(this.container);
      this.container = null;
    }
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    if (!window.VideoEncoder) {
      throw new Error("WebCodecs is not supported. Please use a Chromium-based browser (Chrome, Edge).");
    }

    this.isRendering = true;
    const projectDuration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 0.1);
    const fps = 30;
    const totalFrames = Math.ceil(projectDuration * fps);

    await this.prepareAssets(project, assets);

    const muxer = new Mp4Muxer.Muxer({
      target: new Mp4Muxer.ArrayBufferTarget(),
      video: {
        codec: 'avc',
        width: this.width,
        height: this.height
      },
      fastStart: 'in-memory'
    });

    const videoEncoder = new VideoEncoder({
      output: (chunk, metadata) => muxer.addVideoChunk(chunk, metadata),
      error: (e) => console.error("[ExportEngine] VideoEncoder fatal error:", e)
    });

    videoEncoder.configure({
      codec: 'avc1.42E01E', 
      width: this.width,
      height: this.height,
      bitrate: 5000000, 
      framerate: fps,
    });

    for (let frame = 0; frame <= totalFrames; frame++) {
      if (!this.isRendering) break;

      const timestampSeconds = frame / fps;
      const timestampMicros = timestampSeconds * 1000000;

      this.ctx.fillStyle = '#000000';
      this.ctx.fillRect(0, 0, this.width, this.height);

      for (const track of project.tracks) {
        if (!track.isVisible || track.type !== 'video') continue;
        for (const clip of track.clips) {
          if (timestampSeconds >= clip.startTime && timestampSeconds <= clip.startTime + clip.duration) {
            const video = this.videoElements.get(clip.id);
            if (video) {
              const targetTime = (timestampSeconds - clip.startTime) + clip.offset;
              video.currentTime = targetTime;

              await new Promise(resolve => {
                const onSeek = () => {
                  video.removeEventListener('seeked', onSeek);
                  resolve(true);
                };
                video.addEventListener('seeked', onSeek);
                setTimeout(resolve, 50); // Seek safety margin
              });

              try {
                this.ctx.drawImage(video, 0, 0, this.width, this.height);
              } catch (drawError) {
                console.warn(`[ExportEngine] Drawing failed for clip ${clip.id}. This is usually a CORS issue.`, drawError);
              }
            }
          }
        }
      }

      const bitmap = await createImageBitmap(this.canvas);
      const videoFrame = new VideoFrame(bitmap, { timestamp: timestampMicros });
      videoEncoder.encode(videoFrame, { keyFrame: frame % 30 === 0 });
      videoFrame.close();
      bitmap.close();

      onProgress((frame / totalFrames) * 100);
      if (frame % 5 === 0) await new Promise(r => setTimeout(r, 0));
    }

    await videoEncoder.flush();
    muxer.finalize();

    this.cleanup();
    this.isRendering = false;

    const { buffer } = muxer.target as Mp4Muxer.ArrayBufferTarget;
    return new Blob([buffer], { type: 'video/mp4' });
  }
}

import { Project, Asset } from '../types';

export class ErrorReportingService {
  private static logs: string[] = [];
  private static originalConsoleLog = console.log;
  private static originalConsoleError = console.error;
  private static originalConsoleWarn = console.warn;

  static init() {
    try {
      const capture = (type: string, args: any[]) => {
        const msg = args.map(arg => 
          typeof arg === 'object' ? JSON.stringify(arg) : String(arg)
        ).join(' ');
        this.logs.push(`[${type}] ${new Date().toISOString()}: ${msg}`);
      };

      console.log = (...args) => {
        capture('LOG', args);
        this.originalConsoleLog.apply(console, args);
      };
      console.error = (...args) => {
        capture('ERROR', args);
        this.originalConsoleError.apply(console, args);
      };
      console.warn = (...args) => {
        capture('WARN', args);
        this.originalConsoleWarn.apply(console, args);
      };

      window.addEventListener('unhandledrejection', (event) => {
        this.logs.push(`[PROMISE_ERROR] ${new Date().toISOString()}: ${event.reason}`);
      });

      window.onerror = (msg, url, line, col, error) => {
        this.logs.push(`[RUNTIME_ERROR] ${new Date().toISOString()}: ${msg} at ${line}:${col}`);
      };
    } catch (e) {
      console.error("ErrorReportingService failed to initialize", e);
    }
  }

  static getMimeSupportReport() {
    const types = [
      'video/mp4',
      'video/mp4;codecs=avc1',
      'video/mp4;codecs=h264',
      'video/webm',
      'video/webm;codecs=vp9',
      'video/webm;codecs=vp8',
      'audio/webm;codecs=opus',
      'audio/mp4'
    ];
    const report: Record<string, boolean> = {};

    // Check if MediaRecorder exists before calling it
    if (typeof MediaRecorder !== 'undefined' && MediaRecorder.isTypeSupported) {
      types.forEach(t => {
        try {
          report[t] = MediaRecorder.isTypeSupported(t);
        } catch (e) {
          report[t] = false;
        }
      });
    } else {
      report['MediaRecorder'] = false;
    }

    return report;
  }

  static generateFullReport(project: Project, assets: Asset[]) {
    const performanceData = (performance as any).memory ? {
      jsHeapSizeLimit: (performance as any).memory.jsHeapSizeLimit / (1024 * 1024),
      totalJSHeapSize: (performance as any).memory.totalJSHeapSize / (1024 * 1024),
      usedJSHeapSize: (performance as any).memory.usedJSHeapSize / (1024 * 1024),
    } : 'Memory API not available';

    const report = {
      reportType: "NEXUS_STUDIO_DIAGNOSTIC_v3",
      timestamp: new Date().toISOString(),
      environment: {
        userAgent: navigator.userAgent,
        language: navigator.language,
        hardwareConcurrency: navigator.hardwareConcurrency,
        deviceMemory: (navigator as any).deviceMemory || 'unknown',
        performance: performanceData,
        mimeSupport: this.getMimeSupportReport(),
        webCodecsSupport: typeof VideoEncoder !== 'undefined'
      },
      projectState: project,
      assetManifest: assets.map(a => ({
        id: a.id,
        name: a.name,
        type: a.type,
        urlPrefix: a.url.substring(0, 30),
        duration: a.duration
      })),
      activityLogs: this.logs
    };

    const reportStr = JSON.stringify(report, null, 2);
    const blob = new Blob([reportStr], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `nexus_diagnostic_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

    return reportStr;
  }
}

