import { Project, Asset } from '../types';

// Declare global Mp4Muxer as provided by the script tag in index.html
declare var Mp4Muxer: any;

export class ExportEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private container: HTMLDivElement | null = null;
  private videoElements: Map<string, HTMLVideoElement> = new Map();
  private isRendering: boolean = false;

  constructor(private width: number, private height: number) {
    this.canvas = document.createElement('canvas');
    this.canvas.width = width;
    this.canvas.height = height;

    this.container = document.createElement('div');
    this.container.style.cssText = 'position:fixed;top:-10000px;left:-10000px;width:1px;height:1px;overflow:hidden;opacity:0;';
    this.container.appendChild(this.canvas);
    document.body.appendChild(this.container);

    this.ctx = this.canvas.getContext('2d', { alpha: false, willReadFrequently: true })!;
    console.log(`[ExportEngine] Initialized for High-Quality MP4 at ${width}x${height}`);
  }

  private async prepareAssets(project: Project, assets: Asset[]) {
    console.log("[ExportEngine] Preparing source assets with CORS support...");
    for (const track of project.tracks) {
      for (const clip of track.clips) {
        if (this.videoElements.has(clip.id)) continue;

        const asset = assets.find(a => a.id === clip.assetId);
        if (!asset || asset.type !== 'VIDEO') continue;

        const v = document.createElement('video');
        // CRITICAL: Set crossOrigin BEFORE setting src
        v.crossOrigin = "anonymous";
        v.src = asset.url;
        v.muted = true;
        v.preload = "auto";
        this.container?.appendChild(v);
        this.videoElements.set(clip.id, v);

        await new Promise((resolve) => {
          v.onloadedmetadata = () => resolve(true);
          v.onerror = (e) => {
            console.error(`[ExportEngine] Asset Load Error for ${asset.name}`, e);
            resolve(false);
          };
          setTimeout(resolve, 5000); // 5s timeout
        });
      }
    }
  }

  private cleanup() {
    this.videoElements.forEach(v => {
      v.pause();
      v.src = "";
      v.load();
      v.remove();
    });
    this.videoElements.clear();
    if (this.container) {
      document.body.removeChild(this.container);
      this.container = null;
    }
  }

  async render(project: Project, assets: Asset[], onProgress: (p: number) => void): Promise<Blob> {
    if (!window.VideoEncoder) {
      throw new Error("VideoEncoder (WebCodecs) is not supported in this browser. Please use a modern version of Chrome.");
    }
    if (typeof Mp4Muxer === 'undefined') {
      throw new Error("MP4 Muxer library failed to load.");
    }

    this.isRendering = true;
    const projectDuration = Math.max(...project.tracks.flatMap(t => t.clips.map(c => c.startTime + c.duration)), 0.1);
    const fps = 30;
    const totalFrames = Math.ceil(projectDuration * fps);

    await this.prepareAssets(project, assets);

    // Initialize Muxer
    const muxerTarget = new Mp4Muxer.ArrayBufferTarget();
    const muxer = new Mp4Muxer.Muxer({
      target: muxerTarget,
      video: {
        codec: 'avc',
        width: this.width,
        height: this.height
      },
      fastStart: 'in-memory'
    });

    // Initialize VideoEncoder
    const videoEncoder = new VideoEncoder({
      output: (chunk, metadata) => muxer.addVideoChunk(chunk, metadata),
      error: (e) => console.error("[ExportEngine] Encoder Error:", e)
    });

    videoEncoder.configure({
      codec: 'avc1.42E01E', // H.264 Baseline
      width: this.width,
      height: this.height,
      bitrate: 5_000_000, // 5 Mbps
      framerate: fps,
    });

    console.log(`[ExportEngine] Starting offline rendering: ${totalFrames} frames`);

    for (let frame = 0; frame < totalFrames; frame++) {
      if (!this.isRendering) break;

      const currentTime = frame / fps;
      const timestampMicros = frame * (1_000_000 / fps);

      this.ctx.fillStyle = '#000000';
      this.ctx.fillRect(0, 0, this.width, this.height);

      for (const track of project.tracks) {
        if (!track.isVisible || track.type !== 'video') continue;
        for (const clip of track.clips) {
          if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
            const video = this.videoElements.get(clip.id);
            if (video) {
              const targetTime = (currentTime - clip.startTime) + clip.offset;
              video.currentTime = targetTime;

              // Wait for frame to be ready
              await new Promise(resolve => {
                const onSeeked = () => {
                  video.removeEventListener('seeked', onSeeked);
                  resolve(true);
                };
                video.addEventListener('seeked', onSeeked);
                // Fail-safe timeout
                setTimeout(resolve, 100);
              });

              try {
                this.ctx.drawImage(video, 0, 0, this.width, this.height);
              } catch (e) {
                console.warn("[ExportEngine] Frame draw failed (possibly CORS)", e);
              }
            }
          }
        }
      }

      // Encode frame
      const bitmap = await createImageBitmap(this.canvas);
      const videoFrame = new VideoFrame(bitmap, { timestamp: timestampMicros });
      videoEncoder.encode(videoFrame, { keyFrame: frame % 30 === 0 });
      videoFrame.close();
      bitmap.close();

      onProgress((frame / totalFrames) * 100);

      // Allow UI to remain responsive
      if (frame % 5 === 0) {
        await new Promise(r => setTimeout(r, 0));
      }
    }

    await videoEncoder.flush();
    muxer.finalize();

    this.cleanup();
    this.isRendering = false;

    return new Blob([muxerTarget.buffer], { type: 'video/mp4' });
  }
}

import { Asset, MediaType } from '../types';

export class AssetService {
  static async processFile(file: File): Promise<Asset> {
    const url = URL.createObjectURL(file);
    const type = file.type.startsWith('video/') ? MediaType.VIDEO : 
                 file.type.startsWith('audio/') ? MediaType.AUDIO : 
                 MediaType.IMAGE;

    let duration = 0;
    let thumbnail = '';
    let waveform: number[] | undefined = undefined;

    try {
      if (type === MediaType.VIDEO || type === MediaType.AUDIO) {
        duration = await Promise.race([
          this.getMediaDuration(url),
          new Promise<number>((_, reject) => setTimeout(() => reject('Timeout'), 5000))
        ]).catch(() => (type === MediaType.VIDEO ? 10 : 0));

        if (type === MediaType.VIDEO) {
          thumbnail = await this.generateThumbnail(url).catch(() => '');
        }

        // Extract real waveform data with high fidelity (1000 samples)
        waveform = await this.extractWaveform(url, 1000).catch(err => {
          console.warn("Waveform extraction failed", err);
          return undefined;
        });
      } else if (type === MediaType.IMAGE) {
        duration = 5;
        thumbnail = url;
      }
    } catch (e) {
      console.error("Asset processing failed", e);
    }

    return {
      id: `asset-${Math.random().toString(36).substr(2, 9)}`,
      name: file.name,
      type,
      url,
      duration: duration || 5,
      thumbnail,
      waveform
    };
  }

  private static async extractWaveform(url: string, samples = 1000): Promise<number[]> {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);

    const channelData = audioBuffer.getChannelData(0);
    const blockSize = Math.floor(channelData.length / samples);
    const waveform: number[] = [];

    for (let i = 0; i < samples; i++) {
      let max = 0;
      for (let j = 0; j < blockSize; j++) {
        const val = Math.abs(channelData[i * blockSize + j]);
        if (val > max) max = val;
      }
      // Use Peak detection instead of average for sharper visual representation
      waveform.push(Math.min(1, max * 1.5)); 
    }

    await audioCtx.close();
    return waveform;
  }

  private static getMediaDuration(url: string): Promise<number> {
    return new Promise((resolve) => {
      const media = document.createElement('video');
      media.preload = 'metadata';
      media.src = url;
      media.onloadedmetadata = () => resolve(media.duration);
      media.onerror = () => resolve(0);
    });
  }

  private static generateThumbnail(url: string): Promise<string> {
    return new Promise((resolve) => {
      const video = document.createElement('video');
      // Set CORS for thumbnail generation
      video.crossOrigin = "anonymous";
      video.preload = 'metadata';
      video.src = url;
      video.muted = true;
      video.currentTime = 0.5;
      video.onseeked = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 160;
        canvas.height = 90;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(video, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg'));
      };
      video.onerror = () => resolve('');
    });
  }
}

export interface GFX_Props {
  text?: string;
  subtext?: string;
  color?: string;
  fontSize?: number;
  [key: string]: any;
}

export abstract class GFX_BaseElement {
  abstract id: string;
  abstract name: string;
  abstract iconName: string; // The Lucide icon to display in UI

  /**
   * Main render loop for the graphic.
   * @param ctx Canvas context to draw on.
   * @param time Current local time within the clip (0 to duration).
   * @param duration Total duration of the clip.
   * @param props User-defined properties (text, color, etc).
   */
  abstract render(
    ctx: CanvasRenderingContext2D,
    time: number,
    duration: number,
    props: GFX_Props
  ): void;

  /**
   * Returns metadata for the property inspector.
   */
  abstract getProperties(): Array<{
    id: string;
    label: string;
    type: 'text' | 'color' | 'number';
    default: any;
  }>;
}

import { GFX_BaseElement, GFX_Props } from './GFX_BaseElement';

export class GFX_SimpleText extends GFX_BaseElement {
  id = 'simple-text';
  name = 'Simple Text';
  iconName = 'Type';

  render(ctx: CanvasRenderingContext2D, time: number, duration: number, props: GFX_Props) {
    const text = props.text || 'NEW TITLE';
    const fontSize = props.fontSize || 60;
    const color = props.color || '#FFFFFF';

    // Simple fade in/out animation
    let opacity = 1;
    if (time < 0.5) opacity = time / 0.5;
    else if (time > duration - 0.5) opacity = (duration - time) / 0.5;

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, opacity));
    ctx.fillStyle = color;
    ctx.font = `bold ${fontSize}px Inter, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Add text shadow for legibility
    ctx.shadowColor = 'rgba(0,0,0,0.5)';
    ctx.shadowBlur = 10;
    ctx.shadowOffsetY = 4;

    ctx.fillText(text.toUpperCase(), ctx.canvas.width / 2, ctx.canvas.height / 2);
    ctx.restore();
  }

  getProperties() {
    return [
      { id: 'text', label: 'Title Text', type: 'text', default: 'NEXUS STUDIO' },
      { id: 'fontSize', label: 'Font Size', type: 'number', default: 60 },
      { id: 'color', label: 'Text Color', type: 'color', default: '#FFFFFF' }
    ];
  }
}

import { GFX_BaseElement, GFX_Props } from './GFX_BaseElement';

export class GFX_LowerThird_Basic extends GFX_BaseElement {
  id = 'lower-third-basic';
  name = 'News Lower Third';
  iconName = 'RectangleHorizontal';

  render(ctx: CanvasRenderingContext2D, time: number, duration: number, props: GFX_Props) {
    const text = props.text || 'JOHN DOE';
    const subtext = props.subtext || 'Producer';
    const accentColor = props.color || '#4f46e5';

    // Animation progress (0 to 1)
    let progress = 1;
    if (time < 0.8) progress = Math.pow(time / 0.8, 2);
    else if (time > duration - 0.8) progress = Math.pow((duration - time) / 0.8, 2);

    const x = 100 - (1 - progress) * 200; // Slide from left
    const y = ctx.canvas.height - 180;

    ctx.save();
    ctx.globalAlpha = progress;

    // Main Box
    ctx.fillStyle = accentColor;
    ctx.fillRect(x, y, 400, 60);

    // Text
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 24px Inter, sans-serif';
    ctx.fillText(text.toUpperCase(), x + 20, y + 40);

    // Subtext Box
    ctx.fillStyle = 'rgba(0,0,0,0.8)';
    ctx.fillRect(x, y + 60, 300, 35);

    ctx.fillStyle = 'rgba(255,255,255,0.7)';
    ctx.font = 'bold 14px Inter, sans-serif';
    ctx.fillText(subtext.toUpperCase(), x + 20, y + 83);

    ctx.restore();
  }

  getProperties() {
    return [
      { id: 'text', label: 'Name', type: 'text', default: 'NAME HERE' },
      { id: 'subtext', label: 'Description', type: 'text', default: 'TITLE HERE' },
      { id: 'color', label: 'Accent Color', type: 'color', default: '#4f46e5' }
    ];
  }
}

