export class GFX_Engine {
  /**
   * Renders any GFX clips active at the given time.
   * Tracks are rendered in order (bottom to top in array usually, but here we render top tracks last for overlaying).
   */
  static render(ctx: CanvasRenderingContext2D, project: Project, currentTime: number) {
    if (!ctx) return;

    // Reverse tracks to ensure top tracks in the UI (first in array) are rendered last (on top)
    const renderOrder = [...project.tracks].reverse();

    for (const track of renderOrder) {
      if (!track.isVisible || track.isMuted) continue;

      for (const clip of track.clips) {
        // GFX clips are identified by having an assetId that exists in the Registry
        const gfx = GFX_Registry.find(g => g.id === clip.assetId);
        if (!gfx) continue;

        if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
          const localTime = currentTime - clip.startTime;

          const gfxEffect = clip.effects.find(e => e.type === 'adjustment' && e.name === 'GFX_PROPS');
          const props = gfxEffect ? gfxEffect.params : {};

          ctx.save();
          gfx.render(ctx, localTime, clip.duration, props);
          ctx.restore();
        }
      }
    }
  }
}

import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize } from 'lucide-react';
import { Project, Asset } from '../../types';
import { GFX_Engine } from '../../services/GFX_Engine';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
  onTimeUpdate: (t: number) => void;
}

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime, onTimeUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const gfxCanvasRef = useRef<HTMLCanvasElement>(null);
  const audioContainerRef = useRef<HTMLDivElement>(null);
  const audioElementsRef = useRef<Map<string, HTMLAudioElement>>(new Map());
  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(performance.now());

  const animate = (time: number) => {
    if (isPlaying) {
      const deltaTime = (time - lastTimeRef.current) / 1000;
      const nextTime = currentTime + deltaTime;
      onTimeUpdate(nextTime);
    }

    // Render GFX overlay
    if (gfxCanvasRef.current) {
      const canvas = gfxCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        GFX_Engine.render(ctx, project, currentTime);
      }
    }

    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, currentTime, project]);

  const activeVideoClip = project.tracks
    .slice()
    .reverse()
    .filter(t => t.type === 'video' && t.isVisible)
    .flatMap(t => t.clips)
    .find(c => {
      const isGFX = GFX_Engine.render !== undefined && assets.every(a => a.id !== c.assetId); 
      return currentTime >= c.startTime && currentTime <= c.startTime + c.duration && !isGFX;
    });

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;
  const videoTrackMuted = project.tracks.find(t => t.clips.some(c => c.id === activeVideoClip?.id))?.isMuted;
  const isVideoSilenceNeeded = activeVideoClip?.isSilent || videoTrackMuted;

  const activeAudioSources = project.tracks
    .filter(t => !t.isMuted)
    .flatMap(t => t.clips.map(c => ({ clip: c, asset: assets.find(a => a.id === c.assetId) })))
    .filter(item => 
      item.asset && 
      !item.clip.isSilent && 
      currentTime >= item.clip.startTime && 
      currentTime <= item.clip.startTime + item.clip.duration
    );

  useEffect(() => {
    if (!videoRef.current) return;
    if (activeVideoAsset && activeVideoClip) {
      videoRef.current.muted = !!isVideoSilenceNeeded;
      const targetTime = (currentTime - activeVideoClip.startTime) + activeVideoClip.offset;
      if (Math.abs(videoRef.current.currentTime - targetTime) > 0.1) {
        videoRef.current.currentTime = targetTime;
      }
      if (isPlaying) videoRef.current.play().catch(() => {});
      else videoRef.current.pause();
    } else {
      videoRef.current.pause();
    }
  }, [isPlaying, activeVideoAsset?.id, isVideoSilenceNeeded]);

  useEffect(() => {
    if (!audioContainerRef.current) return;
    const container = audioContainerRef.current;
    const currentActiveIds = new Set(activeAudioSources.map(s => s.clip.id));

    for (const [id, el] of audioElementsRef.current.entries()) {
      if (!currentActiveIds.has(id)) {
        el.pause();
        el.src = "";
        el.remove();
        audioElementsRef.current.delete(id);
      }
    }

    activeAudioSources.forEach(({ clip, asset }) => {
      if (!asset) return;
      let el = audioElementsRef.current.get(clip.id);
      if (!el) {
        el = document.createElement('audio');
        el.src = asset.url;
        el.preload = "auto";
        container.appendChild(el);
        audioElementsRef.current.set(clip.id, el);
      }
      const targetTime = (currentTime - clip.startTime) + clip.offset;
      if (Math.abs(el.currentTime - targetTime) > 0.1) {
        el.currentTime = targetTime;
      }
      if (isPlaying) el.play().catch(() => {});
      else el.pause();
    });
  }, [isPlaying, activeAudioSources.length]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden border-x border-zinc-800/50">
      <div ref={audioContainerRef} className="hidden" aria-hidden="true" />
      <div className="flex-1 flex items-center justify-center p-6 bg-[#0a0a0a]">
        <div className="aspect-video w-full max-w-4xl bg-black rounded shadow-2xl border border-white/5 flex items-center justify-center overflow-hidden relative">
          {activeVideoAsset ? (
            <video 
              ref={videoRef} 
              src={activeVideoAsset.url} 
              className="w-full h-full object-contain pointer-events-none relative z-0" 
            />
          ) : (
            <div className="text-zinc-800 text-[10px] font-black uppercase tracking-widest animate-pulse">Monitor Standby...</div>
          )}

          <canvas 
            ref={gfxCanvasRef} 
            width={1920} 
            height={1080} 
            className="absolute inset-0 w-full h-full pointer-events-none z-10" 
            style={{ imageRendering: 'auto' }}
          />

          <div className="absolute top-4 left-4 flex gap-2 z-20">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono border border-white/10 uppercase">Rec Active</div>
          </div>
        </div>
      </div>

      <div className="h-14 bg-[#121212] border-t border-zinc-800 flex items-center justify-between px-6">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white" onClick={() => onTimeUpdate(0)}><SkipBack size={16} /></button>
            <button 
              onClick={onTogglePlay}
              className="w-9 h-9 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-all shadow-xl"
            >
              {isPlaying ? <Pause className="text-black fill-black" size={16} /> : <Play className="text-black fill-black translate-x-0.5" size={16} />}
            </button>
            <button className="text-zinc-500 hover:text-white"><SkipForward size={16} /></button>
          </div>
          <div className="font-mono text-[13px] text-indigo-400 tabular-nums bg-indigo-500/5 px-3 py-1 rounded border border-indigo-500/10">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">:{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>
        <div className="flex items-center gap-4 text-zinc-500">
           <Maximize size={16} className="cursor-pointer hover:text-white" />
        </div>
      </div>
    </div>
  );
};

export interface GFX_Transform {
  x: number;
  y: number;
  scale: number;
  rotation: number;
}

export interface GFX_Style {
  text: string;
  fontSize: number;
  fontFamily: string;
  color: string;
  fontWeight: string;
  strokeColor: string;
  strokeWidth: number;
  shadowColor: string;
  shadowBlur: number;
}

export class GFX_Layer {
  constructor(
    public transform: GFX_Transform,
    public style: GFX_Style
  ) {}

  /**
   * Calculates the bounding box in local space (unrotated).
   * Note: In a real engine, this would measure the actual text on canvas.
   * Here we approximate based on fontSize and text length.
   */
  getBoundingBox(ctx?: CanvasRenderingContext2D) {
    const width = this.style.text.length * (this.style.fontSize * 0.6);
    const height = this.style.fontSize;
    return {
      width: width * this.transform.scale,
      height: height * this.transform.scale,
      x: this.transform.x - (width * this.transform.scale) / 2,
      y: this.transform.y - (height * this.transform.scale) / 2
    };
  }
}

import { GFX_Layer } from './GFX_Schema';

export class GFX_Renderer {
  static draw(ctx: CanvasRenderingContext2D, layer: GFX_Layer, opacity: number = 1) {
    const { transform, style } = layer;

    ctx.save();
    ctx.globalAlpha = opacity;

    // Position and Rotate
    ctx.translate(transform.x, transform.y);
    ctx.rotate((transform.rotation * Math.PI) / 180);
    ctx.scale(transform.scale, transform.scale);

    // Style configuration
    ctx.fillStyle = style.color;
    ctx.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Shadow
    if (style.shadowBlur > 0) {
      ctx.shadowColor = style.shadowColor;
      ctx.shadowBlur = style.shadowBlur;
      ctx.shadowOffsetY = 4;
    }

    // Stroke
    if (style.strokeWidth > 0) {
      ctx.strokeStyle = style.strokeColor;
      ctx.lineWidth = style.strokeWidth;
      ctx.strokeText(style.text, 0, 0);
    }

    // Fill
    ctx.fillText(style.text, 0, 0);

    ctx.restore();
  }
}

import { GFX_Layer } from './GFX_Schema';

export class GFX_Gizmo {
  static readonly HANDLE_SIZE = 10;
  static readonly ROTATE_HANDLE_OFFSET = 40;

  static draw(ctx: CanvasRenderingContext2D, layer: GFX_Layer) {
    const bbox = layer.getBoundingBox(ctx);
    const { x, y, rotation } = layer.transform;
    const w = bbox.width;
    const h = bbox.height;

    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((rotation * Math.PI) / 180);

    // Main selection box
    ctx.strokeStyle = '#6366f1';
    ctx.lineWidth = 2;
    ctx.setLineDash([5, 5]);
    ctx.strokeRect(-w / 2, -h / 2, w, h);
    ctx.setLineDash([]);

    // Corner Handles
    ctx.fillStyle = '#FFFFFF';
    const corners = [
      { x: -w / 2, y: -h / 2 }, // TL
      { x: w / 2, y: -h / 2 },  // TR
      { x: -w / 2, y: h / 2 },  // BL
      { x: w / 2, y: h / 2 }   // BR
    ];

    corners.forEach(c => {
      ctx.fillRect(c.x - 5, c.y - 5, 10, 10);
      ctx.strokeRect(c.x - 5, c.y - 5, 10, 10);
    });

    // Rotation Handle
    ctx.beginPath();
    ctx.moveTo(0, -h / 2);
    ctx.lineTo(0, -h / 2 - this.ROTATE_HANDLE_OFFSET);
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(0, -h / 2 - this.ROTATE_HANDLE_OFFSET, 6, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    ctx.restore();
  }
}

import { GFX_Layer } from './GFX_Schema';

export type InteractionMode = 'none' | 'move' | 'scale' | 'rotate';

export class GFX_InteractionManager {
  private mode: InteractionMode = 'none';
  private startX: number = 0;
  private startY: number = 0;
  private initialTransform: any = null;

  handleMouseDown(
    mouseX: number, 
    mouseY: number, 
    layer: GFX_Layer
  ): InteractionMode {
    const bbox = layer.getBoundingBox();
    const { x, y, rotation } = layer.transform;

    // Simplified hit-test (In a real app, use inverse matrix for rotation hit testing)
    const dx = mouseX - x;
    const dy = mouseY - y;
    const dist = Math.sqrt(dx * dx + dy * dy);

    // Check Rotation Handle
    const rotHandleY = -bbox.height / 2 - 40;
    const rad = (rotation * Math.PI) / 180;
    const rx = dx * Math.cos(-rad) - dy * Math.sin(-rad);
    const ry = dx * Math.sin(-rad) + dy * Math.cos(-rad);

    if (Math.sqrt(rx * rx + (ry - rotHandleY) * (ry - rotHandleY)) < 15) {
      this.mode = 'rotate';
    } else if (Math.abs(rx) < bbox.width / 2 && Math.abs(ry) < bbox.height / 2) {
      this.mode = 'move';
    } else if (Math.sqrt(Math.pow(Math.abs(rx) - bbox.width / 2, 2) + Math.pow(Math.abs(ry) - bbox.height / 2, 2)) < 20) {
      this.mode = 'scale';
    } else {
      this.mode = 'none';
    }

    this.startX = mouseX;
    this.startY = mouseY;
    this.initialTransform = { ...layer.transform };
    return this.mode;
  }

  handleMouseMove(mouseX: number, mouseY: number, layer: GFX_Layer): boolean {
    if (this.mode === 'none') return false;

    const dx = mouseX - this.startX;
    const dy = mouseY - this.startY;

    if (this.mode === 'move') {
      layer.transform.x = this.initialTransform.x + dx;
      layer.transform.y = this.initialTransform.y + dy;
    } else if (this.mode === 'scale') {
      const mag = Math.sqrt(dx * dx + dy * dy);
      const direction = dx > 0 ? 1 : -1;
      layer.transform.scale = Math.max(0.1, this.initialTransform.scale + (direction * mag) / 500);
    } else if (this.mode === 'rotate') {
      const angle = Math.atan2(mouseY - layer.transform.y, mouseX - layer.transform.x);
      layer.transform.rotation = (angle * 180) / Math.PI + 90;
    }

    return true;
  }

  handleMouseUp() {
    this.mode = 'none';
  }
}

