export const UI_PropertyInspector: React.FC<UI_PropertyInspectorProps> = ({ clip, onUpdate }) => {
  const effect = clip.effects.find(e => e.name === 'GFX_PROPS');
  if (!effect) return null;

  const params = effect.params;

  const handleChange = (key: string, value: any) => {
    onUpdate({ ...params, [key]: value });
