export type GizmoHandle = 'tl' | 'tr' | 'bl' | 'br' | 'rotate' | 'body' | null;

export class GFX_Gizmo {
  static readonly HANDLE_SIZE = 12;
  static readonly ROTATE_OFFSET = 50;

  static draw(ctx: CanvasRenderingContext2D, layer: TextLayer) {
    const bounds = layer.getBounds(ctx);
    const { x, y, rotation } = layer;
    const w = bounds.width;
    const h = bounds.height;

    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((rotation * Math.PI) / 180);

    // Bounding Box
    ctx.strokeStyle = '#6366f1';
    ctx.lineWidth = 2;
    ctx.setLineDash([6, 4]);
    ctx.strokeRect(-w / 2, -h / 2, w, h);
    ctx.setLineDash([]);

    // Corners
    ctx.fillStyle = '#FFFFFF';
    ctx.strokeStyle = '#6366f1';
    ctx.lineWidth = 1.5;

    const corners = [
      { id: 'tl', x: -w / 2, y: -h / 2 },
      { id: 'tr', x: w / 2, y: -h / 2 },
      { id: 'bl', x: -w / 2, y: h / 2 },
      { id: 'br', x: w / 2, y: h / 2 }
    ];

    corners.forEach(c => {
      ctx.fillRect(c.x - 6, c.y - 6, 12, 12);
      ctx.strokeRect(c.x - 6, c.y - 6, 12, 12);
    });

    // Rotation Lollipop
    ctx.beginPath();
    ctx.setLineDash([]);
    ctx.moveTo(0, -h / 2);
    ctx.lineTo(0, -h / 2 - this.ROTATE_OFFSET);
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(0, -h / 2 - this.ROTATE_OFFSET, 8, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    ctx.restore();
  }

  static getHandleAt(mouseX: number, mouseY: number, layer: TextLayer): GizmoHandle {
    const bounds = layer.getBounds();
    const { x, y, rotation } = layer;

    // Transform mouse to local space
    const dx = mouseX - x;
    const dy = mouseY - y;
    const rad = (rotation * Math.PI) / 180;
    const lx = dx * Math.cos(-rad) - dy * Math.sin(-rad);
    const ly = dx * Math.sin(-rad) + dy * Math.cos(-rad);

    const halfW = bounds.width / 2;
    const halfH = bounds.height / 2;
    const hit = 10;

    // Check Rotation
    const rotDist = Math.sqrt(lx * lx + (ly + halfH + this.ROTATE_OFFSET) ** 2);
    if (rotDist < 15) return 'rotate';

    // Check Corners
    if (Math.abs(lx + halfW) < hit && Math.abs(ly + halfH) < hit) return 'tl';
    if (Math.abs(lx - halfW) < hit && Math.abs(ly + halfH) < hit) return 'tr';
    if (Math.abs(lx + halfW) < hit && Math.abs(ly - halfH) < hit) return 'bl';
    if (Math.abs(lx - halfW) < hit && Math.abs(ly - halfH) < hit) return 'br';

    // Check Body
    if (Math.abs(lx) < halfW && Math.abs(ly) < halfH) return 'body';

    return null;
  }
}

