import { Project } from '../types';
import { GFX_Registry } from './GFX_Registry';
import { TextLayer } from './GFX_Schema';
import { GFX_Renderer } from './GFX_Renderer';

export class GFX_Engine {
  /**
   * Renders GFX clips with full transform support using the rewritten rendering pipeline.
   */
  static render(ctx: CanvasRenderingContext2D, project: Project, currentTime: number) {
    if (!ctx) return;

    // Render tracks in reverse order (top of UI list is last drawn = on top)
    const renderOrder = [...project.tracks].reverse();

    for (const track of renderOrder) {
      if (!track.isVisible || track.isMuted) continue;

      for (const clip of track.clips) {
        const isGFX = GFX_Registry.some(g => g.id === clip.assetId);
        if (!isGFX) continue;

        if (currentTime >= clip.startTime && currentTime <= clip.startTime + clip.duration) {
          const localTime = currentTime - clip.startTime;
          const layer = this.getLayerForClip(clip, project.resolution);
          if (!layer) continue;

          // Simple opacity fade
          let opacity = 1;
          if (localTime < 0.3) opacity = localTime / 0.3;
          else if (localTime > clip.duration - 0.3) opacity = (clip.duration - localTime) / 0.3;

          GFX_Renderer.draw(ctx, layer, Math.max(0, opacity));
        }
      }
    }
  }

  /**
   * Factory method to map clip data to the robust TextLayer model.
   */
  static getLayerForClip(clip: any, resolution: { width: number, height: number }): TextLayer | null {
    const gfxEffect = clip.effects.find((e: any) => e.name === 'GFX_PROPS');
    if (!gfxEffect) return null;
    const p = gfxEffect.params;

    return new TextLayer(
      clip.id,
      p.text || '',
      p.x ?? (resolution.width / 2),
      p.y ?? (resolution.height / 2),
      p.fontSize || 80,
      p.fontFamily || 'Inter, sans-serif',
      p.fillColor || '#FFFFFF',
      p.strokeColor || '#000000',
      p.strokeWidth || 0,
      p.shadowBlur || 0,
      p.rotation || 0,
      p.scale || 1
    );
  }
}

