  const [isExportModalOpen, setIsExportModalOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [activeTab, setActiveTab] = useState<'library' | 'titles'>('library');

  useEffect(() => {
    if ((isExportModalOpen || isShortcutModalOpen) && store.isPlaying) {
      store.setIsPlaying(false);
    }
  }, [isExportModalOpen, isShortcutModalOpen]);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
    const action = shortcutStore.getAction(e);
    if (!action) return;
    if (action === 'redo') { store.redo(); e.preventDefault(); return; }
    e.preventDefault();
    switch (action) {
      case 'play_pause': store.setIsPlaying(!store.isPlaying); break;
      case 'split': store.splitClip(store.selectedClipId, store.currentTime); break;
      case 'delete': if (store.selectedClipId) store.deleteClip(store.selectedClipId); break;
      case 'undo': store.undo(); break;
      case 'zoom_in': store.setZoom(Math.min(100, store.zoom + 5)); break;
      case 'zoom_out': store.setZoom(Math.max(1, store.zoom - 5)); break;
      case 'toggle_magnet': store.setIsMagnetEnabled(!store.isMagnetEnabled); break;
    }
  }, [store, shortcutStore]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const handleAddTitle = (gfxId: string, name: string) => {
    const gfx = getGFXById(gfxId);
    if (!gfx) return;

    const defaultParams: any = {
      x: store.project.resolution.width / 2,
      y: store.project.resolution.height / 2,
      scale: 1,
      rotation: 0,
      text: "NEXUS STUDIO",
      fontSize: 80,
      fillColor: "#FFFFFF",
      strokeColor: "#000000",
      strokeWidth: 0,
      shadowBlur: 0
    };

    const newClip: Clip = {
      id: `gfx-${Date.now()}`,
      assetId: gfxId,
      startTime: store.currentTime,
      offset: 0,
      duration: 5,
      layer: 10,
      effects: [{
        id: `effect-props-${Date.now()}`,
        type: 'adjustment',
        name: 'GFX_PROPS',
        params: defaultParams
      }],
      isSilent: true
    };

    store.setProject(prev => {
      const targetTrack = prev.tracks.find(t => t.name === 'Graphics' && t.type === 'video') || prev.tracks.find(t => t.type === 'video');
      if (!targetTrack) return prev;
      return {
        ...prev,
        tracks: prev.tracks.map(t => t.id === targetTrack.id ? { ...t, clips: [...t.clips, newClip] } : t)
      };
    });
    store.setSelectedClipId(newClip.id);
  };

  const handleAICompose = async () => {
    const aistudio = (window as any).aistudio;
    if (typeof aistudio !== 'undefined') {
      try { const hasKey = await aistudio.hasSelectedApiKey(); if (!hasKey) await aistudio.openSelectKey(); } catch (err) {}
    }
