import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, Maximize } from 'lucide-react';
import { Project, Asset } from '../../types';
import { GFX_Engine } from '../../services/GFX_Engine';
import { GFX_Gizmo } from '../../services/GFX_Gizmo';
import { GFX_InteractionManager } from '../../services/GFX_InteractionManager';
import { useProjectStore } from '../../store/useProjectStore';

interface PreviewPlayerProps {
  project: Project;
  assets: Asset[];
  isPlaying: boolean;
  onTogglePlay: () => void;
  currentTime: number;
  onTimeUpdate: (t: number) => void;
}

const interactionManager = new GFX_InteractionManager();

export const PreviewPlayer: React.FC<PreviewPlayerProps> = ({ project, assets, isPlaying, onTogglePlay, currentTime, onTimeUpdate }) => {
  const store = useProjectStore();
  const videoRef = useRef<HTMLVideoElement>(null);
  const gfxCanvasRef = useRef<HTMLCanvasElement>(null);
  const audioContainerRef = useRef<HTMLDivElement>(null);
  const audioElementsRef = useRef<Map<string, HTMLAudioElement>>(new Map());
  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(performance.now());
  const [isInteracting, setIsInteracting] = useState(false);

  const selectedClip = project.tracks.flatMap(t => t.clips).find(c => c.id === store.selectedClipId);

  const animate = (time: number) => {
    if (isPlaying) {
      const deltaTime = (time - lastTimeRef.current) / 1000;
      const nextTime = currentTime + deltaTime;
      onTimeUpdate(nextTime);
    }

    if (gfxCanvasRef.current) {
      const canvas = gfxCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        GFX_Engine.render(ctx, project, currentTime);

        // Draw Gizmo for selected clip if it is a GFX clip
        if (selectedClip && currentTime >= selectedClip.startTime && currentTime <= selectedClip.startTime + selectedClip.duration) {
          const layer = GFX_Engine.getLayerForClip(selectedClip, project.resolution);
          if (layer) {
            GFX_Gizmo.draw(ctx, layer);
          }
        }
      }
    }

    lastTimeRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
  }, [isPlaying, currentTime, project, store.selectedClipId]);

  const handleCanvasMouseDown = (e: React.MouseEvent) => {
    if (!gfxCanvasRef.current || !selectedClip) return;
    const canvas = gfxCanvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * canvas.width;
    const y = ((e.clientY - rect.top) / rect.height) * canvas.height;

    const layer = GFX_Engine.getLayerForClip(selectedClip, project.resolution);
    if (layer) {
      // Fix: Use correct method name onMouseDown
      const mode = interactionManager.onMouseDown(x, y, layer);
      // Fix: mode is InteractionState, which uses 'IDLE' instead of 'none' when no handle is hit.
      if (mode !== 'IDLE') {
        setIsInteracting(true);
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent) => {
    if (!isInteracting || !gfxCanvasRef.current || !selectedClip) return;
    const canvas = gfxCanvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * canvas.width;
    const y = ((e.clientY - rect.top) / rect.height) * canvas.height;

    const layer = GFX_Engine.getLayerForClip(selectedClip, project.resolution);
    if (layer) {
      // Fix: Use correct method name onMouseMove
      const updated = interactionManager.onMouseMove(x, y, layer);
      if (updated) {
        // Sync project state
        store.setProject(prev => ({
          ...prev,
          tracks: prev.tracks.map(t => ({
            ...t,
            clips: t.clips.map(c => c.id === selectedClip.id ? {
              ...c,
              effects: c.effects.map(eff => eff.name === 'GFX_PROPS' ? {
                ...eff,
                params: { 
                  ...eff.params, 
                  // Fix: TextLayer properties are flat, not under .transform
                  x: layer.x, 
                  y: layer.y, 
                  scale: layer.scale, 
                  rotation: layer.rotation 
                }
              } : eff)
            } : c)
          }))
        }));
      }
    }
  };

  const handleCanvasMouseUp = () => {
    setIsInteracting(false);
    // Fix: Use correct method name onMouseUp
    interactionManager.onMouseUp();
  };

  // Video and Audio synchronization logic...
  const activeVideoClip = project.tracks
    .slice().reverse()
    .filter(t => t.type === 'video' && t.isVisible)
    .flatMap(t => t.clips)
    .find(c => {
      const isGFX = assets.every(a => a.id !== c.assetId); 
      return currentTime >= c.startTime && currentTime <= c.startTime + c.duration && !isGFX;
    });

  const activeVideoAsset = activeVideoClip ? assets.find(a => a.id === activeVideoClip.assetId) : null;
  const isVideoSilenceNeeded = activeVideoClip?.isSilent || project.tracks.find(t => t.clips.some(c => c.id === activeVideoClip?.id))?.isMuted;

  const activeAudioSources = project.tracks
    .filter(t => !t.isMuted)
    .flatMap(t => t.clips.map(c => ({ clip: c, asset: assets.find(a => a.id === c.assetId) })))
    .filter(item => item.asset && !item.clip.isSilent && currentTime >= item.clip.startTime && currentTime <= item.clip.startTime + item.clip.duration);

  useEffect(() => {
    if (!videoRef.current) return;
    if (activeVideoAsset && activeVideoClip) {
      videoRef.current.muted = !!isVideoSilenceNeeded;
      const targetTime = (currentTime - activeVideoClip.startTime) + activeVideoClip.offset;
      if (Math.abs(videoRef.current.currentTime - targetTime) > 0.1) videoRef.current.currentTime = targetTime;
      if (isPlaying) videoRef.current.play().catch(() => {});
      else videoRef.current.pause();
    } else videoRef.current.pause();
  }, [isPlaying, activeVideoAsset?.id, isVideoSilenceNeeded]);

  useEffect(() => {
    if (!audioContainerRef.current) return;
    const container = audioContainerRef.current;
    const currentActiveIds = new Set(activeAudioSources.map(s => s.clip.id));

    for (const [id, el] of audioElementsRef.current.entries()) {
      if (!currentActiveIds.has(id)) {
        el.pause(); el.src = ""; el.remove();
        audioElementsRef.current.delete(id);
      }
    }

    activeAudioSources.forEach(({ clip, asset }) => {
      if (!asset) return;
      let el = audioElementsRef.current.get(clip.id);
      if (!el) {
        el = document.createElement('audio');
        el.src = asset.url; el.preload = "auto";
        container.appendChild(el);
        audioElementsRef.current.set(clip.id, el);
      }
      const targetTime = (currentTime - clip.startTime) + clip.offset;
      if (Math.abs(el.currentTime - targetTime) > 0.1) el.currentTime = targetTime;
      if (isPlaying) el.play().catch(() => {});
      else el.pause();
    });
  }, [isPlaying, activeAudioSources.length]);

  return (
    <div className="flex-1 bg-black flex flex-col relative group overflow-hidden border-x border-zinc-800/50">
      <div ref={audioContainerRef} className="hidden" aria-hidden="true" />
      <div className="flex-1 flex items-center justify-center p-6 bg-[#0a0a0a]">
        <div className="aspect-video w-full max-w-4xl bg-black rounded shadow-2xl border border-white/5 flex items-center justify-center overflow-hidden relative">
          {activeVideoAsset ? (
            <video ref={videoRef} src={activeVideoAsset.url} className="w-full h-full object-contain pointer-events-none relative z-0" />
          ) : (
            <div className="text-zinc-800 text-[10px] font-black uppercase tracking-widest animate-pulse">Monitor Standby...</div>
          )}

          <canvas 
            ref={gfxCanvasRef} 
            width={1920} height={1080} 
            onMouseDown={handleCanvasMouseDown}
            onMouseMove={handleCanvasMouseMove}
            onMouseUp={handleCanvasMouseUp}
            onMouseLeave={handleCanvasMouseUp}
            className={`absolute inset-0 w-full h-full z-10 ${isInteracting ? 'cursor-grabbing' : 'cursor-default'}`} 
            style={{ imageRendering: 'auto' }}
          />

          <div className="absolute top-4 left-4 flex gap-2 z-20">
            <div className="px-2 py-1 bg-black/60 backdrop-blur rounded text-[9px] font-mono border border-white/10 uppercase">Rec Active</div>
          </div>
        </div>
      </div>

      <div className="h-14 bg-[#121212] border-t border-zinc-800 flex items-center justify-between px-6">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-4">
            <button className="text-zinc-500 hover:text-white" onClick={() => onTimeUpdate(0)}><SkipBack size={16} /></button>
            <button onClick={onTogglePlay} className="w-9 h-9 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-all shadow-xl">
              {isPlaying ? <Pause className="text-black fill-black" size={16} /> : <Play className="text-black fill-black translate-x-0.5" size={16} />}
            </button>
            <button className="text-zinc-500 hover:text-white"><SkipForward size={16} /></button>
          </div>
          <div className="font-mono text-[13px] text-indigo-400 tabular-nums bg-indigo-500/5 px-3 py-1 rounded border border-indigo-500/10">
            {new Date(currentTime * 1000).toISOString().substr(11, 8)}<span className="opacity-40">:{Math.floor((currentTime % 1) * 30).toString().padStart(2, '0')}</span>
          </div>
        </div>
        <div className="flex items-center gap-4 text-zinc-500">
           <Maximize size={16} className="cursor-pointer hover:text-white" />
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { Upload, Film, Music, Sparkles, Search } from 'lucide-react';
